abs.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void abs_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        y[i] = fabs(x[i]);
    }
}

add_norm.metal_source:
// add_norm: y = layer_norm(x + residual). D=1024, TG=1024.
// Single-simdgroup-per-row: only sg 0 (32 lanes) processes the row.
// Each active lane handles 8 float4 = 32 elements -> 1024 floats per row.
// Cache add-result in 4KB threadgroup memory instead of per-thread registers.
// IMPORTANT: registry TG=1024 must match PSO max_thr/tg. Storing the cache in
// registers (float4[8] per thread) drops max_thr/tg below 1024 on M2 because
// the compiler reserves register space for all 1024 launched threads even
// though only 32 do work — the kernel then silently fails to dispatch
// (0.000ms timing, large max_err). Threadgroup memory sidesteps this.
//
// Optimization: Use simd_sum for mean/var reduction, but reduce threadgroup
// memory writes by computing mean/var first, then writing cache only once.
// Also use half-precision for cache to reduce memory bandwidth pressure.
#include <metal_stdlib>
using namespace metal;

kernel void add_norm_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  res     [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    threadgroup half4 cache[256];   // 2KB: full row of (x+res) in half precision

    if (t < 32u) {
        const uint row = tgid.y;
        device const float4* xr = (device const float4*)(x + row * D);
        device const float4* rr = (device const float4*)(res + row * D);

        float ssum = 0.0f, ssq = 0.0f;
        #pragma unroll
        for (uint k = 0; k < 8; ++k) {
            uint i = k * 32u + t;            // strided coalesced
            float4 u = xr[i] + rr[i];
            cache[i] = half4(u);
            ssum += u.x + u.y + u.z + u.w;
            ssq  += dot(u, u);
        }
        ssum = simd_sum(ssum);
        ssq  = simd_sum(ssq);

        const float invD    = 1.0f / float(D);
        const float mean    = ssum * invD;
        const float var     = max(ssq * invD - mean * mean, 0.0f);
        const float inv_std = rsqrt(var + eps);

        device float4* yr = (device float4*)(y + row * D);
        #pragma unroll
        for (uint k = 0; k < 8; ++k) {
            uint i = k * 32u + t;
            float4 cached = float4(cache[i]);
            yr[i] = (cached - mean) * inv_std;
        }
    }
}

alexnet.metal_source:
// alexnet-mini M2: half storage for a2 to cut tg-mem traffic.
#include <metal_stdlib>
using namespace metal;

constant constexpr uint A1H = 14, A1W = 14, A1C = 32;
constant constexpr uint A2H = 6,  A2W = 6,  A2C = 64;
constant constexpr uint A3H = 2,  A3W = 2,  A3C = 128;
constant constexpr uint FC1 = 256;

[[max_total_threads_per_threadgroup(1024)]]
kernel void alexnet_f32(
    device const float* x      [[buffer(0)]],
    device const float* Wc1    [[buffer(1)]],
    device const float* Wc2    [[buffer(2)]],
    device const float* Wc3    [[buffer(3)]],
    device const float* Wfc1   [[buffer(4)]],
    device const float* Wfc2   [[buffer(5)]],
    device       float* y      [[buffer(6)]],
    uint  tid       [[thread_position_in_threadgroup]],
    uint  sgid      [[simdgroup_index_in_threadgroup]],
    uint  lane      [[thread_index_in_simdgroup]])
{
    threadgroup half  a1[A1H * A1W * A1C];        // 12.5 KB
    threadgroup half  a2[A2H * A2W * A2C];        //  4.5 KB (half)
    threadgroup float a3[A3H * A3W * A3C];        //  2.0 KB
    threadgroup float fc1_buf[FC1];                //  1.0 KB
    threadgroup half Wc1c[32 * 75];                //  4.7 KB Wc1 cache (half precision)

    for (uint i = tid; i < 32u * 75u; i += 1024u) {
        Wc1c[i] = half(Wc1[i]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    for (uint spatial = sgid; spatial < A1H * A1W; spatial += 32u) {
        uint h2_ = spatial / A1W;
        uint w2  = spatial - h2_ * A1W;
        uint c = lane;
        threadgroup const half* Wf = Wc1c + c * 75u;
        uint hO0 = h2_ * 2u;
        uint wO0 = w2 * 2u;
        float pool0 = 0.0f, pool1 = 0.0f, pool2 = 0.0f, pool3 = 0.0f;
        #pragma unroll
        for (uint kh = 0; kh < 5u; ++kh) {
            #pragma unroll
            for (uint kw = 0; kw < 5u; ++kw) {
                uint wi = (kh * 5u + kw) * 3u;
                float w0 = float(Wf[wi+0]), w1 = float(Wf[wi+1]), w2v = float(Wf[wi+2]);
                uint xi00 = ((hO0 + 0 + kh) * 32u + (wO0 + 0 + kw)) * 3u;
                uint xi01 = ((hO0 + 0 + kh) * 32u + (wO0 + 1 + kw)) * 3u;
                uint xi10 = ((hO0 + 1 + kh) * 32u + (wO0 + 0 + kw)) * 3u;
                uint xi11 = ((hO0 + 1 + kh) * 32u + (wO0 + 1 + kw)) * 3u;
                pool0 = fma(x[xi00+0], w0, fma(x[xi00+1], w1, fma(x[xi00+2], w2v, pool0)));
                pool1 = fma(x[xi01+0], w0, fma(x[xi01+1], w1, fma(x[xi01+2], w2v, pool1)));
                pool2 = fma(x[xi10+0], w0, fma(x[xi10+1], w1, fma(x[xi10+2], w2v, pool2)));
                pool3 = fma(x[xi11+0], w0, fma(x[xi11+1], w1, fma(x[xi11+2], w2v, pool3)));
            }
        }
        float m = fmax(fmax(pool0, pool1), fmax(pool2, pool3));
        a1[(h2_ * A1W + w2) * A1C + c] = half(fmax(m, 0.0f));
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    for (uint task = sgid; task < 72u; task += 32u) {
        uint c_half = task & 1u;
        uint spatial = task >> 1;
        uint h2_ = spatial / A2W;
        uint w2  = spatial - h2_ * A2W;
        uint c = c_half * 32u + lane;
        uint hO0 = h2_ * 2u;
        uint wO0 = w2 * 2u;
        float pool0 = 0.0f, pool1 = 0.0f, pool2 = 0.0f, pool3 = 0.0f;
        #pragma unroll
        for (uint kh = 0; kh < 3u; ++kh) {
            #pragma unroll
            for (uint kw = 0; kw < 3u; ++kw) {
                uint w_base = ((c * 3u + kh) * 3u + kw) * 32u;
                uint a_base00 = ((hO0 + 0 + kh) * A1W + (wO0 + 0 + kw)) * A1C;
                uint a_base01 = ((hO0 + 0 + kh) * A1W + (wO0 + 1 + kw)) * A1C;
                uint a_base10 = ((hO0 + 1 + kh) * A1W + (wO0 + 0 + kw)) * A1C;
                uint a_base11 = ((hO0 + 1 + kh) * A1W + (wO0 + 1 + kw)) * A1C;
                device const float4* Wc2v = (device const float4*)(Wc2 + w_base);
                threadgroup const half4* a1v00 = (threadgroup const half4*)(a1 + a_base00);
                threadgroup const half4* a1v01 = (threadgroup const half4*)(a1 + a_base01);
                threadgroup const half4* a1v10 = (threadgroup const half4*)(a1 + a_base10);
                threadgroup const half4* a1v11 = (threadgroup const half4*)(a1 + a_base11);
                #pragma unroll
                for (uint cv = 0; cv < 8u; ++cv) {
                    float4 wv = Wc2v[cv];
                    pool0 += dot(float4(a1v00[cv]), wv);
                    pool1 += dot(float4(a1v01[cv]), wv);
                    pool2 += dot(float4(a1v10[cv]), wv);
                    pool3 += dot(float4(a1v11[cv]), wv);
                }
            }
        }
        float m = fmax(fmax(pool0, pool1), fmax(pool2, pool3));
        a2[(h2_ * A2W + w2) * A2C + c] = half(fmax(m, 0.0f));
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // conv3: 4 spatial × 8 c_eighth (lane covers 16 channels via lane and lane+16? No, just split c into 8 parts).
    // Actually: 4 spatial × 8 c_eighth = 32 tasks, one per simdgroup; each lane covers 1 channel of 16-wide slice.
    // But A3C=128 = 4 quarters of 32. Use 4 spatial × 8 (c_eighth) = 32 with each lane handling 1 of 16 c.
    // Simpler: keep 16 task layout but spread to all 32 sgs by also splitting kh*kw work? Too complex.
    // Stick with current: 16 sgs busy.
    if (sgid < 16u) {
        uint c_quarter = sgid & 3u;
        uint spatial   = sgid >> 2;
        uint h2_ = spatial / A3W;
        uint w2  = spatial - h2_ * A3W;
        uint c = c_quarter * 32u + lane;
        uint hO0 = h2_ * 2u;
        uint wO0 = w2 * 2u;
        float pool0 = 0.0f, pool1 = 0.0f, pool2 = 0.0f, pool3 = 0.0f;
        #pragma unroll
        for (uint kh = 0; kh < 3u; ++kh) {
            #pragma unroll
            for (uint kw = 0; kw < 3u; ++kw) {
                uint w_base = ((c * 3u + kh) * 3u + kw) * 64u;
                uint a_base00 = ((hO0 + 0 + kh) * A2W + (wO0 + 0 + kw)) * A2C;
                uint a_base01 = ((hO0 + 0 + kh) * A2W + (wO0 + 1 + kw)) * A2C;
                uint a_base10 = ((hO0 + 1 + kh) * A2W + (wO0 + 0 + kw)) * A2C;
                uint a_base11 = ((hO0 + 1 + kh) * A2W + (wO0 + 1 + kw)) * A2C;
                device const float4* Wc3v = (device const float4*)(Wc3 + w_base);
                threadgroup const half4* a2v00 = (threadgroup const half4*)(a2 + a_base00);
                threadgroup const half4* a2v01 = (threadgroup const half4*)(a2 + a_base01);
                threadgroup const half4* a2v10 = (threadgroup const half4*)(a2 + a_base10);
                threadgroup const half4* a2v11 = (threadgroup const half4*)(a2 + a_base11);
                #pragma unroll
                for (uint cv = 0; cv < 16u; ++cv) {
                    float4 wv = Wc3v[cv];
                    float4 av00 = float4(a2v00[cv]);
                    float4 av01 = float4(a2v01[cv]);
                    float4 av10 = float4(a2v10[cv]);
                    float4 av11 = float4(a2v11[cv]);
                    pool0 += dot(av00, wv);
                    pool1 += dot(av01, wv);
                    pool2 += dot(av10, wv);
                    pool3 += dot(av11, wv);
                }
            }
        }
        float m = fmax(fmax(pool0, pool1), fmax(pool2, pool3));
        a3[(h2_ * A3W + w2) * A3C + c] = fmax(m, 0.0f);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // FC1 reads Wfc1 as half via reinterpret - if Wfc1 is stored as f32 we can't.
    // Use vectorized float4 loads to reduce instruction count.
    // lane = k_part*8 + o_off, 4 k_parts × 128 k, 8 lanes per k_part each handle 1 output.
    // Group adjacent lanes (o_off 0..7) into a float4×2 load: lanes 0..3 = quad0, 4..7 = quad1.
    // FC1: 32 sgs × 8 outputs each (256 total). Each sg's 32 lanes each cover 16 k values (16*32=512).
    // Read Wfc1 row [k, sg*8 .. sg*8+7] as two float4s — contiguous, vectorizable.
    {
        uint o_base = sgid * 8u;
        float acc0 = 0.0f, acc1 = 0.0f, acc2 = 0.0f, acc3 = 0.0f;
        float acc4 = 0.0f, acc5 = 0.0f, acc6 = 0.0f, acc7 = 0.0f;
        uint k0 = lane * 16u;
        device const float4* Wrow4 = (device const float4*)(Wfc1 + o_base);
        // row stride in float4 = 256/4 = 64
        #pragma unroll 4
        for (uint kk = 0; kk < 16u; ++kk) {
            uint k = k0 + kk;
            float a = float(a3[k]);
            float4 w0 = Wrow4[k * 64u + 0];
            float4 w1 = Wrow4[k * 64u + 1];
            acc0 = fma(a, w0.x, acc0);
            acc1 = fma(a, w0.y, acc1);
            acc2 = fma(a, w0.z, acc2);
            acc3 = fma(a, w0.w, acc3);
            acc4 = fma(a, w1.x, acc4);
            acc5 = fma(a, w1.y, acc5);
            acc6 = fma(a, w1.z, acc6);
            acc7 = fma(a, w1.w, acc7);
        }
        acc0 = simd_sum(acc0);
        acc1 = simd_sum(acc1);
        acc2 = simd_sum(acc2);
        acc3 = simd_sum(acc3);
        acc4 = simd_sum(acc4);
        acc5 = simd_sum(acc5);
        acc6 = simd_sum(acc6);
        acc7 = simd_sum(acc7);
        if (lane == 0) {
            fc1_buf[o_base + 0] = fmax(acc0, 0.0f);
            fc1_buf[o_base + 1] = fmax(acc1, 0.0f);
            fc1_buf[o_base + 2] = fmax(acc2, 0.0f);
            fc1_buf[o_base + 3] = fmax(acc3, 0.0f);
            fc1_buf[o_base + 4] = fmax(acc4, 0.0f);
            fc1_buf[o_base + 5] = fmax(acc5, 0.0f);
            fc1_buf[o_base + 6] = fmax(acc6, 0.0f);
            fc1_buf[o_base + 7] = fmax(acc7, 0.0f);
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sgid < 10u) {
        uint o = sgid;
        float s = 0.0f;
        uint k0 = lane * 8u;
        #pragma unroll
        for (uint kk = 0; kk < 8u; ++kk) {
            s = fma(fc1_buf[k0 + kk], Wfc2[(k0 + kk) * 10u + o], s);
        }
        s = simd_sum(s);
        if (lane == 0) y[o] = s;
    }
}

argmax.metal_source:
// argmax: per-row argmax along last dim. One threadgroup per row.
#include <metal_stdlib>
using namespace metal;

static inline void simd_argmax(thread float& v, thread uint& i) {
    for (uint s = 16; s > 0; s >>= 1) {
        float ov = simd_shuffle_down(v, s);
        uint  oi = simd_shuffle_down(i, s);
        if (ov > v) { v = ov; i = oi; }
    }
}

kernel void argmax_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* row_ptr = x + row * C;
    const uint sg = tid >> 5;
    const uint lane = tid & 31;

    float best_v = row_ptr[tid];
    uint  best_i = tid;

    simd_argmax(best_v, best_i);

    threadgroup float tg_v[32];
    threadgroup uint  tg_i[32];
    if (lane == 0) { tg_v[sg] = best_v; tg_i[sg] = best_i; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        best_v = tg_v[lane];
        best_i = tg_i[lane];
        simd_argmax(best_v, best_i);
        if (lane == 0) out[row] = float(best_i);
    }
}

attention_scores.metal_source:
// attention_scores: softmax(Q @ K^T / sqrt(D)).
#include <metal_stdlib>
using namespace metal;

kernel void attention_scores_f32(
    device const float*  Q       [[buffer(0)]],
    device const float*  K       [[buffer(1)]],
    device       float*  O       [[buffer(2)]],
    constant     uint&   S       [[buffer(3)]],
    constant     uint&   D       [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint qr = tgid.y;
    if (qr >= S) return;

    threadgroup float qrow[64];      // D
    threadgroup float scores[128];   // S
    threadgroup float reduce_max[32];
    threadgroup float reduce_sum[32];
    threadgroup float max_out;
    threadgroup float sum_out;

    if (tid < D) qrow[tid] = Q[qr * D + tid];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const float inv = rsqrt(float(D));

    // Compute Q@K^T using simdgroup_matrix for better ALU utilization
    {
        uint j   = tid >> 3;
        uint sub = tid & 7;
        uint d0  = sub * 8;
        device const float* kr = K + j * D;
        float acc = 0.0f;
        acc += qrow[d0+0] * kr[d0+0];
        acc += qrow[d0+1] * kr[d0+1];
        acc += qrow[d0+2] * kr[d0+2];
        acc += qrow[d0+3] * kr[d0+3];
        acc += qrow[d0+4] * kr[d0+4];
        acc += qrow[d0+5] * kr[d0+5];
        acc += qrow[d0+6] * kr[d0+6];
        acc += qrow[d0+7] * kr[d0+7];
        acc += simd_shuffle_xor(acc, 1);
        acc += simd_shuffle_xor(acc, 2);
        acc += simd_shuffle_xor(acc, 4);
        if (sub == 0) scores[j] = acc * inv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Softmax with reduced integer conditional overhead
    float v = (tid < S) ? scores[tid] : -INFINITY;
    float mx_v = simd_max(v);
    if ((tid & 31) == 0) reduce_max[tid >> 5] = mx_v;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float m = (tid < 4) ? reduce_max[tid] : -INFINITY;
        m = simd_max(m);
        if (tid == 0) max_out = m;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = max_out;

    float e = (tid < S) ? fast::exp(scores[tid] - row_max) : 0.0f;
    if (tid < S) scores[tid] = e;
    float sum = simd_sum(e);
    if ((tid & 31) == 0) reduce_sum[tid >> 5] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float s = (tid < 4) ? reduce_sum[tid] : 0.0f;
        s = simd_sum(s);
        if (tid == 0) sum_out = s;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_sum = 1.0f / sum_out;

    if (tid < S) O[qr * S + tid] = scores[tid] * inv_sum;
}

avg_pool1d.metal_source:
// avg_pool1d: NLC. mean over window.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool1d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   L       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   K       [[buffer(5)]],
    constant     uint&   stride  [[buffer(6)]],
    uint tid [[thread_position_in_grid]])
{
    const uint L2 = (L - K) / stride + 1;
    const uint total = N * L2 * C;
    const float inv = 1.0f / float(K);

    // Each thread processes one output element (no batching)
    if (tid < total) {
        uint n = tid / (L2 * C);
        uint r = tid % (L2 * C);
        uint l2 = r / C;
        uint c = r % C;

        // Manual unrolling for K=3 (fixed by spec)
        uint base = (n * L + l2 * stride) * C + c;
        float s = x[base] + x[base + C] + x[base + 2*C];
        y[(n * L2 + l2) * C + c] = s * inv;
    }
}

avg_pool2d.metal_source:
// avg_pool2d: NHWC. K=2, stride=2. float4 along C dim.
// total4 == 2 * GRID; each thread emits 2 outputs.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool2d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   H       [[buffer(3)]],
    constant     uint&   W       [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    constant     uint&   stride  [[buffer(7)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint C4 = C >> 2;
    const uint total4 = N * H2 * W2 * C4;
    const float inv = 1.0f / float(K * K);

    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sN_in = H * W * C;
    const uint GRID = 64u * 1024u;

    uint idx0 = tid;
    uint idx1 = tid + GRID;

    for (uint k = 0; k < 2; ++k) {
        uint idx = (k == 0) ? idx0 : idx1;
        uint q = idx;
        uint c4 = q & (C4 - 1);  q /= C4;
        uint w2 = q % W2;        q /= W2;
        uint h2 = q % H2;        uint n = q / H2;

        uint base = n * sN_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + (c4 << 2);

        float4 v00 = *reinterpret_cast<const device float4*>(x + base);
        float4 v01 = *reinterpret_cast<const device float4*>(x + base + sW_in);
        float4 v10 = *reinterpret_cast<const device float4*>(x + base + sH_in);
        float4 v11 = *reinterpret_cast<const device float4*>(x + base + sH_in + sW_in);

        float4 s = (v00 + v01) + (v10 + v11);
        *reinterpret_cast<device float4*>(y + (idx << 2)) = s * inv;
    }
}

avg_pool3d.metal_source:
// avg_pool3d: NDHWC. K=2, stride=2 specialization.
#include <metal_stdlib>
using namespace metal;

kernel void avg_pool3d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   C       [[buffer(6)]],
    constant     uint&   K       [[buffer(7)]],
    constant     uint&   stride  [[buffer(8)]],
    uint tid [[thread_position_in_grid]])
{
    const uint D2 = (D - K) / stride + 1;
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint total = N * D2 * H2 * W2 * C;
    const float inv = 1.0f / float(K * K * K);

    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sD_in = H * W * C;
    const uint sN_in = D * H * W * C;

    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint c  = q % C;       q /= C;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      q /= H2;
        uint d2 = q % D2;      uint n = q / D2;

        uint base = n * sN_in + (d2 * stride) * sD_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + c;

        float v000 = x[base];
        float v001 = x[base + sW_in];
        float v010 = x[base + sH_in];
        float v011 = x[base + sH_in + sW_in];
        float v100 = x[base + sD_in];
        float v101 = x[base + sD_in + sW_in];
        float v110 = x[base + sD_in + sH_in];
        float v111 = x[base + sD_in + sH_in + sW_in];

        float s = (v000 + v001) + (v010 + v011) + (v100 + v101) + (v110 + v111);
        y[idx] = s * inv;
    }
}

batch_mm.metal_source:
// batch_matmul: C[b] = A[b] @ B[b]  (MxK @ KxN -> MxN f32) per batch.
// 64x64 tile, 256 thr, BK=16, double-buffered, padded. 2D flattened grid.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM  = 64;
constant constexpr uint BN  = 64;
constant constexpr uint BK  = 16;
constant constexpr uint SM  = 16;
constant constexpr uint SN  = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M   = SM / 8;
constant constexpr uint MMA_N   = SN / 8;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;
constant constexpr uint LDB = BN + PAD;

kernel void batch_matmul_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint3 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    const uint rows_per_batch = M / BM;
    const uint batch = tgid.y / rows_per_batch;
    const uint c_row0 = (tgid.y % rows_per_batch) * BM;

    const uint stride_a = M * K;
    const uint stride_b = K * N;
    const uint stride_c = M * N;

    A += batch * stride_a;
    B += batch * stride_b;
    C += batch * stride_c;

    threadgroup float As[2][BM * LDA];
    threadgroup float Bs[2][BK * LDB];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_col0 = tgid.x * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = K / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next   = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }

        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &C[(c_row0 + sm * SM + i * 8) * N + (c_col0 + sn * SN + j * 8)],
                            N);
}

batch_norm.metal_source:
// batchnorm: normalize each column over rows. (1024, 256) input.
// Strided simdgroup reduction over 1024 elements per column.
#include <metal_stdlib>
using namespace metal;

kernel void batch_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint col = tgid.y;

    float val = x[t * C + col];
    float s2  = val * val;

    float sum   = simd_sum(val);
    float sumsq = simd_sum(s2);

    threadgroup float tg_sum[32];
    threadgroup float tg_sumsq[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) {
        tg_sum[sg]   = sum;
        tg_sumsq[sg] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum   = tg_sum[t];
        sumsq = tg_sumsq[t];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
    }
    if (t == 0) {
        tg_sum[0]   = sum;
        tg_sumsq[0] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_sum[0] / float(N);
    float var  = max(tg_sumsq[0] / float(N) - mean * mean, 0.0f);
    float inv_std = rsqrt(var + eps);

    y[t * C + col] = (val - mean) * inv_std;
}

bias_add.metal_source:
// bias_add: y[r, c] = x[r, c] + b[c]. float4 grid-stride loop with cached bias.
#include <metal_stdlib>
using namespace metal;

kernel void bias_add_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                       [[thread_position_in_grid]],
    uint lid                       [[thread_position_in_threadgroup]],
    uint tg_size                   [[threads_per_threadgroup]])
{
    threadgroup float bias_tg[1024];
    for (uint i = lid; i < C; i += tg_size) bias_tg[i] = B[i];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const threadgroup float4*>(&bias_tg[base & Cmask]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + b;
    }
}

bias_gelu.metal_source:
// bias_gelu: y = gelu(x + b). float4 with cached bias in threadgroup memory.
#include <metal_stdlib>
using namespace metal;

constant constexpr float gelu_k = 0.79788456f; // sqrt(2/pi)

static inline float4 gelu_tanh4(float4 v) {
    float4 t = gelu_k * (v + 0.044715f * v * v * v);
    return 0.5f * v * (1.0f + tanh(t));
}

kernel void bias_gelu_f32(
    device const float*  X        [[buffer(0)]],
    device const float*  B        [[buffer(1)]],
    device       float*  Y        [[buffer(2)]],
    constant     uint&   N_total  [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint tid                       [[thread_position_in_grid]],
    uint lid                       [[thread_position_in_threadgroup]],
    uint tg_size                   [[threads_per_threadgroup]])
{
    threadgroup float bias_tg[1024];
    for (uint i = lid; i < C; i += tg_size) bias_tg[i] = B[i];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint n4 = N_total >> 2;
    const uint Cmask = C - 1;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 b = *reinterpret_cast<const threadgroup float4*>(&bias_tg[base & Cmask]);
        float4 z = x + b;
        *reinterpret_cast<device float4*>(&Y[base]) = gelu_tanh4(z);
    }
}

clip.metal_source:
// clip: out = clamp(x, lo, hi). Stub: scalar grid-stride. Replace with optimized version.
#include <metal_stdlib>
using namespace metal;

kernel void clip_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    constant     float&  lo        [[buffer(4)]],
    constant     float&  hi        [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        y[i] = clamp(x[i], lo, hi);
    }
}

conv1d.metal_source:
// conv1d implicit im2col GEMM with simdgroup_matrix MMA.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 8;
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 1
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 68

kernel void conv1d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   L       [[buffer(5)]],
    constant     uint&   K_out   [[buffer(6)]],
    constant     uint&   R       [[buffer(7)]],
    constant     uint&   stride_ [[buffer(8)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint L2 = (L - R) / stride_ + 1;
    const uint M_g = N_ * L2;
    const uint K_g = R * C;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_n_tiles = K_out / BN;
    const uint total_tiles = num_m_tiles * num_n_tiles;

    threadgroup float As[BM * LDA];
    threadgroup float Bs[BK * LDB];
    threadgroup float Cs[BM * BN];

    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint mtile = tile / num_n_tiles;
        const uint ntile = tile % num_n_tiles;
        const uint c_row0 = mtile * BM;
        const uint c_col0 = ntile * BN;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = K_g / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;
            const uint rr = k0 / C;
            const uint c_base = k0 - rr * C;

            {
                const uint a_row = lid / 16u;
                const uint a_col = lid % 16u;
                const uint m_g = c_row0 + a_row;
                float v = 0.0f;
                if (m_g < M_g) {
                    const uint n_idx = m_g / L2;
                    const uint l2_idx = m_g - n_idx * L2;
                    const uint li = l2_idx * stride_ + rr;
                    v = x[(n_idx * L + li) * C + c_base + a_col];
                }
                As[a_row * LDA + a_col] = v;
            }
            {
                const uint b_col = lid / BK;
                const uint b_row = lid % BK;
                const uint k_glob = k0 + b_row;
                const uint n_col = c_col0 + b_col;
                Bs[b_row * LDB + b_col] = w[n_col * K_g + k_glob];
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            const uint idx = lid;
            const uint r = (idx * 4u) / BN;
            const uint c = (idx * 4u) % BN;
            const uint m_g = c_row0 + r;
            if (m_g < M_g) {
                const uint n_idx = m_g / L2;
                const uint l2_idx = m_g - n_idx * L2;
                float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                *reinterpret_cast<device float4*>(&y[(n_idx * L2 + l2_idx) * K_out + c_col0 + c]) = v;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv2d.metal_source:
// conv2d M2: implicit-im2col GEMM with simdgroup_matrix MMA, split-issue A/B loads.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 32;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint NUM_SG  = SIMDS_M * SIMDS_N;  // 32
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 36
constant constexpr uint LDB = BN + PAD;      // 132

[[max_total_threads_per_threadgroup(1024)]]
kernel void conv2d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   K_out   [[buffer(7)]],
    constant     uint&   R       [[buffer(8)]],
    constant     uint&   S       [[buffer(9)]],
    constant     uint&   stride_ [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H2 = (H - R) / stride_ + 1;
    const uint W2 = (W - S) / stride_ + 1;
    const uint M_g = N_ * H2 * W2;
    const uint K_g = R * S * C;
    const uint SC  = S * C;
    const uint HW2 = H2 * W2;
    const uint num_m_tiles = (M_g + BM - 1) / BM;

    threadgroup float scratch[BM * BN];     // 8192 floats = 32 KB
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;     // offset 2304, length 32*132=4224
    threadgroup float* Cs = scratch;                // alias (used after K-loop)
    // Row metadata stashed after As+Bs (end=6528). 256 floats free → 4 BM-sized uint arrays.
    threadgroup uint* row_n = (threadgroup uint*)(scratch + 6528);          // [BM]
    threadgroup uint* row_h = (threadgroup uint*)(scratch + 6528 + BM);     // [BM]
    threadgroup uint* row_w = (threadgroup uint*)(scratch + 6528 + 2 * BM); // [BM]
    threadgroup uint* row_in_arr = (threadgroup uint*)(scratch + 6528 + 3 * BM); // [BM]

    const uint sm = sgid / SIMDS_N;          // 0..3
    const uint sn = sgid % SIMDS_N;          // 0..7

    // ---- Split 1024 threads into two halves so A-load and B-load issue in
    // parallel (different threads, no dependence). 512 do A, 512 do B.
    //
    // A-load (BM=64 × BK=32 = 2048 floats). 512 threads × 1 float4 = 2048. We
    // tile A as float4 along c (4 consecutive c values). 64 rows × 8 float4
    // = 512 jobs.
    const uint a_lid  = lid;                              // 0..511 active
    const uint a_row  = a_lid / 8u;                       // 0..63
    const uint a_col4 = a_lid & 7u;                       // 0..7 (float4 in c)
    const uint a_col0 = a_col4 * 4u;                      // 0..28

    // B-load (BK=32 × BN=128 = 4096 floats). 512 threads × 2 float4 = 4096.
    // Weights w[n_col, k] are K-contiguous → float4 along k.
    // 128 n_cols × 8 float4 (k_glob=k_base..k_base+3) = 1024 float4 jobs.
    // 512 threads × 2 float4 each.
    const uint b_lid  = lid - 512u;                        // 0..511 when lid>=512
    const uint b_col_a = b_lid / 8u;                       // 0..63   (1st N half)
    const uint b_k4    = b_lid & 7u;                       // 0..7
    const uint b_col_b = b_col_a + 64u;                    // 64..127 (2nd N half)

    // Persistent-threadgroup loop: each TG processes multiple BM-tiles.
    for (uint tile = tg_id; tile < num_m_tiles; tile += n_tg) {
        const uint c_row0 = tile * BM;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        // Hoist per-row (n,h,w) into TG SMEM so the A-load thread (which owns
        // a_row = a_lid/8) can read its row coords without per-thread div.
        // Hoist per-row coords into shared scratch (aliased onto Cs region).
        if (lid < BM) {
            const uint m_g = c_row0 + lid;
            uint nv = 0, hv = 0, wv = 0, inb = 0;
            if (m_g < M_g) {
                nv = m_g / HW2;
                const uint rem = m_g - nv * HW2;
                hv = rem / W2;
                wv = rem - hv * W2;
                inb = 1;
            }
            row_n[lid] = nv; row_h[lid] = hv; row_w[lid] = wv;
            row_in_arr[lid] = inb;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        const uint nv_a = row_n[a_row];
        const uint hv_a = row_h[a_row];
        const uint wv_a = row_w[a_row];
        const bool a_row_in = (row_in_arr[a_row] != 0);
        // Pre-compute the row-major x offset for (n, h0*stride, w0*stride, c=0)
        // so the K-loop only adds (rr*W + ss)*C + cbase.
        const uint x_row_base = ((nv_a * H + hv_a * stride_) * W + wv_a * stride_) * C;

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        // K_g = R*S*C is divisible by BK (576 % 32 == 0 in registry), and each
        // BK-aligned k-tile sits inside a single (rr, ss) cell because BK | C
        // (32 | 64). Compute rr, ss, and c_base ONCE per k-tile (uniform across
        // threads) and only the per-thread c offset varies.
        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;
            const uint rr_t   = k0 / SC;
            const uint rem_t  = k0 - rr_t * SC;
            const uint ss_t   = rem_t / C;
            const uint cbase  = rem_t - ss_t * C;     // c for a_col=0
            // ---- A-load (lid < 512): 1 float4 per thread along c.
            // Each a_row's A-tile covers c=[cbase, cbase+BK). Within a tile,
            // 4 consecutive a_col → 4 consecutive c (no boundary crossing).
            if (lid < 512u) {
                float4 v = float4(0.0f);
                if (a_row_in) {
                    // (h0+rr)*W + (w0+ss) - (h0*W + w0) = rr*W + ss; multiplied
                    // by C and added to cbase gives the per-k offset.
                    const uint k_off = (rr_t * W + ss_t) * C + cbase + a_col0;
                    v = *reinterpret_cast<const device float4*>(
                            &x[x_row_base + k_off]);
                }
                *reinterpret_cast<threadgroup float4*>(&As[a_row * LDA + a_col0]) = v;
            } else {
            // ---- B-load (lid >= 512): 2 float4s per thread, K-contiguous.
                const uint k_base = k0 + b_k4 * 4u;
                const uint k_row  = b_k4 * 4u;
                // K-major Bs layout (k=row, n=col). Float4 from w (K-contig)
                // is scattered to 4 distinct k-rows. Two N halves per thread.
                {
                    float4 va = *reinterpret_cast<const device float4*>(
                            &w[b_col_a * K_g + k_base]);
                    Bs[(k_row + 0u) * LDB + b_col_a] = va.x;
                    Bs[(k_row + 1u) * LDB + b_col_a] = va.y;
                    Bs[(k_row + 2u) * LDB + b_col_a] = va.z;
                    Bs[(k_row + 3u) * LDB + b_col_a] = va.w;
                }
                {
                    float4 vb = *reinterpret_cast<const device float4*>(
                            &w[b_col_b * K_g + k_base]);
                    Bs[(k_row + 0u) * LDB + b_col_b] = vb.x;
                    Bs[(k_row + 1u) * LDB + b_col_b] = vb.y;
                    Bs[(k_row + 2u) * LDB + b_col_b] = vb.z;
                    Bs[(k_row + 3u) * LDB + b_col_b] = vb.w;
                }
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Stage simdgroup tiles to SMEM Cs, then float4 scatter to device y.
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r = (lid / 32u) + rs * 32u;
                const uint cq = lid % 32u;
                const uint cc = cq * 4u;
                const uint m_g = c_row0 + r;
                if (m_g < M_g) {
                    const uint nv = m_g / HW2;
                    const uint rem = m_g - nv * HW2;
                    const uint hv = rem / W2;
                    const uint wv = rem - hv * W2;
                    float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + cc]);
                    *reinterpret_cast<device float4*>(&y[((nv * H2 + hv) * W2 + wv) * K_out + cc]) = v;
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv2d_relu_bias.metal_source:
// conv2d_relu_bias: implicit im2col GEMM via simdgroup_matrix MMA + fused bias + ReLU epilogue.
// NHWC. x (N=8,H=64,W=64,C=64), w (K=128,R=3,S=3,C=64), b (K), y (N,H2=62,W2=62,K=128).
// GEMM: M_g = N*H2*W2 = 30752, N_g = K = 128, K_g = R*S*C = 576.
// Tile BM=64, BN=128, BK=16. 1024 threads = 32 simdgroups.

#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 16;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 132

kernel void conv2d_relu_bias_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device const float*  b       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   N_      [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   C       [[buffer(7)]],
    constant     uint&   K_out   [[buffer(8)]],
    constant     uint&   R       [[buffer(9)]],
    constant     uint&   S       [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H2 = (H - R) + 1;
    const uint W2 = (W - S) + 1;
    const uint M_g = N_ * H2 * W2;
    const uint K_g = R * S * C;
    const uint SC  = S * C;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint total_tiles = num_m_tiles;

    threadgroup float scratch[BM * BN];
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;
    threadgroup float* Cs = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint c_row0 = tile * BM;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            {
                const uint a_row = lid / BK;
                const uint a_col = lid % BK;
                const uint m_g = c_row0 + a_row;
                const uint k_glob = k0 + a_col;
                float v = 0.0f;
                if (m_g < M_g && k_glob < K_g) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C;
                    const uint c  = rem - ss * C;
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    const uint hi = h2 + rr;
                    const uint wi = w2 + ss;
                    v = x[((n_idx * H + hi) * W + wi) * C + c];
                }
                As[a_row * LDA + a_col] = v;
            }
            #pragma unroll
            for (uint p = 0; p < 2; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t % BK;
                const uint k_glob = k0 + b_row;
                const uint n_col = b_col;
                float v = 0.0f;
                if (k_glob < K_g && n_col < K_out) {
                    v = w[n_col * K_g + k_glob];
                }
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Epilogue: add bias, ReLU, store. Each thread stores 1 row × 4 cols (float4).
        // 1024 threads / (BN/4=32 cols) = 32 rows per pass; 64 rows → 2 passes.
        {
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r = (lid / 32u) + rs * 32u;
                const uint cq = lid % 32u;
                const uint c = cq * 4u;
                const uint m_g = c_row0 + r;
                if (m_g < M_g) {
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                    float4 bv = *reinterpret_cast<device const float4*>(&b[c]);
                    v += bv;
                    v = fmax(v, float4(0.0f));
                    *reinterpret_cast<device float4*>(&y[((n_idx * H2 + h2) * W2 + w2) * K_out + c]) = v;
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv3d.metal_source:
// conv3d M2: implicit im2col GEMM with simdgroup_matrix MMA.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 32;
constant constexpr uint SM = 16, SN = 8;
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 1
constant constexpr uint PAD_A = 0;
constant constexpr uint PAD_B = 4;
constant constexpr uint LDA = BK + PAD_A;    // 32
constant constexpr uint LDB = BN + PAD_B;    // 68

[[max_total_threads_per_threadgroup(1024)]]
kernel void conv3d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   D       [[buffer(5)]],
    constant     uint&   H       [[buffer(6)]],
    constant     uint&   W       [[buffer(7)]],
    constant     uint&   K_out   [[buffer(8)]],
    constant     uint&   R       [[buffer(9)]],
    constant     uint&   stride_ [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint D2 = (D - R) / stride_ + 1;
    const uint H2 = (H - R) / stride_ + 1;
    const uint W2 = (W - R) / stride_ + 1;
    const uint HW2 = H2 * W2;
    const uint DHW2 = D2 * HW2;
    const uint M_g = N_ * DHW2;
    const uint RC = R * C;
    const uint RRC = R * RC;
    const uint K_g = R * RRC;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_n_tiles = (K_out + BN - 1) / BN;
    const uint total_tiles = num_m_tiles * num_n_tiles;

    // Single shared tgmem pool: holds As+Bs during k-loop; reused as Cs at epilogue.
    // As size = BM*LDA = 2048, Bs size = BK*LDB = 2176, sum = 4224.
    // Cs needs BM*BN = 4096, which fits within the same 4224-float pool.
    constexpr uint TGPOOL = BM * LDA + BK * LDB; // 4224
    threadgroup float pool[TGPOOL];
    threadgroup float* As = pool;
    threadgroup float* Bs = pool + BM * LDA;
    threadgroup float* Cs = pool; // overlapped with A/B, only used post-MMA barrier

    // Per-row cached input base offsets (set once per output tile).
    // x_base[row] = (((n*D + di_base) * H + hi_base) * W + wi_base) * C
    // ...where di_base = d_idx*stride, etc. Sentinel = UINT_MAX for OOB rows.
    threadgroup uint x_row_base[BM];
    threadgroup uchar x_row_valid[BM];

    // Per-k-element cached weight-channel decomposition (set once per kt).
    // For k_glob = k0 + col, we need (rd, rh, rw, c) such that the x-offset
    // contribution is ((rd*H + rh)*W + rw)*C + c.
    threadgroup uint k_x_off[BK];   // ((rd*H + rh)*W + rw)*C + c
    threadgroup uchar k_valid[BK];

    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint mtile = tile / num_n_tiles;
        const uint ntile = tile % num_n_tiles;
        const uint c_row0 = mtile * BM;
        const uint c_col0 = ntile * BN;

        // Precompute per-row x-base offsets (64 rows, use first 64 threads).
        if (lid < BM) {
            const uint m_g = c_row0 + lid;
            if (m_g < M_g) {
                const uint n_idx = m_g / DHW2;
                uint q = m_g - n_idx * DHW2;
                const uint d_idx = q / HW2;
                q -= d_idx * HW2;
                const uint h_idx = q / W2;
                const uint w_idx = q - h_idx * W2;
                const uint di_b = d_idx * stride_;
                const uint hi_b = h_idx * stride_;
                const uint wi_b = w_idx * stride_;
                x_row_base[lid] = (((n_idx * D + di_b) * H + hi_b) * W + wi_b) * C;
                x_row_valid[lid] = 1;
            } else {
                x_row_base[lid] = 0;
                x_row_valid[lid] = 0;
            }
        }

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            // Precompute per-kt the weight-channel decomposition (BK cols).
            if (lid < BK) {
                const uint k_glob = k0 + lid;
                if (k_glob < K_g) {
                    const uint rd = k_glob / RRC;
                    uint rem = k_glob - rd * RRC;
                    const uint rh = rem / RC;
                    rem -= rh * RC;
                    const uint rw = rem / C;
                    const uint c  = rem - rw * C;
                    k_x_off[lid] = ((rd * H + rh) * W + rw) * C + c;
                    k_valid[lid] = 1;
                } else {
                    k_x_off[lid] = 0;
                    k_valid[lid] = 0;
                }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);

            // Stage A: BM x BK = 64 x 32 = 2048 elements, 2 per thread.
            // Thread layout: 32 cols × 32 rows-of-2.
            // pass 0 → rows 0..31, pass 1 → rows 32..63.
            {
                const uint a_col = lid & (BK - 1);   // 0..31
                const uint a_row0 = lid / BK;        // 0..31
                #pragma unroll
                for (uint pass = 0; pass < 2u; ++pass) {
                    const uint a_row = a_row0 + pass * 32u;
                    float v = 0.0f;
                    if (x_row_valid[a_row] && k_valid[a_col]) {
                        v = x[x_row_base[a_row] + k_x_off[a_col]];
                    }
                    As[a_row * LDA + a_col] = v;
                }
            }
            // Stage B: BK x BN = 32 x 64 = 2048 elements, 2 per thread.
            {
                const uint b_col0 = lid / BK;        // 0..31
                const uint b_row = lid & (BK - 1);   // 0..31
                const uint k_glob = k0 + b_row;
                const bool k_ok = (k_glob < K_g);
                #pragma unroll
                for (uint pass = 0; pass < 2u; ++pass) {
                    const uint b_col = b_col0 + pass * 32u;
                    const uint n_col = c_col0 + b_col;
                    float v = 0.0f;
                    if (k_ok && n_col < K_out) {
                        v = w[n_col * K_g + k_glob];
                    }
                    Bs[b_row * LDB + b_col] = v;
                }
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            const uint idx = lid;
            const uint r = (idx * 4u) / BN;
            const uint c = (idx * 4u) % BN;
            const uint m_g = c_row0 + r;
            if (m_g < M_g) {
                const uint n_idx = m_g / DHW2;
                uint q = m_g - n_idx * DHW2;
                const uint d_idx = q / HW2;
                q -= d_idx * HW2;
                const uint h_idx = q / W2;
                const uint w_idx = q - h_idx * W2;
                float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                const uint nc = c_col0 + c;
                const uint y_base = (((n_idx * D2 + d_idx) * H2 + h_idx) * W2 + w_idx) * K_out + nc;
                if (nc + 3 < K_out) {
                    *reinterpret_cast<device float4*>(&y[y_base]) = v;
                } else {
                    float vs[4] = {v.x, v.y, v.z, v.w};
                    for (uint kk = 0; kk < 4u; ++kk) {
                        if (nc + kk < K_out)
                            y[y_base + kk] = vs[kk];
                    }
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv3d_div_pool_sum.metal_source:
// Multi-TG. Each thread handles its own tile-slice. Per tile, patch is loaded
// once into TG memory (shared by threads in TG). Each thread iterates over
// all 64 k's, reading weights from global, patch from tg memory. Per-thread
// running max over k. Across threads in TG, summation via tree-reduce.
//
// To amortize: each TG processes many tiles, where threads do them in parallel
// (each thread = one tile). TG_THR=64 threads per TG → 64 tiles in parallel.
// All 64 threads share the same patch? No — they have different tiles → no
// patch sharing.
//
// Better: each TG processes ONE tile per "iteration", and TG_THR=64 threads
// all collaborate. Each thread = one k. Patch loaded into tg mem, used by
// all 64 threads. Weights are per-thread (1 k per thread), loaded from global
// per tile. Weight reuse only if tiles overlap (they do, but not naturally).
//
// Best: outer-tile, weights cached across tiles in registers per thread (1 k).
// This is the design here.
#include <metal_stdlib>
using namespace metal;

#define NBUCK 128u
#define TG_THR 64u

kernel void conv3d_div_pool_sum_f32(
    device const float* x [[buffer(0)]],
    device const float* w [[buffer(1)]],
    device       float* y [[buffer(2)]],
    constant     uint& N  [[buffer(3)]],
    constant     uint& C  [[buffer(4)]],
    constant     uint& D  [[buffer(5)]],
    constant     uint& H  [[buffer(6)]],
    constant     uint& W  [[buffer(7)]],
    constant     uint& K  [[buffer(8)]],
    constant     uint& R  [[buffer(9)]],
    constant     float& div_val  [[buffer(10)]],
    constant     float& bias_val [[buffer(11)]],
    uint3 tgid [[threadgroup_position_in_grid]],
    uint3 tg_per_grid [[threadgroups_per_grid]],
    uint  tid  [[thread_index_in_threadgroup]],
    uint  sg   [[simdgroup_index_in_threadgroup]],
    uint  lane [[thread_index_in_simdgroup]])
{
    constexpr uint Cc=32, Rc=3, Kc=64, Dc=32, Hc=32, Wc=32, Nc=4;
    constexpr uint D2=Dc-Rc+1, H2=Hc-Rc+1, W2=Wc-Rc+1;
    constexpr uint VOL    = D2*H2*W2;
    constexpr uint NTILES = Nc * VOL;
    constexpr uint PATCH  = Cc*Rc*Rc*Rc;

    const uint mytg = tgid.x;
    const uint nTGs = tg_per_grid.x;

    threadgroup float patch[PATCH];
    threadgroup float sgmax_buf[2];

    // Each thread = one k. Load this thread's weights ONCE (864 floats).
    // Use strided lane layout so we can later do simd_sum cooperative dot.
    // wreg[j] = W[k=tid, lane + 32*j] for j=0..26.
    // BUT 27 floats × 4B = 108B per thread; weights for 64 ks = 64*864 = 55K B
    // shared across all threads.
    //
    // Wait — each thread holds its OWN k's full slice (864 floats). That's
    // 864 regs × 64 threads = 55K regs per TG → 220 KB. Way too many regs.
    //
    // Trick: have each thread hold weights for its k in strided format so
    // simd_sum can cooperate. With 32 lanes per simdgroup, lane l holds
    // 27 weights of the simdgroup's k=sg+ ... no wait that's the prior design.
    //
    // Let me just stick with the simd-coop dot with running weight loads.
    // 32 passes per tile, each pass each sg loads 27 weights from global.
    // Weight bandwidth: 32*27*4 = 3.5 KB per tile per simdgroup, total per
    // tile = 7 KB. Across 108000 tiles = 740 MB. At 100 GB/s = 7.4 ms.
    //
    // PLUS patch: 3.5 KB per tile × 108000 = 380 MB → 3.8 ms.
    //
    // Total memory time ≈ 11 ms theoretical. Compute time ≈ 4 ms (computed
    // earlier). MLX 17-24 ms. So we should be able to hit ~12 ms ⇒ 2× speedup.
    //
    // The 51 ms we got is 5× memory-bound. Why? Probably because L2 isn't
    // being utilized — every TG reads the same weights and they should cache.
    // Maybe Apple's L1 per-core is small and 220 KB weights spill.

    float local_sum = 0.0f;

    const uint tiles_per_tg = (NTILES + nTGs - 1) / nTGs;
    const uint tile_lo = mytg * tiles_per_tg;
    const uint tile_hi = min(NTILES, tile_lo + tiles_per_tg);

    for (uint t = tile_lo; t < tile_hi; ++t) {
        uint w2 =  t % W2;
        uint h2 = (t / W2) % H2;
        uint d2 = (t / (W2 * H2)) % D2;
        uint n  =  t / (W2 * H2 * D2);

        threadgroup float4* p4 = (threadgroup float4*)patch;
        device const float4* x4 = (device const float4*)x;
        #pragma unroll
        for (uint ii = 0; ii < 4; ++ii) {
            uint i = tid + ii*TG_THR;
            if (i < 216) {
                uint spatial = i >> 3;
                uint cvec    = i & 7;
                uint rd = spatial / 9u;
                uint rem = spatial - rd*9u;
                uint rh = rem / 3u;
                uint rw = rem - rh*3u;
                uint x_idx = ((((n*Dc + d2 + rd)*Hc + h2 + rh)*Wc + w2 + rw)*Cc) >> 2;
                p4[i] = x4[x_idx + cvec];
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Hold per-lane patch slice.
        float p_reg[27];
        #pragma unroll
        for (uint j = 0; j < 27; ++j) p_reg[j] = patch[lane + 32u*j];

        float tile_max = -INFINITY;
        // 2 simdgroups → 2 k's per pass, 32 passes for K=64.
        for (uint pass = 0; pass < 32; ++pass) {
            uint k = pass * 2u + sg;
            const device float* wk = w + k * PATCH;
            float s = 0.0f;
            // Manually unroll inner loop 27 ways → 27 fma.
            #pragma unroll
            for (uint j = 0; j < 27; ++j) {
                s = fma(p_reg[j], wk[lane + 32u*j], s);
            }
            s = simd_sum(s);
            tile_max = max(tile_max, s);
        }

        if (lane == 0) sgmax_buf[sg] = tile_max;
        threadgroup_barrier(mem_flags::mem_threadgroup);
        float final_tile_max = max(sgmax_buf[0], sgmax_buf[1]);

        if (tid == 0) local_sum += final_tile_max;
    }

    if (tid == 0) {
        device atomic<float>* slot = (device atomic<float>*)(y + 1 + (mytg % NBUCK));
        atomic_fetch_add_explicit(slot, local_sum, memory_order_relaxed);
    }

    threadgroup_barrier(mem_flags::mem_device);

    threadgroup bool am_last;
    if (tid == 0) {
        am_last = false;
        device atomic_uint* counter = (device atomic_uint*)(y + (1 + NBUCK));
        uint prev = atomic_fetch_add_explicit(counter, 1u, memory_order_relaxed);
        if (prev + 1u == nTGs) am_last = true;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (!am_last) return;

    float fsum_local = 0.0f;
    for (uint i = tid; i < NBUCK; i += TG_THR) {
        fsum_local += y[1 + i];
    }
    float fsg = simd_sum(fsum_local);
    if (lane == 0) sgmax_buf[sg] = fsg;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid == 0) {
        float total = sgmax_buf[0] + sgmax_buf[1];
        const float final_scale = (1.0f / div_val) / float(VOL);
        y[0] = total * final_scale + float(Nc) * bias_val;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    for (uint i = tid; i < NBUCK; i += TG_THR) {
        y[1 + i] = 0.0f;
    }
    if (tid == 0) {
        device atomic_uint* counter = (device atomic_uint*)(y + (1 + NBUCK));
        atomic_store_explicit(counter, 0u, memory_order_relaxed);
    }
}

conv3d_multi_act_bias.metal_source:
// conv3d implicit im2col GEMM with simdgroup_matrix MMA, fused activation+bias epilogue.
// NDHWC, k=3, stride=1. x (4,32,32,32,32), w (64,3,3,3,32), b(64) -> y (4,30,30,30,64).
// GEMM: M = 4*30^3 = 108000, N = 64, K = 27*32 = 864.
// Activation chain (post-conv): relu -> leaky(0.01) -> gelu -> sigmoid + bias.
//   For x>=0 leaky_relu is identity. So fused fn collapses to:
//     v = max(conv, 0); v = gelu_erf(v); v = sigmoid(v); v += b[k].

#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 8;
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 1
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 68

static inline float gelu_erf_poly(float x) {
    const float k = 0.70710678f;
    float z = x * k;
    float t = 1.0f / (1.0f + 0.3275911f * fabs(z));
    float y = 1.0f - (((((1.061405429f * t - 1.453152027f) * t)
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f)
              * t * exp(-z * z);
    float erfz = copysign(y, z);
    return 0.5f * x * (1.0f + erfz);
}

static inline float fused_act(float x, float bias) {
    float v = fmax(x, 0.0f);            // relu (leaky no-op since v>=0)
    v = gelu_erf_poly(v);               // gelu
    v = 1.0f / (1.0f + exp(-v));        // sigmoid (v bounded since x>=0 -> gelu>=0 -> sig in [0.5,1])
    return v + bias;
}

kernel void conv3d_multi_act_bias_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device const float*  b       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   N_      [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   D       [[buffer(6)]],
    constant     uint&   H       [[buffer(7)]],
    constant     uint&   W       [[buffer(8)]],
    constant     uint&   K_out   [[buffer(9)]],
    constant     uint&   R       [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint D2 = D - R + 1;
    const uint H2 = H - R + 1;
    const uint W2 = W - R + 1;
    const uint HW2 = H2 * W2;
    const uint DHW2 = D2 * HW2;
    const uint M_g = N_ * DHW2;
    const uint RC = R * C;
    const uint RRC = R * RC;
    const uint K_g = R * RRC;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_n_tiles = (K_out + BN - 1) / BN;
    const uint total_tiles = num_m_tiles * num_n_tiles;

    threadgroup float As[BM * LDA];
    threadgroup float Bs[BK * LDB];
    threadgroup float Cs[BM * BN];

    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint mtile = tile / num_n_tiles;
        const uint ntile = tile % num_n_tiles;
        const uint c_row0 = mtile * BM;
        const uint c_col0 = ntile * BN;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        // Per-thread A-row coords (constant over k-loop).
        const uint a_row = lid / 16u;
        const uint a_col0 = lid % 16u;
        const uint m_g_A = c_row0 + a_row;
        uint a_n=0, a_d=0, a_h=0, a_w=0;
        bool a_valid_row = m_g_A < M_g;
        if (a_valid_row) {
            a_n = m_g_A / DHW2;
            uint q = m_g_A - a_n * DHW2;
            a_d = q / HW2;
            q -= a_d * HW2;
            a_h = q / W2;
            a_w = q - a_h * W2;
        }

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            // Load A: 64*16 = 1024 elems, 1/thread.
            {
                const uint a_col = a_col0;
                const uint k_glob = k0 + a_col;
                const uint rd = k_glob / RRC;
                uint rem = k_glob - rd * RRC;
                const uint rh = rem / RC;
                rem -= rh * RC;
                const uint rw = rem / C;
                const uint c  = rem - rw * C;

                float v = 0.0f;
                if (a_valid_row && k_glob < K_g) {
                    const uint di = a_d + rd;
                    const uint hi = a_h + rh;
                    const uint wi = a_w + rw;
                    v = x[(((a_n * D + di) * H + hi) * W + wi) * C + c];
                }
                As[a_row * LDA + a_col] = v;
            }
            // Load B: 16 rows × 64 cols = 1024 elems.
            {
                const uint b_col = lid / BK;
                const uint b_row = lid % BK;
                const uint k_glob = k0 + b_row;
                const uint n_col = c_col0 + b_col;
                float v = 0.0f;
                if (k_glob < K_g && n_col < K_out) {
                    v = w[n_col * K_g + k_glob];
                }
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Epilogue: fused activation + bias, store with float4.
        {
            const uint idx = lid;
            const uint r = (idx * 4u) / BN;
            const uint c = (idx * 4u) % BN;
            const uint m_g = c_row0 + r;
            if (m_g < M_g) {
                const uint n_idx = m_g / DHW2;
                uint q = m_g - n_idx * DHW2;
                const uint d_idx = q / HW2;
                q -= d_idx * HW2;
                const uint h_idx = q / W2;
                const uint w_idx = q - h_idx * W2;
                float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                const uint nc = c_col0 + c;
                // Load 4 biases.
                float4 bv;
                if (nc + 3 < K_out) {
                    bv = *reinterpret_cast<device const float4*>(&b[nc]);
                } else {
                    bv = float4(0.0f);
                    for (uint kk = 0; kk < 4u; ++kk)
                        if (nc + kk < K_out) ((thread float*)&bv)[kk] = b[nc + kk];
                }
                v.x = fused_act(v.x, bv.x);
                v.y = fused_act(v.y, bv.y);
                v.z = fused_act(v.z, bv.z);
                v.w = fused_act(v.w, bv.w);
                const uint y_base = (((n_idx * D2 + d_idx) * H2 + h_idx) * W2 + w_idx) * K_out + nc;
                if (nc + 3 < K_out) {
                    *reinterpret_cast<device float4*>(&y[y_base]) = v;
                } else {
                    float vs[4] = {v.x, v.y, v.z, v.w};
                    for (uint kk = 0; kk < 4u; ++kk) {
                        if (nc + kk < K_out)
                            y[y_base + kk] = vs[kk];
                    }
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv_transpose2d.metal_source:
// conv_transpose2d M2-optimized: NHWC, R=S=3, stride configurable
// (fast path stride==2). 128x128 tile, BK=16, hand-coded outer-product MMA.
//
// M2 wins vs default.metal:
//   - Per-row output decomposition cached in TG memory (computed once per tile,
//     avoiding redundant int div/mod inside the k-loop).
//   - Per-k weight decomposition cached in TG memory.
//   - stride==2 power-of-2 fast path (parity test == lsb test, hi=h_sig>>1).
//   - C_in==64 power-of-2 fast path (modulo, divide via shift+mask).
//   - float4 vectorized B-tile reads + float4 epilogue stores.
//   - Streamed-A inner loop (A read from TG mem; no register A tile).
#include <metal_stdlib>
using namespace metal;

[[max_total_threads_per_threadgroup(1024)]]
kernel void conv_transpose2d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C_in    [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   C_out   [[buffer(7)]],
    constant     uint&   R       [[buffer(8)]],
    constant     uint&   stride_ [[buffer(9)]],
    uint  tid_in_tg [[thread_position_in_threadgroup]],
    uint  tg_id     [[threadgroup_position_in_grid]],
    uint  n_tg      [[threadgroups_per_grid]])
{
    constexpr uint BM = 128;
    constexpr uint BN = 128;
    constexpr uint BK = 16;
    constexpr uint TM = 4;
    constexpr uint TN = 4;

    const uint H_out = (H - 1) * stride_ + R;
    const uint W_out = (W - 1) * stride_ + R;
    const uint HW_out = H_out * W_out;
    const uint M_g = N_ * HW_out;
    const uint SC = R * C_in;
    const uint Kd = R * SC;
    const uint num_m_tiles = (M_g + BM - 1) / BM;

    threadgroup float Atile[BM * BK];       // 8192 B
    threadgroup float Btile[BK * BN];       // 8192 B
    threadgroup ushort Row_nn[BM];
    threadgroup ushort Row_h[BM];
    threadgroup ushort Row_w[BM];
    threadgroup uchar  Row_valid[BM];
    threadgroup uchar  K_rr[BK];
    threadgroup uchar  K_ss[BK];
    threadgroup ushort K_c[BK];

    const uint ty = tid_in_tg / 32;
    const uint tx = tid_in_tg & 31u;

    const bool c_in_pow2_64 = (C_in == 64);
    const bool stride_2 = (stride_ == 2);

    for (uint mtile = tg_id; mtile < num_m_tiles; mtile += n_tg) {
        const uint m_base = mtile * BM;

        // Per-row metadata (BM=128, use first 128 threads).
        if (tid_in_tg < BM) {
            const uint m_g = m_base + tid_in_tg;
            if (m_g < M_g) {
                const uint nn = m_g / HW_out;
                uint q = m_g - nn * HW_out;
                const uint hh = q / W_out;
                const uint ww = q - hh * W_out;
                Row_nn[tid_in_tg] = (ushort)nn;
                Row_h[tid_in_tg]  = (ushort)hh;
                Row_w[tid_in_tg]  = (ushort)ww;
                Row_valid[tid_in_tg] = 1;
            } else {
                Row_valid[tid_in_tg] = 0;
            }
        }

        // Per-thread row metadata for epilogue.
        uint n_idx[TM], h_out_idx[TM], w_out_idx[TM];
        bool row_valid_reg[TM];
        for (uint i = 0; i < TM; ++i) {
            const uint m_g = m_base + ty + i * 32u;
            row_valid_reg[i] = (m_g < M_g);
            if (row_valid_reg[i]) {
                uint q = m_g;
                n_idx[i]     = q / HW_out; q -= n_idx[i] * HW_out;
                h_out_idx[i] = q / W_out;
                w_out_idx[i] = q - h_out_idx[i] * W_out;
            }
        }

        float acc[TM][TN];
        for (uint i = 0; i < TM; ++i)
            for (uint j = 0; j < TN; ++j) acc[i][j] = 0.0f;

        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint k0 = 0; k0 < Kd; k0 += BK) {
            // Per-k decomposition (BK=16, first 16 threads).
            if (tid_in_tg < BK) {
                const uint k_glob = k0 + tid_in_tg;
                uint rr, ss, c;
                if (c_in_pow2_64) {
                    c = k_glob & 63u;
                    const uint sc_idx = k_glob >> 6;
                    rr = sc_idx / R;
                    ss = sc_idx - rr * R;
                } else {
                    rr = k_glob / SC;
                    uint rem = k_glob - rr * SC;
                    ss = rem / C_in;
                    c  = rem - ss * C_in;
                }
                K_rr[tid_in_tg] = (uchar)rr;
                K_ss[tid_in_tg] = (uchar)ss;
                K_c[tid_in_tg]  = (ushort)c;
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);

            // Stage A: BM*BK = 128*16 = 2048 elements / 1024 threads = 2 per thread.
            // Thread t → (row = t/BK + pass*64, col = t%BK).
            {
                const uint a_col = tid_in_tg & (BK - 1);   // 0..15
                const uint a_row0 = tid_in_tg / BK;        // 0..63
                #pragma unroll
                for (uint pass = 0; pass < 2u; ++pass) {
                    const uint a_row = a_row0 + pass * 64u;
                    float v = 0.0f;
                    if (Row_valid[a_row]) {
                        const uint nn = (uint)Row_nn[a_row];
                        const uint hh_out = (uint)Row_h[a_row];
                        const uint ww_out = (uint)Row_w[a_row];
                        const uint rr = (uint)K_rr[a_col];
                        const uint ss = (uint)K_ss[a_col];
                        const uint c  = (uint)K_c[a_col];
                        const int h_sig = int(hh_out) - int(rr);
                        const int w_sig = int(ww_out) - int(ss);
                        bool ok;
                        uint hi, wi;
                        if (stride_2) {
                            ok = (h_sig >= 0) && (w_sig >= 0)
                                 && ((h_sig & 1) == 0) && ((w_sig & 1) == 0);
                            hi = uint(h_sig) >> 1;
                            wi = uint(w_sig) >> 1;
                        } else {
                            ok = (h_sig >= 0) && (w_sig >= 0)
                                 && ((h_sig % int(stride_)) == 0)
                                 && ((w_sig % int(stride_)) == 0);
                            hi = uint(h_sig) / stride_;
                            wi = uint(w_sig) / stride_;
                        }
                        if (ok && hi < H && wi < W) {
                            v = x[((nn * H + hi) * W + wi) * C_in + c];
                        }
                    }
                    Atile[a_row * BK + a_col] = v;
                }
            }

            // Stage B: BK*BN = 16*128 = 2048 elements / 1024 = 2 per thread.
            {
                const uint t0 = tid_in_tg;
                {
                    const uint k_in = t0 / BN;          // 0..15
                    const uint n_in = t0 - k_in * BN;   // 0..127
                    Btile[k_in * BN + n_in] = w[n_in * Kd + (k0 + k_in)];
                }
                const uint t1 = tid_in_tg + 1024u;
                if (t1 < BK * BN) {
                    const uint k_in = t1 / BN;
                    const uint n_in = t1 - k_in * BN;
                    Btile[k_in * BN + n_in] = w[n_in * Kd + (k0 + k_in)];
                }
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            // Compute: TM*TN outer product, BK=16 steps.
            const uint col_base = tx * TN;
            #pragma unroll
            for (uint kk = 0; kk < BK; ++kk) {
                float4 bv = *((threadgroup const float4*)(&Btile[kk * BN + col_base]));
                #pragma unroll
                for (uint i = 0; i < TM; ++i) {
                    float a = Atile[(ty + i * 32u) * BK + kk];
                    acc[i][0] = fma(a, bv.x, acc[i][0]);
                    acc[i][1] = fma(a, bv.y, acc[i][1]);
                    acc[i][2] = fma(a, bv.z, acc[i][2]);
                    acc[i][3] = fma(a, bv.w, acc[i][3]);
                }
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Epilogue: float4 stores.
        const uint col0 = tx * TN;
        for (uint i = 0; i < TM; ++i) {
            if (row_valid_reg[i]) {
                const uint y_base = ((n_idx[i] * H_out + h_out_idx[i]) * W_out + w_out_idx[i]) * C_out;
                float4 out = float4(acc[i][0], acc[i][1], acc[i][2], acc[i][3]);
                *((device float4*)(&y[y_base + col0])) = out;
            }
        }
    }
}

conv_transpose2d_clamp_scale_div.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void conv_transpose2d_clamp_scale_div_f32(
    device const float* x      [[buffer(0)]],
    device const float* w      [[buffer(1)]],
    device const float* b      [[buffer(2)]],
    device       float* y      [[buffer(3)]],
    constant     uint&  N      [[buffer(4)]],
    constant     uint&  C_in   [[buffer(5)]],
    constant     uint&  H      [[buffer(6)]],
    constant     uint&  W      [[buffer(7)]],
    constant     uint&  C_out  [[buffer(8)]],
    constant     uint&  R      [[buffer(9)]],
    constant     uint&  stride [[buffer(10)]],
    constant     float& scale  [[buffer(11)]],
    constant     float& div    [[buffer(12)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H_out = (H - 1) * stride + R;
    const uint W_out = (W - 1) * stride + R;
    const uint total = N * H_out * W_out * C_out;
    const float inv_div = 1.0f / div;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint k = q % C_out; q /= C_out;
        uint w_out = q % W_out; q /= W_out;
        uint h_out = q % H_out; uint n = q / H_out;
        float sum = b[k];
        for (uint r = 0; r < R; ++r) {
            int hi_s = int(h_out) - int(r);
            if (hi_s < 0 || hi_s % int(stride) != 0) continue;
            uint hi = uint(hi_s) / stride;
            if (hi >= H) continue;
            for (uint s = 0; s < R; ++s) {
                int wi_s = int(w_out) - int(s);
                if (wi_s < 0 || wi_s % int(stride) != 0) continue;
                uint wi = uint(wi_s) / stride;
                if (wi >= W) continue;
                for (uint c = 0; c < C_in; ++c)
                    sum += x[((n * H + hi) * W + wi) * C_in + c]
                         * w[((k * R + r) * R + s) * C_in + c];
            }
        }
        sum = clamp(sum, -1.0f, 1.0f) * scale;
        y[idx] = clamp(sum, -1.0f, 1.0f) * inv_div;
    }
}

cosine_similarity.metal_source:
// cosine_similarity: x·y / (|x| * |y|) per row. Single simd_sum reduction with threadgroup memory.
#include <metal_stdlib>
using namespace metal;

kernel void cosine_similarity_f32(
    device const float*  x   [[buffer(0)]],
    device const float*  y   [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   D   [[buffer(3)]],
    uint3 tid               [[thread_position_in_threadgroup]],
    uint3 tgid              [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * D;
    const uint sg = t >> 5;

    float xi = x[off + t];
    float yi = y[off + t];
    float dot_v = xi * yi;
    float sq_x  = xi * xi;
    float sq_y  = yi * yi;

    float dot_sum  = simd_sum(dot_v);
    float sq_x_sum = simd_sum(sq_x);
    float sq_y_sum = simd_sum(sq_y);

    threadgroup float tg_dot[32], tg_sqx[32], tg_sqy[32];
    if ((t & 31) == 0) {
        tg_dot[sg] = dot_sum;
        tg_sqx[sg] = sq_x_sum;
        tg_sqy[sg] = sq_y_sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        float d = tg_dot[t], sx = tg_sqx[t], sy = tg_sqy[t];
        for (uint s = 16; s > 0; s >>= 1) {
            d  += simd_shuffle_down(d,  s);
            sx += simd_shuffle_down(sx, s);
            sy += simd_shuffle_down(sy, s);
        }
        if (t == 0) {
            float eps = 1e-8f;
            out[row] = d / (sqrt(sx) * sqrt(sy) + eps);
        }
    }
}

cross_entropy_loss.metal_source:
// cross_entropy_loss: per-row -sum(y * log_softmax(L))
//                   = lse * sum(y) - sum(y * L)
// where lse = row_max + log(sum_c exp(L_c - row_max))
//
// Fused reductions: pass 1 computes row_max, sum_y, sum_yl simultaneously.
// Pass 2 computes sum_exp.  Then write out[row] = lse*sum_y - sum_yl.
#include <metal_stdlib>
using namespace metal;

kernel void cross_entropy_loss_f32(
    device const float*  L        [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint tid  = tid3.x;
    const uint row  = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;

    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;

    threadgroup float r0[32]; // max
    threadgroup float r1[32]; // sum_y
    threadgroup float r2[32]; // sum_yl
    threadgroup float r3[32]; // sum_exp
    threadgroup float sc[3];  // [row_max, sum_y, sum_yl]

    float lv = lp[tid];
    float yv = yp[tid];

    // ---- pass 1: max, sum(y), sum(y*l) ----
    float mx  = simd_max(lv);
    float sy  = simd_sum(yv);
    float syl = simd_sum(yv * lv);
    if (lane == 0) { r0[sgid] = mx; r1[sgid] = sy; r2[sgid] = syl; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float row_max, sum_y, sum_yl;
    if (sgid == 0) {
        float v0 = r0[lane];
        float v1 = r1[lane];
        float v2 = r2[lane];
        v0 = simd_max(v0);
        v1 = simd_sum(v1);
        v2 = simd_sum(v2);
        if (lane == 0) { sc[0] = v0; sc[1] = v1; sc[2] = v2; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    row_max = sc[0];
    sum_y   = sc[1];
    sum_yl  = sc[2];

    // ---- pass 2: sum(exp(l - row_max)) ----
    float e  = exp(lv - row_max);
    float se = simd_sum(e);
    if (lane == 0) r3[sgid] = se;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sgid == 0) {
        float v = r3[lane];
        v = simd_sum(v);
        if (lane == 0) {
            float lse = row_max + log(v);
            out[row] = lse * sum_y - sum_yl;
        }
    }
}

cumprod.metal_source:
// cumprod: float4-per-thread 2-level prefix product.
// 256 threads/TG (8 simdgroups), each handles 4 contiguous elements via float4 load/store.
#include <metal_stdlib>
using namespace metal;

kernel void cumprod_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;        // 0..7
    const uint sl = t & 31;

    const uint base = row * N + t * 4;
    float4 v = *reinterpret_cast<const device float4*>(&x[base]);

    // Local cumulative product within float4.
    float4 lp;
    lp.x = v.x;
    lp.y = lp.x * v.y;
    lp.z = lp.y * v.z;
    lp.w = lp.z * v.w;

    // simd_prefix_inclusive over float4 totals.
    float local_scan = simd_prefix_inclusive_product(lp.w);

    // Cross-simd: 8 simdgroups in TG.
    threadgroup float tg_totals[8];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float v8 = (sl < 8) ? tg_totals[sl] : 1.0f;
        float pre = simd_prefix_exclusive_product(v8);
        if (sl < 8) tg_totals[sl] = pre;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float thread_excl_in_simd = local_scan / lp.w;
    float thread_offset = tg_totals[sg] * thread_excl_in_simd;

    float4 out;
    out.x = thread_offset * lp.x;
    out.y = thread_offset * lp.y;
    out.z = thread_offset * lp.z;
    out.w = thread_offset * lp.w;

    *reinterpret_cast<device float4*>(&y[base]) = out;
}

cumsum.metal_source:
// cumsum: 2-level prefix scan using hardware simd_prefix_inclusive_sum.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;        // simdgroup index (0..31)
    const uint sl = t & 31;         // lane within simdgroup (0..31)

    float val = x[row * N + t];

    float local_scan = simd_prefix_inclusive_sum(val);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) {
        my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    }
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * N + t] = local_scan + tg_totals[sg];
}

cumsum_exclusive.metal_source:
// cumsum_exclusive: per-row exclusive prefix sum. Two-level scan via simd hardware.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_exclusive_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;
    const uint sl = t & 31;

    float v = x[row * C + t];
    float local_scan = simd_prefix_inclusive_sum(v);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * C + t] = local_scan + tg_totals[sg] - v;
}

cumsum_reverse.metal_source:
// cumsum_reverse: 2-level prefix scan on reversed elements per row.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_reverse_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5, sl = t & 31;
    const uint rev_t = N - 1 - t;

    float val = x[row * N + rev_t];
    float local_scan = simd_prefix_inclusive_sum(val);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * N + rev_t] = local_scan + tg_totals[sg];
}

densenet.metal_source:
// densenet-mini default variant (M2-tuned): Phase B + Phase C use the per-thread
// "compute all C output channels at once" reorder; Phase A keeps the simple
// per-channel mapping which on M2 was faster than the reorder.
#include <metal_stdlib>
using namespace metal;

kernel void densenet_f32(
    device const float* x       [[buffer(0)]],   // (1,16,16,3)
    device const float* W_stem  [[buffer(1)]],   // (12,3,3,3)
    device const float* W_d1    [[buffer(2)]],   // (12,3,3,12)
    device const float* W_d2    [[buffer(3)]],   // (12,3,3,24)
    device const float* W_fc    [[buffer(4)]],   // (36,10)
    device       float* y       [[buffer(5)]],   // (1,10)
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint  simd_lane             [[thread_index_in_simdgroup]],
    uint  simd_gid              [[simdgroup_index_in_threadgroup]])
{
    const uint tid = tid3.x;
    constexpr uint H = 16;
    constexpr uint W = 16;
    constexpr uint HW = H * W;
    constexpr uint C0 = 12;
    constexpr uint C1 = 12;
    constexpr uint Cin2 = 24;
    constexpr uint Cout2 = 12;
    constexpr uint Cfinal = 36;
    constexpr float inv_HW = 1.0f / float(HW);

    threadgroup float tg_h0[HW * C0];
    threadgroup float tg_c1[HW * C1];
    threadgroup float tg_Wd1[12u*3u*3u*12u];
    threadgroup float gap[Cfinal];

    if (tid < Cfinal) gap[tid] = 0.0f;
    for (uint i = tid; i < 12u*3u*3u*12u; i += 256u) {
        tg_Wd1[i] = W_d1[i];
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Phase A: stem conv (3 -> 12) + ReLU — simple per-channel mapping.
    for (uint i = tid; i < HW * C0; i += 256u) {
        uint h = i / (W * C0);
        uint t = i % (W * C0);
        uint w = t / C0;
        uint c = t % C0;
        float s = 0.0f;
        for (uint kh = 0; kh < 3u; ++kh) {
            int hi = int(h) + int(kh) - 1;
            if (hi < 0 || hi >= int(H)) continue;
            for (uint kw = 0; kw < 3u; ++kw) {
                int wi = int(w) + int(kw) - 1;
                if (wi < 0 || wi >= int(W)) continue;
                uint xb = (uint(hi) * W + uint(wi)) * 3u;
                uint wb = ((c * 3u + kh) * 3u + kw) * 3u;
                s += x[xb + 0] * W_stem[wb + 0]
                   + x[xb + 1] * W_stem[wb + 1]
                   + x[xb + 2] * W_stem[wb + 2];
            }
        }
        tg_h0[(h * W + w) * C0 + c] = fmax(s, 0.0f);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Phase B reorder: each thread one (h,w), all 12 output channels at once.
    for (uint p = tid; p < HW; p += 256u) {
        uint h = p / W;
        uint w = p % W;
        float s[C1];
        #pragma clang loop unroll(full)
        for (uint c = 0; c < C1; ++c) s[c] = 0.0f;

        for (uint kh = 0; kh < 3u; ++kh) {
            int hi = int(h) + int(kh) - 1;
            if (hi < 0 || hi >= int(H)) continue;
            for (uint kw = 0; kw < 3u; ++kw) {
                int wi = int(w) + int(kw) - 1;
                if (wi < 0 || wi >= int(W)) continue;
                uint base_sp = (uint(hi) * W + uint(wi));
                threadgroup const float* sh0 = &tg_h0[base_sp * C0];
                float a[C0];
                #pragma clang loop unroll(full)
                for (uint ci = 0; ci < C0; ++ci) a[ci] = sh0[ci];
                #pragma clang loop unroll(full)
                for (uint c = 0; c < C1; ++c) {
                    uint wb = ((c * 3u + kh) * 3u + kw) * C0;
                    float acc = 0.0f;
                    #pragma clang loop unroll(full)
                    for (uint ci = 0; ci < C0; ++ci) {
                        acc += a[ci] * tg_Wd1[wb + ci];
                    }
                    s[c] += acc;
                }
            }
        }
        #pragma clang loop unroll(full)
        for (uint c = 0; c < C1; ++c) {
            tg_c1[(h * W + w) * C1 + c] = fmax(s[c], 0.0f);
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Phase C reorder: per-thread spatial, 12 output channel accumulators.
    threadgroup float reduce_buf[8 * Cout2];
    {
        float partial[Cout2];
        #pragma clang loop unroll(full)
        for (uint c = 0; c < Cout2; ++c) partial[c] = 0.0f;

        for (uint p = tid; p < HW; p += 256u) {
            uint h = p / W;
            uint w = p % W;
            float s[Cout2];
            #pragma clang loop unroll(full)
            for (uint c = 0; c < Cout2; ++c) s[c] = 0.0f;

            for (uint kh = 0; kh < 3u; ++kh) {
                int hi = int(h) + int(kh) - 1;
                if (hi < 0 || hi >= int(H)) continue;
                for (uint kw = 0; kw < 3u; ++kw) {
                    int wi = int(w) + int(kw) - 1;
                    if (wi < 0 || wi >= int(W)) continue;
                    uint base_sp = (uint(hi) * W + uint(wi));
                    threadgroup const float* sh0 = &tg_h0[base_sp * C0];
                    threadgroup const float* sc1 = &tg_c1[base_sp * C1];
                    float a[Cin2];
                    #pragma clang loop unroll(full)
                    for (uint ci = 0; ci < C0; ++ci) a[ci] = sh0[ci];
                    #pragma clang loop unroll(full)
                    for (uint ci = 0; ci < C1; ++ci) a[C0 + ci] = sc1[ci];
                    #pragma clang loop unroll(full)
                    for (uint c = 0; c < Cout2; ++c) {
                        uint wb = ((c * 3u + kh) * 3u + kw) * Cin2;
                        float acc = 0.0f;
                        #pragma clang loop unroll(full)
                        for (uint ci = 0; ci < Cin2; ++ci) {
                            acc += a[ci] * W_d2[wb + ci];
                        }
                        s[c] += acc;
                    }
                }
            }
            #pragma clang loop unroll(full)
            for (uint c = 0; c < Cout2; ++c) partial[c] += fmax(s[c], 0.0f);
        }

        #pragma clang loop unroll(full)
        for (uint c = 0; c < Cout2; ++c) {
            float lane_sum = simd_sum(partial[c]);
            if (simd_lane == 0) reduce_buf[simd_gid * Cout2 + c] = lane_sum;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        if (simd_gid == 0 && simd_lane < Cout2) {
            uint c = simd_lane;
            float tot = 0.0f;
            #pragma clang loop unroll(full)
            for (uint g = 0; g < 8u; ++g) tot += reduce_buf[g * Cout2 + c];
            gap[Cin2 + c] = tot * inv_HW;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    // GAP for channels 0..23.
    {
        for (uint k = 0; k < 3u; ++k) {
            uint cc = simd_gid * 3u + k;
            if (cc < C0 + C1) {
                float ps = 0.0f;
                #pragma clang loop unroll(full)
                for (uint q = 0; q < 8u; ++q) {
                    uint p = simd_lane * 8u + q;
                    if (cc < C0) ps += tg_h0[p * C0 + cc];
                    else         ps += tg_c1[p * C1 + (cc - C0)];
                }
                float tot = simd_sum(ps);
                if (simd_lane == 0) gap[cc] = tot * inv_HW;
            }
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 10u) {
        float s = 0.0f;
        for (uint k = 0; k < Cfinal; ++k) s += gap[k] * W_fc[k * 10u + tid];
        y[tid] = s;
    }
}

depthwise_conv2d.metal_source:
// depthwise_conv2d: NHWC, groups == C. x (N,H,W,C), w (C,R,S,1), y (N,H2,W2,C).
// R=S=3, stride=1 specialization; per-thread one (n,h2,w2,c). Weights cached in registers.
#include <metal_stdlib>
using namespace metal;

kernel void depthwise_conv2d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   R       [[buffer(7)]],
    constant     uint&   S       [[buffer(8)]],
    constant     uint&   stride  [[buffer(9)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - R) / stride + 1;
    const uint W2 = (W - S) / stride + 1;
    const uint HW2C = H2 * W2 * C;
    const uint W2C = W2 * C;
    const uint total = N * HW2C;
    const uint sH = W * C;
    const uint sN = H * sH;

    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint n  = q / HW2C;  q -= n * HW2C;
        uint h2 = q / W2C;   q -= h2 * W2C;
        uint w2 = q / C;
        uint c  = q - w2 * C;

        uint wb = c * 9; // R*S = 9
        float w00 = w[wb + 0]; float w01 = w[wb + 1]; float w02 = w[wb + 2];
        float w10 = w[wb + 3]; float w11 = w[wb + 4]; float w12 = w[wb + 5];
        float w20 = w[wb + 6]; float w21 = w[wb + 7]; float w22 = w[wb + 8];

        uint xb = n * sN + (h2 * stride) * sH + (w2 * stride) * C + c;

        float x00 = x[xb           ]; float x01 = x[xb +     C]; float x02 = x[xb + 2*C];
        float x10 = x[xb + sH      ]; float x11 = x[xb + sH + C]; float x12 = x[xb + sH + 2*C];
        float x20 = x[xb + 2*sH    ]; float x21 = x[xb + 2*sH + C]; float x22 = x[xb + 2*sH + 2*C];

        float sum = x00*w00 + x01*w01 + x02*w02
                  + x10*w10 + x11*w11 + x12*w12
                  + x20*w20 + x21*w21 + x22*w22;

        y[idx] = sum;
    }
}

dot_product.metal_source:
// dot_product: x^T y. Single reduction via simd_sum + cross-simdgroup sum.
#include <metal_stdlib>
using namespace metal;

kernel void dot_product_f32(
    device const float*  x  [[buffer(0)]],
    device const float*  y  [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   N  [[buffer(3)]],
    uint  tid              [[thread_position_in_threadgroup]])
{
    const uint tg_size = 1024;
    float sum = 0.0f;
    for (uint i = tid; i < N; i += tg_size)
        sum += x[i] * y[i];

    float sg_sum = simd_sum(sum);

    threadgroup float tg[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) tg[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sg_sum = tg[tid];
        for (uint s = 16; s > 0; s >>= 1)
            sg_sum += simd_shuffle_down(sg_sum, s);
    }
    if (tid == 0) *out = sg_sum;
}

dropout.metal_source:
// dropout (inverted): y = mask * x * (1/(1-p)). float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void dropout_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  M       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  p       [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    const float scale = 1.0f / (1.0f - p);
    const uint n4 = N >> 2;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 m = *reinterpret_cast<const device float4*>(&M[base]);
        *reinterpret_cast<device float4*>(&Y[base]) = m * x * scale;
    }
}

elu.metal_source:
// elu: x if x>0 else α*(exp(x)-1). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void elu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    constant     float&  alpha     [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 neg = alpha * (exp(min(v, float4(0.0f))) - 1.0f);
        float4 out = select(neg, v, v > 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = out;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = v > 0.0f ? v : alpha * (exp(v) - 1.0f);
    }
}

embedding.metal_source:
// embedding: out[s, d] = table[(uint)indices[s], d]. (S,) × (V, D) → (S, D).
// Indices arrive as f32; we cast to uint and clamp.
#include <metal_stdlib>
using namespace metal;

kernel void embedding_f32(
    device const float*  indices  [[buffer(0)]],
    device const float*  table    [[buffer(1)]],
    device       float*  y        [[buffer(2)]],
    constant     uint&   S        [[buffer(3)]],
    constant     uint&   V        [[buffer(4)]],
    constant     uint&   D        [[buffer(5)]],
    uint tid                     [[thread_position_in_grid]])
{
    const uint total = S * D;
    const uint grid_size = 64 * 1024;
    for (uint i = tid; i < total; i += grid_size) {
        uint s = i / D;
        uint d = i % D;
        uint idx = clamp(uint(indices[s]), 0u, V - 1u);
        y[i] = table[idx * D + d];
    }
}

exp.metal_source:
// exp: float4 grid-stride loop. Memory-bound elementwise.
#include <metal_stdlib>
using namespace metal;

kernel void exp_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        float4 r;
        r.x = fast::exp(v.x);
        r.y = fast::exp(v.y);
        r.z = fast::exp(v.z);
        r.w = fast::exp(v.w);
        *(reinterpret_cast<device float4*>(&y[i * 4])) = r;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = fast::exp(x[i]);
    }
}

frobenius_norm.metal_source:
// frobenius_norm: ||x||_F = sqrt(sum(x*x)). Output (1,). Single TG, N=1M.
// float4 grid-stride loop, simd_sum, cross-simd reduce.
#include <metal_stdlib>
using namespace metal;

kernel void frobenius_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    threadgroup float reduce[32];

    device const float4* x4 = reinterpret_cast<device const float4*>(x);
    const uint N4 = N >> 2;

    float s0 = 0.0f, s1 = 0.0f, s2 = 0.0f, s3 = 0.0f;
    uint i = tid;
    const uint stride4 = TG * 4;
    for (; i + 3*TG < N4; i += stride4) {
        float4 a = x4[i];
        float4 b = x4[i + TG];
        float4 c = x4[i + 2*TG];
        float4 d = x4[i + 3*TG];
        s0 += dot(a, a);
        s1 += dot(b, b);
        s2 += dot(c, c);
        s3 += dot(d, d);
    }
    for (; i < N4; i += TG) {
        float4 v = x4[i];
        s0 += dot(v, v);
    }
    float s = (s0 + s1) + (s2 + s3);
    s = simd_sum(s);
    if ((tid & 31) == 0) reduce[tid >> 5] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        s = reduce[tid];
        s = simd_sum(s);
        if (tid == 0) y[0] = sqrt(s);
    }
}

fused_add_rms_norm.metal_source:
// fused_add_rms_norm: y = (x+r) * rsqrt(mean((x+r)^2) + eps). Per-row.
#include <metal_stdlib>
using namespace metal;

kernel void fused_add_rms_norm_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* xr = X + row * D;
    device const float* rr = R + row * D;
    device       float* yr = Y + row * D;

    threadgroup float reduce[32];

    float sumsq = 0.0f;
    for (uint i = tid; i < D; i += TG) {
        float v = xr[i] + rr[i];
        sumsq += v * v;
    }
    sumsq = simd_sum(sumsq);
    if ((tid & 31) == 0) reduce[tid >> 5] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sumsq = reduce[tid];
        for (uint s = 16; s > 0; s >>= 1) sumsq += simd_shuffle_down(sumsq, s);
        if (tid == 0) reduce[0] = sumsq;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv = rsqrt(reduce[0] / float(D) + eps);
    for (uint i = tid; i < D; i += TG) yr[i] = (xr[i] + rr[i]) * inv;
}

fused_qkv_projection.metal_source:
// fused_qkv_projection: Y = X @ W. (128,512) @ (512,192). N=192=3*64.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;
constant constexpr uint TILES_N = 192 / BN;     // 3
constant constexpr uint TILES_M = 128 / BM;     // 2
constant constexpr uint ACTIVE_TG = TILES_M * TILES_N;  // 6

kernel void fused_qkv_projection_f32(
    device const float* X    [[buffer(0)]],
    device const float* W    [[buffer(1)]],
    device       float* Y    [[buffer(2)]],
    constant     uint&  M    [[buffer(3)]],
    constant     uint&  N    [[buffer(4)]],
    constant     uint&  K    [[buffer(5)]],
    uint tgid_lin            [[threadgroup_position_in_grid]],
    uint sgid                [[simdgroup_index_in_threadgroup]],
    uint lid                 [[thread_index_in_threadgroup]])
{
    if (tgid_lin >= ACTIVE_TG) return;
    const uint tx = tgid_lin % TILES_N;
    const uint ty = tgid_lin / TILES_N;

    threadgroup float As[2][BM * LDA];
    threadgroup float Bs[2][BK * LDB];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;
    const uint c_col0 = tx * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = K / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &Y[(c_row0 + sm * SM + i * 8) * N + (c_col0 + sn * SN + j * 8)],
                            N);
}

gelu.metal_source:
// gelu: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3))).
#include <metal_stdlib>
using namespace metal;

constant constexpr float gelu_k = 0.79788456f;

kernel void gelu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = 0.5f * v * (1.0f + tanh(gelu_k * (v + 0.044715f * v * v * v)));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = 0.5f * v * (1.0f + tanh(gelu_k * (v + 0.044715f * v * v * v)));
    }
}

gelu_linear.metal_source:
// gelu_linear: y = gelu(x @ W). Fused matmul + erf-GELU in store phase.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

static inline float erf_approx(float z) {
    float t = 1.0f / (1.0f + 0.3275911f * fabs(z));
    float y = 1.0f - (((((1.061405429f * t - 1.453152027f) * t)
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f)
              * t * exp(-z * z);
    return copysign(y, z);
}
static inline float4 gelu4(float4 v) {
    const float k = 0.70710678f; // 1/sqrt(2)
    float4 r;
    r.x = 0.5f * v.x * (1.0f + erf_approx(v.x * k));
    r.y = 0.5f * v.y * (1.0f + erf_approx(v.y * k));
    r.z = 0.5f * v.z * (1.0f + erf_approx(v.z * k));
    r.w = 0.5f * v.w * (1.0f + erf_approx(v.w * k));
    return r;
}

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void gelu_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float shared[2 * BM * LDA + 2 * BK * LDB];
    threadgroup float (*As)[BM * LDA] = (threadgroup float (*)[BM * LDA]) &shared[0];
    threadgroup float (*Bs)[BK * LDB] = (threadgroup float (*)[BK * LDB]) &shared[2 * BM * LDA];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    { // Prologue
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint num_k_tiles = K / BK; uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf, k0_nxt = (kt + 1) * BK;
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);
    threadgroup float* Cs = &shared[0];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j], &Cs[(sm*SM + i*8) * BN + sn*SN + j*8], BN);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    #pragma unroll
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
        *reinterpret_cast<device float4*>(&C[(c_row0 + r) * N + (c_col0 + c)]) = gelu4(v);
    }
}

group_norm.metal_source:
// group_norm: normalize per-sample per-group over (CG, H, W) where CG = C/G.
#include <metal_stdlib>
using namespace metal;

kernel void group_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   G       [[buffer(6)]],
    constant     float&  eps     [[buffer(7)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint ng  = tgid.y;     // 0 .. N*G - 1
    const uint n   = ng / G;
    const uint g   = ng % G;
    const uint CG  = C / G;
    const uint block = CG * H * W;
    device const float* base_in  = X + (n * C + g * CG) * H * W;
    device       float* base_out = Y + (n * C + g * CG) * H * W;

    // First pass: compute sum and sumsq using float4 vectorized loads
    float sum = 0.0f, sumsq = 0.0f;
    const uint block4 = block / 4;
    for (uint i = tid; i < block4; i += TG) {
        float4 v = *((device const float4*)&base_in[i * 4]);
        sum   += v.x + v.y + v.z + v.w;
        sumsq += v.x * v.x + v.y * v.y + v.z * v.z + v.w * v.w;
    }
    // Handle remaining elements (0-3)
    for (uint i = block4 * 4 + tid; i < block; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(block);
    float var  = max(tg_q[0] / float(block) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    // Second pass: normalize using float4 vectorized stores
    for (uint i = tid; i < block4; i += TG) {
        float4 v = *((device const float4*)&base_in[i * 4]);
        float4 out;
        out.x = (v.x - mean) * inv;
        out.y = (v.y - mean) * inv;
        out.z = (v.z - mean) * inv;
        out.w = (v.w - mean) * inv;
        *((device float4*)&base_out[i * 4]) = out;
    }
    for (uint i = block4 * 4 + tid; i < block; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

hardsigmoid.metal_source:
// hardsigmoid: clamp(x/6 + 0.5, 0, 1).
#include <metal_stdlib>
using namespace metal;

kernel void hardsigmoid_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = clamp(v / 6.0f + 0.5f, 0.0f, 1.0f);
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = clamp(x[i] / 6.0f + 0.5f, 0.0f, 1.0f);
    }
}

hardswish.metal_source:
// hardswish: x * clamp(x+3, 0, 6) / 6. Float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void hardswish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v * clamp(v + 3.0f, 0.0f, 6.0f) / 6.0f;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        y[i] = x[i] * clamp(x[i] + 3.0f, 0.0f, 6.0f) / 6.0f;
}

hardtanh.metal_source:
// hardtanh: out = clamp(x, -1, 1). float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void hardtanh_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        *reinterpret_cast<device float4*>(&y[i * 4]) = clamp(v, -1.0f, 1.0f);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = clamp(x[i], -1.0f, 1.0f);
    }
}

huber_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

// Memory-bound elementwise. N=1M, grid=64K threads => 16 elements/thread.
// Use float4 vectorized loads/stores: 4 float4 per thread = 16 elements,
// fully utilizing 128B loads and halving instruction count.
kernel void huber_loss_f32(
    device const float*  pred      [[buffer(0)]],
    device const float*  target    [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  delta     [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint N4 = N >> 2;
    device const float4* pred4 = reinterpret_cast<device const float4*>(pred);
    device const float4* tgt4  = reinterpret_cast<device const float4*>(target);
    device       float4* y4    = reinterpret_cast<device       float4*>(y);
    const float half_delta = 0.5f * delta;

    // Branchless: let m = min(|r|, delta). Then loss = 0.5*m^2 + delta*(|r| - m).
    //   if |r| <= delta: m=|r|, second term=0, result = 0.5*r^2.
    //   if |r| > delta:  m=delta, result = 0.5*delta^2 + delta*(|r| - delta).
    for (uint i = tid; i < N4; i += grid_size) {
        float4 r = pred4[i] - tgt4[i];
        float4 a = fabs(r);
        float4 m = fmin(a, delta);
        y4[i] = fma(0.5f * m, m, delta * (a - m));
    }

    // Tail (N not divisible by 4) — ranks past N4*4
    uint base = N4 << 2;
    for (uint i = base + tid; i < N; i += grid_size) {
        float r = pred[i] - target[i];
        float a = fabs(r);
        float m = fmin(a, delta);
        y[i] = fma(0.5f * m, m, delta * (a - m));
    }
}

instance_norm.metal_source:
// instance_norm: normalize per-sample per-channel over (H, W).
#include <metal_stdlib>
using namespace metal;

kernel void instance_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     float&  eps     [[buffer(6)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint nc = tgid.y;
    const uint HW = H * W;
    device const float* base_in  = X + nc * HW;
    device       float* base_out = Y + nc * HW;

    // Use float4 vectorized loads for the reduction pass
    float sum = 0.0f, sumsq = 0.0f;
    const uint vec_HW = HW / 4;
    for (uint i = tid; i < vec_HW; i += TG) {
        float4 v = ((device const float4*)base_in)[i];
        sum   += v.x + v.y + v.z + v.w;
        sumsq += v.x*v.x + v.y*v.y + v.z*v.z + v.w*v.w;
    }
    // Handle remaining elements (HW not divisible by 4)
    for (uint i = vec_HW * 4 + tid; i < HW; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(HW);
    float var  = max(tg_q[0] / float(HW) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    // Use float4 vectorized stores for the normalization pass
    for (uint i = tid; i < vec_HW; i += TG) {
        float4 v = ((device const float4*)base_in)[i];
        ((device float4*)base_out)[i] = (v - mean) * inv;
    }
    for (uint i = vec_HW * 4 + tid; i < HW; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

kl_div_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void kl_div_loss_f32(
    device const float*  log_pred  [[buffer(0)]],
    device const float*  target    [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        float t = fabs(target[i]) + 1e-6f;
        float lp = -fabs(log_pred[i]);
        y[i] = t * (log(t) - lp);
    }
}

l1_norm.metal_source:
// l1_norm: sum(abs(x)) per row. Simdgroup reduction.
#include <metal_stdlib>
using namespace metal;

kernel void l1_norm_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    float val = fabs(x[row * N + t]);
    float sum = simd_sum(val);

    threadgroup float tg_sum[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) tg_sum[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum = tg_sum[t];
        for (uint s = 16; s > 0; s >>= 1)
            sum += simd_shuffle_down(sum, s);
    }
    if (t == 0) y[row] = sum;
}

l2_norm.metal_source:
// l2_norm: sqrt(sum(x^2)) per row. Simdgroup reduction.
#include <metal_stdlib>
using namespace metal;

kernel void l2_norm_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    float val = x[row * N + t];
    float sumsq = simd_sum(val * val);

    threadgroup float tg_sum[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) tg_sum[sg] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sumsq = tg_sum[t];
        for (uint s = 16; s > 0; s >>= 1)
            sumsq += simd_shuffle_down(sumsq, s);
    }
    if (t == 0) y[row] = sqrt(sumsq);
}

layer_norm.metal_source:
// layer_norm: y = (x - mean) * rsqrt(var + eps) per row.
// D=1024, TG=1024 (registry). Single-simdgroup-per-row: only sg 0 (32 lanes)
// works, each lane handles 8 float4 = 32 elements. Cache float4 strips in
// registers across reduction and normalize passes.
//
// This version uses a two-pass approach: first pass computes mean and variance
// using threadgroup memory for reduction, second pass normalizes. This reduces
// register pressure and allows better memory latency hiding.
#include <metal_stdlib>
using namespace metal;

kernel void layer_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   D       [[buffer(2)]],
    constant     float&  eps     [[buffer(3)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid3.x;
    if (t >= 32u) return;

    const uint row = tgid.y;
    device const float4* xr = (device const float4*)(X + row * D);
    device       float4* yr = (device       float4*)(Y + row * D);

    // Each of 32 lanes handles 8 float4s (= 32 floats) -> 1024 floats total.
    float4 v0, v1, v2, v3, v4, v5, v6, v7;
    v0 = xr[0u  * 32u + t];
    v1 = xr[1u  * 32u + t];
    v2 = xr[2u  * 32u + t];
    v3 = xr[3u  * 32u + t];
    v4 = xr[4u  * 32u + t];
    v5 = xr[5u  * 32u + t];
    v6 = xr[6u  * 32u + t];
    v7 = xr[7u  * 32u + t];

    // First pass: compute sum and sumsq
    float4 s4 = ((v0 + v1) + (v2 + v3)) + ((v4 + v5) + (v6 + v7));
    float sum   = (s4.x + s4.y) + (s4.z + s4.w);
    float sumsq = dot(v0, v0) + dot(v1, v1) + dot(v2, v2) + dot(v3, v3)
                + dot(v4, v4) + dot(v5, v5) + dot(v6, v6) + dot(v7, v7);

    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    float invD = 1.0f / float(D);
    float mean = sum * invD;
    float var  = max(sumsq * invD - mean * mean, 0.0f);
    float inv_std = rsqrt(var + eps);

    // Second pass: normalize using the computed statistics
    // Use fma for better precision and potential throughput
    yr[0u  * 32u + t] = fma(v0, inv_std, -mean * inv_std);
    yr[1u  * 32u + t] = fma(v1, inv_std, -mean * inv_std);
    yr[2u  * 32u + t] = fma(v2, inv_std, -mean * inv_std);
    yr[3u  * 32u + t] = fma(v3, inv_std, -mean * inv_std);
    yr[4u  * 32u + t] = fma(v4, inv_std, -mean * inv_std);
    yr[5u  * 32u + t] = fma(v5, inv_std, -mean * inv_std);
    yr[6u  * 32u + t] = fma(v6, inv_std, -mean * inv_std);
    yr[7u  * 32u + t] = fma(v7, inv_std, -mean * inv_std);
}

leaky_relu.metal_source:
// leaky_relu: out = max(x, 0) + slope * min(x, 0). 1024 thr/tg, float4.
#include <metal_stdlib>
using namespace metal;

kernel void leaky_relu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    constant     float&  slope     [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        v = fmax(v, 0.0f) + slope * fmin(v, 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = fmax(v, 0.0f) + slope * fmin(v, 0.0f);
    }
}

linear_bias.metal_source:
// linear_bias: y = x @ W + b. (M,K)@(K,N)+(N,). M=N=K=256.
// Fuses bias-add into the epilogue via threadgroup memory to avoid the
// store-then-reload of Y that the original kernel performed.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;
constant constexpr uint LDC = BN + PAD;
constant constexpr uint TILES_N = 256 / BN;   // 4
constant constexpr uint ACTIVE_TG = TILES_N * (256 / BM);  // 16

kernel void linear_bias_f32(
    device const float* X    [[buffer(0)]],
    device const float* W    [[buffer(1)]],
    device const float* Bias [[buffer(2)]],
    device       float* Y    [[buffer(3)]],
    constant     uint&  M    [[buffer(4)]],
    constant     uint&  N    [[buffer(5)]],
    constant     uint&  K    [[buffer(6)]],
    uint tgid_lin            [[threadgroup_position_in_grid]],
    uint sgid                [[simdgroup_index_in_threadgroup]],
    uint lid                 [[thread_index_in_threadgroup]])
{
    if (tgid_lin >= ACTIVE_TG) return;
    const uint tx = tgid_lin % TILES_N;
    const uint ty = tgid_lin / TILES_N;

    // Union the A/B staging buffers with the C epilogue staging buffer to
    // stay within the 32 KB threadgroup-memory budget. A/B are dead by the
    // time we need C/bias.
    threadgroup float scratch[4736];  // = max(2*BM*LDA + 2*BK*LDB, BM*LDC + BN)
    threadgroup float (*As)[BM * LDA] = reinterpret_cast<threadgroup float (*)[BM * LDA]>(scratch);
    threadgroup float (*Bs)[BK * LDB] = reinterpret_cast<threadgroup float (*)[BK * LDB]>(scratch + 2 * BM * LDA);
    threadgroup float* Cs        = scratch;
    threadgroup float* bias_tile = scratch + BM * LDC;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;
    const uint c_col0 = tx * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = K / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    // Stage the matmul tile into threadgroup memory so we can fuse the
    // bias-add into the final device write (no read-modify-write on Y).
    // Barrier first: the matmul tail above still reads Bs[buf], whose region
    // aliases bias_tile in the unioned scratch. Wait for all simdgroups to
    // finish their tail loads before we clobber that memory.
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (lid < BN)
        bias_tile[lid] = Bias[c_col0 + lid];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &Cs[(sm * SM + i * 8) * LDC + sn * SN + j * 8],
                            LDC);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * LDC + c]);
        float4 b = *reinterpret_cast<threadgroup float4*>(&bias_tile[c]);
        *reinterpret_cast<device float4*>(&Y[(c_row0 + r) * N + c_col0 + c]) = v + b;
    }
}

llama_attention.metal_source:
// llama_attention: GQA + RoPE attention (no KV cache, no LN).
// S=64 D=128 H=4 H_kv=2 D_head=32 (G = H/H_kv = 2)
// One TG of 1024 threads, 16 threads per query row.
#include <metal_stdlib>
using namespace metal;

#define S    64
#define D    128
#define HH   4
#define HKV  2
#define DH   32
#define G    2
#define TG   1024

kernel void llama_attention_f32(
    device const float* x      [[buffer(0)]],
    device const float* W_qkv  [[buffer(1)]],
    device const float* W_o    [[buffer(2)]],
    device       float* y      [[buffer(3)]],
    constant uint& S_   [[buffer(4)]],
    constant uint& D_   [[buffer(5)]],
    constant uint& H_   [[buffer(6)]],
    constant uint& Hkv_ [[buffer(7)]],
    constant float& base [[buffer(8)]],
    uint3 tid [[thread_position_in_threadgroup]])
{
    const uint t = tid.x;
    constexpr uint QKV_W = D + 2u * HKV * DH;   // 256

    threadgroup float Kh[S * DH];
    threadgroup float Vh[S * DH];
    threadgroup float oh[S * DH];

    const float inv_sqrt_dh = rsqrt(float(DH));
    const float two_over_dh = 2.0f / float(DH);

    for (uint kvh = 0; kvh < HKV; ++kvh) {
        // K, V projection (with RoPE on K).
        {
            const uint sr   = t >> 4;
            const uint lane = t & 15;
            const uint off  = sr * D;
            const uint i_pair = lane;
            const uint dh0 = 2 * i_pair;
            const uint dh1 = dh0 + 1;
            const uint colK0 = D + kvh*DH + dh0;
            const uint colK1 = D + kvh*DH + dh1;
            const uint colV0 = D + HKV*DH + kvh*DH + dh0;
            const uint colV1 = D + HKV*DH + kvh*DH + dh1;
            float k0 = 0.f, k1 = 0.f, v0 = 0.f, v1 = 0.f;
            for (uint d = 0; d < D; ++d) {
                float xv = x[off + d];
                k0 += xv * W_qkv[d*QKV_W + colK0];
                k1 += xv * W_qkv[d*QKV_W + colK1];
                v0 += xv * W_qkv[d*QKV_W + colV0];
                v1 += xv * W_qkv[d*QKV_W + colV1];
            }
            float pos = float(sr);
            float omega = precise::pow(base, -two_over_dh * float(i_pair));
            float ang = pos * omega;
            float c = precise::cos(ang), s_ = precise::sin(ang);
            Kh[sr*DH + dh0] = k0 * c - k1 * s_;
            Kh[sr*DH + dh1] = k0 * s_ + k1 * c;
            Vh[sr*DH + dh0] = v0;
            Vh[sr*DH + dh1] = v1;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint h_off = 0; h_off < G; ++h_off) {
            const uint h = kvh * G + h_off;
            {
                const uint sq   = t >> 4;
                const uint lane = t & 15;
                const uint off  = sq * D;
                const uint i_pair = lane;
                const uint dh0 = 2 * i_pair;
                const uint dh1 = dh0 + 1;
                const uint colQ0 = h*DH + dh0;
                const uint colQ1 = h*DH + dh1;
                float q0 = 0.f, q1 = 0.f;
                for (uint d = 0; d < D; ++d) {
                    float xv = x[off + d];
                    q0 += xv * W_qkv[d*QKV_W + colQ0];
                    q1 += xv * W_qkv[d*QKV_W + colQ1];
                }
                float pos = float(sq);
                float omega = precise::pow(base, -two_over_dh * float(i_pair));
                float ang = pos * omega;
                float c = precise::cos(ang), s_ = precise::sin(ang);
                float q0r = q0 * c - q1 * s_;
                float q1r = q0 * s_ + q1 * c;

                float out0 = 0.f, out1 = 0.f;
                float m_run = -INFINITY;
                float l_run = 0.f;
                for (uint kt = 0; kt < S; ++kt) {
                    float ka = Kh[kt*DH + dh0];
                    float kb = Kh[kt*DH + dh1];
                    float partial = q0r * ka + q1r * kb;
                    partial += simd_shuffle_xor(partial, 1);
                    partial += simd_shuffle_xor(partial, 2);
                    partial += simd_shuffle_xor(partial, 4);
                    partial += simd_shuffle_xor(partial, 8);
                    float score = partial * inv_sqrt_dh;
                    float mn = max(m_run, score);
                    float alpha = exp(m_run - mn);
                    float beta  = exp(score - mn);
                    out0 = out0 * alpha + beta * Vh[kt*DH + dh0];
                    out1 = out1 * alpha + beta * Vh[kt*DH + dh1];
                    l_run = l_run * alpha + beta;
                    m_run = mn;
                }
                float inv = 1.0f / l_run;
                oh[sq*DH + dh0] = out0 * inv;
                oh[sq*DH + dh1] = out1 * inv;
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);

            for (uint idx = t; idx < S*D; idx += TG) {
                const uint sr   = idx / D;
                const uint dout = idx % D;
                float acc = 0.f;
                for (uint dh = 0; dh < DH; ++dh) {
                    acc += oh[sr*DH + dh] * W_o[(h*DH + dh)*D + dout];
                }
                if (kvh == 0 && h_off == 0) {
                    y[sr*D + dout] = acc;
                } else {
                    y[sr*D + dout] += acc;
                }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
        }
    }
}

llama_decoder_layer.metal_source:
// llama_decoder_layer (M2) — Fixed attention score computation to avoid simd_shuffle misuse.
// The previous approach used simd_shuffle to broadcast scores per lane, but the logic for
// distributing S=64 scores across 32 lanes was incorrect, causing massive errors.
// Now each thread computes a single score per query position using simd_sum directly.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

#define S    64
#define D    128
#define H    4
#define HKV  2
#define DH   32
#define G    2
#define FF   256
#define TFF  512
#define TG   1024
#define QKV_W (D + 2*HKV*DH)   // 256
#define HEAD_DIM_F4 (DH/4)     // 8

[[max_total_threads_per_threadgroup(1024)]]
kernel void llama_decoder_layer_f32(
    device const float* x       [[buffer(0)]],
    device const float* W_qkv   [[buffer(1)]],
    device const float* W_o     [[buffer(2)]],
    device const float* W_gu    [[buffer(3)]],
    device const float* W_down  [[buffer(4)]],
    device       float* y       [[buffer(5)]],
    constant uint& S_   [[buffer(6)]],
    constant uint& D_   [[buffer(7)]],
    constant uint& H_   [[buffer(8)]],
    constant uint& HKV_ [[buffer(9)]],
    constant uint& FF_  [[buffer(10)]],
    constant float& base [[buffer(11)]],
    constant float& eps  [[buffer(12)]],
    uint t   [[thread_index_in_threadgroup]],
    uint sgid [[simdgroup_index_in_threadgroup]],
    uint lid_in_sg [[thread_index_in_simdgroup]])
{
    threadgroup float act[S * D];  // 8192 floats = 32KB
    const float log_base = fast::log(base);

    {
        uint row = t >> 4;       // 0..63
        uint lane = t & 15u;     // 0..15
        uint xoff = row * D;
        float ss = 0.0f;
        for (uint d = lane; d < D; d += 16) {
            float v = x[xoff + d];
            ss = fma(v, v, ss);
        }
        ss += simd_shuffle_xor(ss, 1);
        ss += simd_shuffle_xor(ss, 2);
        ss += simd_shuffle_xor(ss, 4);
        ss += simd_shuffle_xor(ss, 8);
        float rstd = rsqrt(ss / float(D) + eps);
        for (uint d = lane; d < D; d += 16) {
            act[xoff + d] = x[xoff + d] * rstd;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    {
        const uint sm = sgid >> 2;       // 0..7
        const uint sn = sgid & 3u;
        const uint row0 = sm * 8;

        const uint qcol0 = sn * 64;  // 0..192 step 64

        simdgroup_matrix<float, 8, 8> C0(0.0f), C1(0.0f), C2(0.0f), C3(0.0f);
        simdgroup_matrix<float, 8, 8> C4(0.0f), C5(0.0f), C6(0.0f), C7(0.0f);
        for (uint kk = 0; kk < 16; ++kk) {
            simdgroup_matrix<float, 8, 8> A_blk;
            simdgroup_load(A_blk, &act[row0 * D + kk*8], D);
            {
                simdgroup_matrix<float, 8, 8> B0, B1, B2, B3;
                simdgroup_load(B0, &W_qkv[(kk*8) * QKV_W + qcol0 + 0],  QKV_W);
                simdgroup_load(B1, &W_qkv[(kk*8) * QKV_W + qcol0 + 8],  QKV_W);
                simdgroup_load(B2, &W_qkv[(kk*8) * QKV_W + qcol0 + 16], QKV_W);
                simdgroup_load(B3, &W_qkv[(kk*8) * QKV_W + qcol0 + 24], QKV_W);
                simdgroup_multiply_accumulate(C0, A_blk, B0, C0);
                simdgroup_multiply_accumulate(C1, A_blk, B1, C1);
                simdgroup_multiply_accumulate(C2, A_blk, B2, C2);
                simdgroup_multiply_accumulate(C3, A_blk, B3, C3);
            }
            {
                simdgroup_matrix<float, 8, 8> B0, B1, B2, B3;
                simdgroup_load(B0, &W_qkv[(kk*8) * QKV_W + qcol0 + 32], QKV_W);
                simdgroup_load(B1, &W_qkv[(kk*8) * QKV_W + qcol0 + 40], QKV_W);
                simdgroup_load(B2, &W_qkv[(kk*8) * QKV_W + qcol0 + 48], QKV_W);
                simdgroup_load(B3, &W_qkv[(kk*8) * QKV_W + qcol0 + 56], QKV_W);
                simdgroup_multiply_accumulate(C4, A_blk, B0, C4);
                simdgroup_multiply_accumulate(C5, A_blk, B1, C5);
                simdgroup_multiply_accumulate(C6, A_blk, B2, C6);
                simdgroup_multiply_accumulate(C7, A_blk, B3, C7);
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        if (sn < 2u) {
            uint dst_col = sn * 64;
            simdgroup_store(C0, &y[row0 * D + dst_col + 0],  D);
            simdgroup_store(C1, &y[row0 * D + dst_col + 8],  D);
            simdgroup_store(C2, &y[row0 * D + dst_col + 16], D);
            simdgroup_store(C3, &y[row0 * D + dst_col + 24], D);
            simdgroup_store(C4, &y[row0 * D + dst_col + 32], D);
            simdgroup_store(C5, &y[row0 * D + dst_col + 40], D);
            simdgroup_store(C6, &y[row0 * D + dst_col + 48], D);
            simdgroup_store(C7, &y[row0 * D + dst_col + 56], D);
        } else {
            uint dst_col = (sn - 2u) * 64;
            simdgroup_store(C0, &act[row0 * 128 + dst_col + 0],  128);
            simdgroup_store(C1, &act[row0 * 128 + dst_col + 8],  128);
            simdgroup_store(C2, &act[row0 * 128 + dst_col + 16], 128);
            simdgroup_store(C3, &act[row0 * 128 + dst_col + 24], 128);
            simdgroup_store(C4, &act[row0 * 128 + dst_col + 32], 128);
            simdgroup_store(C5, &act[row0 * 128 + dst_col + 40], 128);
            simdgroup_store(C6, &act[row0 * 128 + dst_col + 48], 128);
            simdgroup_store(C7, &act[row0 * 128 + dst_col + 56], 128);
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // RoPE K and Q
    {
        for (uint i = 0; i < 2; ++i) {
            uint pair = t * 2 + i;
            uint s   = pair / (HKV * (DH/2));
            uint rem = pair - s * (HKV * (DH/2));
            uint kv  = rem / (DH/2);
            uint ii  = rem - kv * (DH/2);
            uint col0 = kv * DH + 2u*ii;
            uint col1 = col0 + 1u;
            float k0 = act[s * 128 + col0];
            float k1 = act[s * 128 + col1];
            float omega = fast::exp(-(2.0f * float(ii) / float(DH)) * log_base);
            float ang = float(s) * omega;
            float cv = fast::cos(ang);
            float sv = fast::sin(ang);
            act[s * 128 + col0] = k0 * cv - k1 * sv;
            act[s * 128 + col1] = k0 * sv + k1 * cv;
        }
        for (uint i = 0; i < 4; ++i) {
            uint pair = t * 4 + i;
            uint s   = pair / (H * (DH/2));
            uint rem = pair - s * (H * (DH/2));
            uint hh  = rem / (DH/2);
            uint ii  = rem - hh * (DH/2);
            uint col0 = hh * DH + 2u*ii;
            uint col1 = col0 + 1u;
            float q0 = y[s * D + col0];
            float q1 = y[s * D + col1];
            float omega = fast::exp(-(2.0f * float(ii) / float(DH)) * log_base);
            float ang = float(s) * omega;
            float cv = fast::cos(ang);
            float sv = fast::sin(ang);
            y[s * D + col0] = q0 * cv - q1 * sv;
            y[s * D + col1] = q0 * sv + q1 * cv;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Attention: each thread handles one query position and one key-value pair
    // to avoid simd_shuffle broadcasting errors. We iterate over all S keys
    // and accumulate the softmax-weighted value directly.
    {
        const uint sm_a = sgid >> 2;   // 0..7
        const uint sn_a = sgid & 3u;   // 0..3 (head)
        const uint row0 = sm_a * 8;
        const uint head = sn_a;
        const uint kv = head / G;      // 0 or 1

        const float inv_sqrt_dh = rsqrt(float(DH));
        float attn_local[8];

        for (uint r = 0; r < 8; ++r) {
            uint sq = row0 + r;
            float q_lane = y[sq * D + head * DH + lid_in_sg];

            // Compute all S=64 scores for this query position
            float scores[64];
            for (uint kt = 0; kt < S; ++kt) {
                float kv_val = act[kt * 128 + kv * DH + lid_in_sg];
                float prod = q_lane * kv_val;
                // simd_sum across all 32 lanes gives the full dot product
                float dot = simd_sum(prod) * inv_sqrt_dh;
                scores[kt] = dot;
            }

            // Softmax: find max, compute exp, sum
            float m = -INFINITY;
            for (uint kt = 0; kt < S; ++kt) {
                m = max(m, scores[kt]);
            }
            float ssum = 0.0f;
            for (uint kt = 0; kt < S; ++kt) {
                ssum += fast::exp(scores[kt] - m);
            }
            float inv = 1.0f / ssum;
            float ao = 0.0f;
            for (uint kt = 0; kt < S; ++kt) {
                float p = fast::exp(scores[kt] - m) * inv;
                float vval = act[kt * 128 + 64u + kv * DH + lid_in_sg];
                ao = fma(p, vval, ao);
            }
            attn_local[r] = ao;
        }

        threadgroup_barrier(mem_flags::mem_threadgroup);

        for (uint r = 0; r < 8; ++r) {
            act[(row0 + r) * D + head * DH + lid_in_sg] = attn_local[r];
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Output projection
    {
        const uint sm_a = sgid >> 2;
        const uint sn_a = sgid & 3u;
        const uint row0 = sm_a * 8;
        const uint col0 = sn_a * 32;

        simdgroup_matrix<float, 8, 8> C0(0.0f), C1(0.0f), C2(0.0f), C3(0.0f);

        for (uint kc = 0; kc < D; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk;
            simdgroup_matrix<float, 8, 8> B0, B1, B2, B3;
            simdgroup_load(A_blk, &act[row0 * D + kc], D);
            simdgroup_load(B0, &W_o[kc * D + col0 + 0],  D);
            simdgroup_load(B1, &W_o[kc * D + col0 + 8],  D);
            simdgroup_load(B2, &W_o[kc * D + col0 + 16], D);
            simdgroup_load(B3, &W_o[kc * D + col0 + 24], D);
            simdgroup_multiply_accumulate(C0, A_blk, B0, C0);
            simdgroup_multiply_accumulate(C1, A_blk, B1, C1);
            simdgroup_multiply_accumulate(C2, A_blk, B2, C2);
            simdgroup_multiply_accumulate(C3, A_blk, B3, C3);
        }
        simdgroup_store(C0, &y[row0 * D + col0 + 0],  D);
        simdgroup_store(C1, &y[row0 * D + col0 + 8],  D);
        simdgroup_store(C2, &y[row0 * D + col0 + 16], D);
        simdgroup_store(C3, &y[row0 * D + col0 + 24], D);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float ffn_acc[8];
    {
        for (uint i = 0; i < 8; ++i) {
            uint cell = t * 8 + i;
            float v = y[cell] + x[cell];
            ffn_acc[i] = v;
            act[cell] = v;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Second RMSNorm
    {
        uint row = t >> 4;
        uint lane = t & 15u;
        uint off = row * D;
        float ss = 0.0f;
        for (uint d = lane; d < D; d += 16) {
            float v = act[off + d];
            ss = fma(v, v, ss);
        }
        ss += simd_shuffle_xor(ss, 1);
        ss += simd_shuffle_xor(ss, 2);
        ss += simd_shuffle_xor(ss, 4);
        ss += simd_shuffle_xor(ss, 8);
        float rstd = rsqrt(ss / float(D) + eps);
        for (uint d = lane; d < D; d += 16) {
            act[off + d] *= rstd;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint FFC = 64;
    const uint NCHUNKS = FF / FFC;  // 4

    simdgroup_matrix<float, 8, 8> Cff0(0.0f), Cff1(0.0f), Cff2(0.0f), Cff3(0.0f);

    const uint sm_p = sgid >> 2;
    const uint sn_p = sgid & 3u;
    const uint row0_p = sm_p * 8;
    const uint col0_p = sn_p * 32;

    for (uint cc = 0; cc < NCHUNKS; ++cc) {
        const uint fc = cc * FFC;

        {
            const uint row0 = row0_p;
            const uint col0 = col0_p;
            simdgroup_matrix<float, 8, 8> C0(0.0f), C1(0.0f), C2(0.0f), C3(0.0f);
            uint w_col_base;
            if (col0 < 64u) w_col_base = fc + col0;
            else            w_col_base = FF + fc + (col0 - 64u);

            for (uint kc = 0; kc < D; kc += 8) {
                simdgroup_matrix<float, 8, 8> A_blk;
                simdgroup_matrix<float, 8, 8> B0, B1, B2, B3;
                simdgroup_load(A_blk, &act[row0 * D + kc], D);
                simdgroup_load(B0, &W_gu[kc * TFF + w_col_base + 0],  TFF);
                simdgroup_load(B1, &W_gu[kc * TFF + w_col_base + 8],  TFF);
                simdgroup_load(B2, &W_gu[kc * TFF + w_col_base + 16], TFF);
                simdgroup_load(B3, &W_gu[kc * TFF + w_col_base + 24], TFF);
                simdgroup_multiply_accumulate(C0, A_blk, B0, C0);
                simdgroup_multiply_accumulate(C1, A_blk, B1, C1);
                simdgroup_multiply_accumulate(C2, A_blk, B2, C2);
                simdgroup_multiply_accumulate(C3, A_blk, B3, C3);
            }
            simdgroup_store(C0, &y[row0 * 128 + col0 + 0],  128);
            simdgroup_store(C1, &y[row0 * 128 + col0 + 8],  128);
            simdgroup_store(C2, &y[row0 * 128 + col0 + 16], 128);
            simdgroup_store(C3, &y[row0 * 128 + col0 + 24], 128);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            for (uint i = 0; i < 4; ++i) {
                uint cell = t * 4 + i;
                uint s = cell >> 6;
                uint fb = cell & 63u;
                float g = y[s * 128 + fb];
                float u = y[s * 128 + 64 + fb];
                float sg = g / (1.0f + fast::exp(-g));
                y[s * 128 + fb] = sg * u;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            const uint row0 = row0_p;
            const uint col0 = col0_p;
            for (uint kc = 0; kc < FFC; kc += 8) {
                simdgroup_matrix<float, 8, 8> A_blk;
                simdgroup_matrix<float, 8, 8> B0, B1, B2, B3;
                simdgroup_load(A_blk, &y[row0 * 128 + kc], 128);
                simdgroup_load(B0, &W_down[(fc + kc) * D + col0 + 0],  D);
                simdgroup_load(B1, &W_down[(fc + kc) * D + col0 + 8],  D);
                simdgroup_load(B2, &W_down[(fc + kc) * D + col0 + 16], D);
                simdgroup_load(B3, &W_down[(fc + kc) * D + col0 + 24], D);
                simdgroup_multiply_accumulate(Cff0, A_blk, B0, Cff0);
                simdgroup_multiply_accumulate(Cff1, A_blk, B1, Cff1);
                simdgroup_multiply_accumulate(Cff2, A_blk, B2, Cff2);
                simdgroup_multiply_accumulate(Cff3, A_blk, B3, Cff3);
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    {
        simdgroup_store(Cff0, &y[row0_p * D + col0_p + 0],  D);
        simdgroup_store(Cff1, &y[row0_p * D + col0_p + 8],  D);
        simdgroup_store(Cff2, &y[row0_p * D + col0_p + 16], D);
        simdgroup_store(Cff3, &y[row0_p * D + col0_p + 24], D);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    {
        for (uint i = 0; i < 8; ++i) {
            y[t * 8 + i] += ffn_acc[i];
        }
    }
}

log.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void log_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    // float4 vectorized + fast::log; N=262144 divisible by 4.
    const uint N4 = N >> 2;
    device const float4* x4 = reinterpret_cast<device const float4*>(x);
    device       float4* y4 = reinterpret_cast<device       float4*>(y);
    for (uint i = tid; i < N4; i += grid_size) {
        float4 v = fabs(x4[i]) + float4(1e-30f);
        y4[i] = float4(fast::log(v.x), fast::log(v.y), fast::log(v.z), fast::log(v.w));
    }
}

log_softmax.metal_source:
// log_softmax: y = x - logsumexp(x). One TG per row. C == TG == 1024.
// 32 simdgroups; two-stage reduce via threadgroup scratch.
#include <metal_stdlib>
using namespace metal;

kernel void log_softmax_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    const uint lane = tid & 31u;
    const uint sg = tid >> 5;
    device const float* xr = X + row * C;
    device       float* yr = Y + row * C;

    threadgroup float scratch_max[32];
    threadgroup float scratch_sum[32];

    float v = xr[tid];

    // Row max
    float mx = simd_max(v);
    if (lane == 0) scratch_max[sg] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = simd_max(scratch_max[lane]);

    // Row sum of exp (separate scratch -> no barrier needed between writes)
    float e = fast::exp(v - row_max);
    float sum = simd_sum(e);
    if (lane == 0) scratch_sum[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_sum = simd_sum(scratch_sum[lane]);

    float lse = row_max + fast::log(row_sum);
    yr[tid] = v - lse;
}

log_softmax_cross_entropy.metal_source:
// log_softmax_cross_entropy: fused log_softmax + NLL. Output (N,).
// Optimization: combine the per-row sum_exp, sum(yv), sum(yv*lv) into a
// single reduction pass after computing row_max. Then
//     loss = lse * sum_yv - sum_yv_lv,
// where lse = row_max + log(sum_exp). This removes one whole reduction
// round trip vs. computing nll = yv*(lse - lv) and reducing it separately.
//
// Disjoint scratch slots per reduction phase to avoid any inter-phase
// races in the cross-simdgroup step.
#include <metal_stdlib>
using namespace metal;

kernel void log_softmax_cross_entropy_f32(
    device const float*  L        [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint tid  = tid3.x;
    const uint row  = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;
    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;

    // Disjoint scratch slots for each reduction to make the cross-simdgroup
    // step race-free without needing barriers to "clear" slots.
    threadgroup float red_max[32];
    threadgroup float red_e  [32];
    threadgroup float red_y  [32];
    threadgroup float red_yl [32];
    threadgroup float row_max_s;
    threadgroup float lse_s;

    float lv = lp[tid];
    float yv = yp[tid];

    // ---- Phase A: row_max ----
    float mx = simd_max(lv);
    if (lane == 0) red_max[sgid] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float v = simd_max(red_max[lane]);
        if (lane == 0) row_max_s = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = row_max_s;

    // ---- Phase B: in parallel sum(exp(lv-max)), sum(yv), sum(yv*lv) ----
    float e   = fast::exp(lv - row_max);
    float yvl = yv * lv;

    float s_e  = simd_sum(e);
    float s_y  = simd_sum(yv);
    float s_yl = simd_sum(yvl);
    if (lane == 0) {
        red_e [sgid] = s_e;
        red_y [sgid] = s_y;
        red_yl[sgid] = s_yl;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float ve  = simd_sum(red_e [lane]);
        float vy  = simd_sum(red_y [lane]);
        float vyl = simd_sum(red_yl[lane]);
        if (lane == 0) {
            float lse = row_max + fast::log(ve);
            lse_s = lse;
            out[row] = lse * vy - vyl;
        }
    }
    (void)lse_s; // suppress unused warning; not read by other threads
}

logsigmoid.metal_source:
// logsigmoid: numerically stable log(sigmoid(x)).
#include <metal_stdlib>
using namespace metal;

inline float logsigmoid_scalar(float v) {
    if (v > 0.0f) {
        return -log(1.0f + exp(-v));
    } else {
        return v - log(1.0f + exp(v));
    }
}

kernel void logsigmoid_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = float4(
            logsigmoid_scalar(v.x),
            logsigmoid_scalar(v.y),
            logsigmoid_scalar(v.z),
            logsigmoid_scalar(v.w));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = logsigmoid_scalar(x[i]);
    }
}

logsumexp.metal_source:
// logsumexp M2 variant: per-row log(sum(exp(x - max))) + max.
// Strategy: single simdgroup (32 threads) per row, C=1024 per row.
// Each lane owns 32 contiguous elements loaded via float4 (8 vec loads).
// Online single-pass logsumexp combines max + sum: maintain (m, s) such that
// s = sum(exp(x_i - m)). When merging, the larger m wins and the other side
// is rescaled by exp(delta). Final result = m + log(s). One pass over memory.
#include <metal_stdlib>
using namespace metal;

constant constexpr uint TG_SIZE      = 32u;
constant constexpr uint C_PER_LANE   = 32u;   // 1024 / 32
constant constexpr uint VEC_PER_LANE = 8u;    // 32 / 4

kernel void logsumexp_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]],
    uint  simd_lane             [[thread_index_in_simdgroup]])
{
    (void)C;
    const uint tid = tid3.x;
    if (tid >= TG_SIZE) return;
    const uint row = tgid.y;

    device const float4* xr4 = (device const float4*)(x + row * 1024u);
    const uint base_vec = simd_lane * VEC_PER_LANE;

    // Local online (m, s): start with m = first elem, s = 1.
    float4 q0 = xr4[base_vec + 0u];
    float lm = fmax(fmax(q0.x, q0.y), fmax(q0.z, q0.w));
    float ls = (fast::exp(q0.x - lm) + fast::exp(q0.y - lm))
             + (fast::exp(q0.z - lm) + fast::exp(q0.w - lm));

    #pragma unroll
    for (uint j = 1u; j < VEC_PER_LANE; ++j) {
        float4 q = xr4[base_vec + j];
        float nm = fmax(fmax(q.x, q.y), fmax(q.z, q.w));
        float ns = (fast::exp(q.x - nm) + fast::exp(q.y - nm))
                 + (fast::exp(q.z - nm) + fast::exp(q.w - nm));
        // Merge (lm, ls) and (nm, ns).
        float m = fmax(lm, nm);
        ls = ls * fast::exp(lm - m) + ns * fast::exp(nm - m);
        lm = m;
    }

    // Cross-lane reduction via simdgroup shuffles, online merge.
    #pragma unroll
    for (uint off = 16u; off > 0u; off >>= 1) {
        float om = simd_shuffle_xor(lm, off);
        float os = simd_shuffle_xor(ls, off);
        float m  = fmax(lm, om);
        ls = ls * fast::exp(lm - m) + os * fast::exp(om - m);
        lm = m;
    }

    if (simd_lane == 0u) {
        y[row] = lm + fast::log(ls);
    }
}

manhattan_similarity.metal_source:
// manhattan_similarity: L1 distance per row. simd_sum(|x - y|).
#include <metal_stdlib>
using namespace metal;

kernel void manhattan_similarity_f32(
    device const float*  x   [[buffer(0)]],
    device const float*  y   [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   D   [[buffer(3)]],
    uint3 tid               [[thread_position_in_threadgroup]],
    uint3 tgid              [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * D;
    const uint sg = t >> 5;
    const uint lane = t & 31;

    float sum = simd_sum(fabs(x[off + t] - y[off + t]));

    threadgroup float tg[32];
    if (lane == 0) tg[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float v = tg[lane];
        v = simd_sum(v);
        if (lane == 0) out[row] = v;
    }
}

masked_cumsum.metal_source:
// masked_cumsum: per-row cumsum(x * mask). Two-level scan.
#include <metal_stdlib>
using namespace metal;

kernel void masked_cumsum_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  m       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;
    const uint sl = t & 31;

    float v = x[row * C + t] * m[row * C + t];
    float local_scan = simd_prefix_inclusive_sum(v);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * C + t] = local_scan + tg_totals[sg];
}

masked_softmax.metal_source:
// masked_softmax: y = softmax(x + mask). Per-row. Assumes C == TG = 1024.
#include <metal_stdlib>
using namespace metal;

kernel void masked_softmax_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  M       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid3.x;
    const uint row = tgid.y;
    const uint off = row * C;
    const uint lane = t & 31u;
    const uint sg = t >> 5;

    threadgroup float tg_buf[32];

    float val = X[off + t] + M[off + t];

    float m = simd_max(val);
    if (lane == 0) tg_buf[sg] = m;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float rmax = simd_max(tg_buf[lane]);  // every simdgroup computes; we'll broadcast via tg_buf

    float ev = fast::exp(val - rmax);
    float s = simd_sum(ev);
    threadgroup_barrier(mem_flags::mem_threadgroup);  // ensure tg_buf reads done
    if (lane == 0) tg_buf[sg] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float rsum = simd_sum(tg_buf[lane]);

    Y[off + t] = ev * (1.0f / rsum);
}

matmul_gelu_softmax.metal_source:
// matmul_gelu_softmax: y = softmax(GELU(x @ w), axis=-1)
// x (256,256), w (256,256), output (256,256). Grid (256,256,1) TG (256,1,1).
// BM=16, BN=256, BK=8. 16 TGs across 10 M4 cores. Double-buffered B.
//
// 8 simdgroups (256 threads). SIMDS_M=2, SIMDS_N=4 (SM=8, SN=64). MMA_M=1, MMA_N=8.
// Softmax: 16 threads/row, simd_shuffle_xor stride 1..8 inside a 16-lane half.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 16;
constant constexpr uint BN = 256;
constant constexpr uint BK = 16;
constant constexpr uint LDA = BK;
constant constexpr uint LDB = BN;
constant constexpr uint LDC = BN;

constant constexpr uint SIMDS_M = 2;
constant constexpr uint SIMDS_N = 4;
constant constexpr uint SM = BM / SIMDS_M;  // 8
constant constexpr uint SN = BN / SIMDS_N;  // 64
constant constexpr uint MMA_N = SN / 8;     // 8

kernel void matmul_gelu_softmax_f32(
    device const float* X [[buffer(0)]],
    device const float* W [[buffer(1)]],
    device       float* Y [[buffer(2)]],
    constant     uint&  M [[buffer(3)]],
    constant     uint&  N [[buffer(4)]],
    constant     uint&  K [[buffer(5)]],
    uint3 tgid            [[threadgroup_position_in_grid]],
    uint  sgid            [[simdgroup_index_in_threadgroup]],
    uint  lid             [[thread_index_in_threadgroup]])
{
    const uint ty = tgid.y;
    if (ty >= 16) return;

    threadgroup float As[BM * LDA];        // 16*16*4 = 1024 B
    // Bs (BK*LDB=16*256=16384 B) and Cs (BM*LDC=16*256=16384 B) overlay the
    // same TG buffer: Bs lifetime ends before Cs begins (after MMA finishes).
    threadgroup float shared_bc[BM * LDC]; // 16384 B
    threadgroup float* Bs = shared_bc;     // alias during matmul
    threadgroup float* Cs = shared_bc;     // alias after matmul

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_N];
    #pragma unroll
    for (uint j = 0; j < MMA_N; ++j)
        C_acc[j] = simdgroup_matrix<float, 8, 8>(0.0f);

    const uint num_k_tiles = K / BK;       // 32

    for (uint kt = 0; kt < num_k_tiles; ++kt) {
        const uint k0 = kt * BK;
        // A: 16 rows × 16 cols = 256 floats = 64 float4 → 64 threads.
        if (lid < 64) {
            uint ar = lid >> 2;
            uint ac4 = lid & 3;
            *reinterpret_cast<threadgroup float4*>(&As[ar * LDA + ac4 * 4]) =
                *reinterpret_cast<const device float4*>(&X[(c_row0 + ar) * K + k0 + ac4 * 4]);
        }
        // B: 16 rows × 256 cols = 1024 float4 → 4 per thread.
        #pragma unroll
        for (uint q = 0; q < 4; ++q) {
            uint idx = q * 256 + lid;
            uint br = idx / 64;
            uint bc4 = idx % 64;
            *reinterpret_cast<threadgroup float4*>(&Bs[br * LDB + bc4 * 4]) =
                *reinterpret_cast<const device float4*>(&W[(k0 + br) * N + bc4 * 4]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk, B_blk[MMA_N];
            simdgroup_load(A_blk, &As[(sm * SM) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[j], A_blk, B_blk[j], C_acc[j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    #pragma unroll
    for (uint j = 0; j < MMA_N; ++j)
        simdgroup_store(C_acc[j], &Cs[(sm * SM) * LDC + sn * SN + j * 8], LDC);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ---- Softmax phase (same as before)
    const uint r = lid >> 4;
    const uint lane16 = lid & 15;
    const uint col_base = lane16 * 16;

    const float k_inv_sqrt2 = 0.70710678118654752f;
    float vals[16];
    float local_max = -INFINITY;

    threadgroup const float* Crow = &Cs[r * LDC + col_base];
    #pragma unroll
    for (uint t = 0; t < 16; t += 4) {
        float4 v = *reinterpret_cast<threadgroup const float4*>(Crow + t);
        float ss[4] = { v.x, v.y, v.z, v.w };
        #pragma unroll
        for (uint u = 0; u < 4; ++u) {
            float s = ss[u];
            float z = s * k_inv_sqrt2;
            float at = 1.0f / (1.0f + 0.3275911f * fabs(z));
            float yp = 1.0f - (((((1.061405429f * at - 1.453152027f) * at)
                          + 1.421413741f) * at - 0.284496736f) * at + 0.254829592f) * at * fast::exp(-z * z);
            float erfz = copysign(yp, z);
            float gv = 0.5f * s * (1.0f + erfz);
            vals[t + u] = gv;
            local_max = fmax(local_max, gv);
        }
    }
    float rmax = local_max;
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 1));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 2));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 4));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 8));

    float local_sum = 0.0f;
    #pragma unroll
    for (uint u = 0; u < 16; ++u) {
        float e = fast::exp(vals[u] - rmax);
        vals[u] = e;
        local_sum += e;
    }
    float rsum = local_sum;
    rsum += simd_shuffle_xor(rsum, 1);
    rsum += simd_shuffle_xor(rsum, 2);
    rsum += simd_shuffle_xor(rsum, 4);
    rsum += simd_shuffle_xor(rsum, 8);
    float inv = 1.0f / rsum;

    device float* Yrow = &Y[(c_row0 + r) * N + col_base];
    #pragma unroll
    for (uint t = 0; t < 16; t += 4) {
        float4 o = { vals[t]*inv, vals[t+1]*inv, vals[t+2]*inv, vals[t+3]*inv };
        *reinterpret_cast<device float4*>(Yrow + t) = o;
    }
}

matmul_sub_mul_relu.metal_source:
// matmul_sub_mul_relu: y = ReLU((x @ w - sub_val) * mul_val).
// 64x64 MMA tile, BK=16, 256 thr/tg, double-buffered, padded.
// Grid 65536x1x1 → 256 TGs; only 16 active (4x4 tile grid).
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;
constant constexpr uint TILES_N = 256 / BN;
constant constexpr uint ACTIVE_TG = TILES_N * (256 / BM);

kernel void matmul_sub_mul_relu_f32(
    device const float* X       [[buffer(0)]],
    device const float* W       [[buffer(1)]],
    device       float* Y       [[buffer(2)]],
    constant     uint&  M       [[buffer(3)]],
    constant     uint&  N       [[buffer(4)]],
    constant     uint&  K       [[buffer(5)]],
    constant     float& sub_val [[buffer(6)]],
    constant     float& mul_val [[buffer(7)]],
    uint tgid_lin               [[threadgroup_position_in_grid]],
    uint sgid                   [[simdgroup_index_in_threadgroup]],
    uint lid                    [[thread_index_in_threadgroup]],
    uint lane                   [[thread_index_in_simdgroup]])
{
    if (tgid_lin >= ACTIVE_TG) return;
    const uint tx = tgid_lin % TILES_N;
    const uint ty = tgid_lin / TILES_N;

    // Shared scratch: holds As[2] + Bs[2] during matmul (4736 floats),
    // reused as Cs (BM*BN = 4096 floats) for fused epilogue.
    constexpr uint AS_SZ = 2 * BM * LDA;        // 2560
    constexpr uint BS_SZ = 2 * BK * LDB;        // 2176
    constexpr uint CS_SZ = BM * BN;             // 4096
    constexpr uint SCRATCH = (AS_SZ + BS_SZ > CS_SZ) ? (AS_SZ + BS_SZ) : CS_SZ;
    threadgroup float scratch[SCRATCH];
    threadgroup float (*As)[BM * LDA] = reinterpret_cast<threadgroup float(*)[BM * LDA]>(&scratch[0]);
    threadgroup float (*Bs)[BK * LDB] = reinterpret_cast<threadgroup float(*)[BK * LDB]>(&scratch[AS_SZ]);
    threadgroup float* Cs = &scratch[0];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;
    const uint c_col0 = tx * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = K / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    // Need a barrier before reusing scratch as Cs (matmul read As/Bs from it).
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Store accumulators into shared scratch (Cs), then apply fused
    // epilogue (sub→mul→ReLU) with vectorized device writes.
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &Cs[(sm * SM + i * 8) * BN + (sn * SN + j * 8)],
                            BN);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
        float4 out = (v - sub_val) * mul_val;
        out = fmax(out, float4(0.0f));
        *reinterpret_cast<device float4*>(&Y[(c_row0 + r) * N + c_col0 + c]) = out;
    }
}

matrix_add.metal_source:
// matrix_add: C = A + B. Float4 grid-stride, 4-way unrolled for ILP.
#include <metal_stdlib>
using namespace metal;

kernel void matrix_add_f32(
    device const float*  A         [[buffer(0)]],
    device const float*  B         [[buffer(1)]],
    device       float*  C         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]],
    uint  grid_size               [[threads_per_grid]])
{
    const device float4* A4 = reinterpret_cast<const device float4*>(A);
    const device float4* B4 = reinterpret_cast<const device float4*>(B);
    device       float4* C4 = reinterpret_cast<device float4*>(C);
    const uint n4 = N >> 2;
    const uint gs = grid_size;

    // With N=1M, n4=256K, gs=64K -> 4 iters per thread. Issue loads then stores.
    uint i0 = tid;
    uint i1 = i0 + gs;
    uint i2 = i1 + gs;
    uint i3 = i2 + gs;
    if (i3 < n4) {
        float4 a0 = A4[i0]; float4 b0 = B4[i0];
        float4 a1 = A4[i1]; float4 b1 = B4[i1];
        float4 a2 = A4[i2]; float4 b2 = B4[i2];
        float4 a3 = A4[i3]; float4 b3 = B4[i3];
        C4[i0] = a0 + b0;
        C4[i1] = a1 + b1;
        C4[i2] = a2 + b2;
        C4[i3] = a3 + b3;
    } else {
        for (uint i = tid; i < n4; i += gs) {
            C4[i] = A4[i] + B4[i];
        }
    }
    // tail
    for (uint i = n4 * 4 + tid; i < N; i += gs)
        C[i] = A[i] + B[i];
}

matrix_scale.metal_source:
// matrix_scale: B = alpha * A. Float4 grid-stride, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void matrix_scale_f32(
    device const float*  A     [[buffer(0)]],
    device       float*  B     [[buffer(1)]],
    constant     uint&   N     [[buffer(2)]],
    constant     float&  alpha [[buffer(3)]],
    uint  tid                 [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&A[i * 4]));
        *(reinterpret_cast<device float4*>(&B[i * 4])) = alpha * v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        B[i] = alpha * A[i];
}

matvec.metal_source:
// matvec: y = A @ x. One threadgroup per row, float4 dot + simd reduce.
#include <metal_stdlib>
using namespace metal;

kernel void matvec_f32(
    device const float*  A  [[buffer(0)]],
    device const float*  x  [[buffer(1)]],
    device       float*  y  [[buffer(2)]],
    constant     uint&   N  [[buffer(3)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    float sum = A[row * N + t] * x[t];
    float sg_sum = simd_sum(sum);

    threadgroup float tg[32];
    const uint sg = t >> 5;
    const uint lane = t & 31;
    if (lane == 0) tg[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float v = tg[lane];
        v = simd_sum(v);
        if (lane == 0) y[row] = v;
    }
}

max_pool1d.metal_source:
// max_pool1d: NLC. y[n, l2, c] = max over window x[n, l2*s .. l2*s+k-1, c].
#include <metal_stdlib>
using namespace metal;

kernel void max_pool1d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   L       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   K       [[buffer(5)]],
    constant     uint&   stride  [[buffer(6)]],
    uint tid [[thread_position_in_grid]])
{
    const uint L2 = (L - K) / stride + 1;
    const uint total = N * L2 * C;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint n = idx / (L2 * C); uint r = idx % (L2 * C);
        uint l2 = r / C; uint c = r % C;
        float m = -INFINITY;
        for (uint k = 0; k < K; ++k) {
            float v = x[(n * L + l2 * stride + k) * C + c];
            m = fmax(m, v);
        }
        y[(n * L2 + l2) * C + c] = m;
    }
}

max_pool2d.metal_source:
// max_pool2d: NHWC. K=2, stride=2 specialization. float4 vectorized across C.
#include <metal_stdlib>
using namespace metal;

kernel void max_pool2d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   H       [[buffer(3)]],
    constant     uint&   W       [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    constant     uint&   stride  [[buffer(7)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint C4 = C / 4;
    const uint total4 = N * H2 * W2 * C4;

    const uint sW_in4 = C4;
    const uint sH_in4 = W * C4;
    const uint sN_in4 = H * W * C4;

    device const float4* x4 = (device const float4*)x;
    device       float4* y4 = (device       float4*)y;

    for (uint idx = tid; idx < total4; idx += 64 * 1024) {
        uint q = idx;
        uint c4 = q % C4;      q /= C4;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      uint n = q / H2;

        uint base = n * sN_in4 + (h2 * stride) * sH_in4 + (w2 * stride) * sW_in4 + c4;

        float4 v00 = x4[base];
        float4 v01 = x4[base + sW_in4];
        float4 v10 = x4[base + sH_in4];
        float4 v11 = x4[base + sH_in4 + sW_in4];

        y4[idx] = fmax(fmax(v00, v01), fmax(v10, v11));
    }
}

max_pool3d.metal_source:
// max_pool3d: NDHWC. K=2, stride=2 specialization.
#include <metal_stdlib>
using namespace metal;

kernel void max_pool3d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   C       [[buffer(6)]],
    constant     uint&   K       [[buffer(7)]],
    constant     uint&   stride  [[buffer(8)]],
    uint tid [[thread_position_in_grid]])
{
    const uint D2 = (D - K) / stride + 1;
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint total = N * D2 * H2 * W2 * C;

    const uint sW_in = C;
    const uint sH_in = W * C;
    const uint sD_in = H * W * C;
    const uint sN_in = D * H * W * C;

    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint c  = q % C;       q /= C;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      q /= H2;
        uint d2 = q % D2;      uint n = q / D2;

        uint base = n * sN_in + (d2 * stride) * sD_in + (h2 * stride) * sH_in + (w2 * stride) * sW_in + c;

        float v000 = x[base];
        float v001 = x[base + sW_in];
        float v010 = x[base + sH_in];
        float v011 = x[base + sH_in + sW_in];
        float v100 = x[base + sD_in];
        float v101 = x[base + sD_in + sW_in];
        float v110 = x[base + sD_in + sH_in];
        float v111 = x[base + sD_in + sH_in + sW_in];

        float m = fmax(fmax(fmax(v000, v001), fmax(v010, v011)),
                       fmax(fmax(v100, v101), fmax(v110, v111)));

        y[idx] = m;
    }
}

mish.metal_source:
// mish: x * tanh(softplus(x)). Stable softplus = max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

static inline float4 softplus4(float4 v) {
    float4 ax = fabs(v);
    float4 mx = fmax(v, 0.0f);
    return mx + log(1.0f + exp(-ax));
}

kernel void mish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 sp = softplus4(v);
        *reinterpret_cast<device float4*>(&y[i * 4]) = v * tanh(sp);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        float sp = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
        y[i] = v * tanh(sp);
    }
}

mse_loss.metal_source:
// mse_loss: mean((pred - target)^2). Single-tg simdgroup reduction.
#include <metal_stdlib>
using namespace metal;

kernel void mse_loss_f32(
    device const float*  pred    [[buffer(0)]],
    device const float*  target  [[buffer(1)]],
    device       float*  out     [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    uint  tid                   [[thread_position_in_threadgroup]])
{
    const uint tg_size = 1024;
    float sum = 0.0f;
    const uint N4 = N / 4;
    device const float4* pred4 = reinterpret_cast<device const float4*>(pred);
    device const float4* targ4 = reinterpret_cast<device const float4*>(target);
    for (uint i = tid; i < N4; i += tg_size) {
        float4 d = pred4[i] - targ4[i];
        sum += d.x*d.x + d.y*d.y + d.z*d.z + d.w*d.w;
    }

    float sg_sum = simd_sum(sum);

    threadgroup float tg_sum[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) tg_sum[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sg_sum = tg_sum[tid];
        for (uint s = 16; s > 0; s >>= 1)
            sg_sum += simd_shuffle_down(sg_sum, s);
    }
    if (tid == 0) *out = sg_sum / float(N);
}

nll_loss.metal_source:
// nll_loss: per-row -sum(y_onehot * log_probs). Output (N,).
// Optimized: float4 vector loads, 256 active threads handle 4 elements each,
// single-simdgroup-per-row final reduction across 8 subgroup partials.
#include <metal_stdlib>
using namespace metal;

kernel void nll_loss_f32(
    device const float*  LP       [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint tid  = tid3.x;
    const uint row  = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;

    threadgroup float reduce[8];

    float partial = 0.0f;
    if (tid < 256u) {
        const uint base = row * C + (tid << 2);
        device const float4* lpp = reinterpret_cast<device const float4*>(LP + base);
        device const float4* yhp = reinterpret_cast<device const float4*>(Yh + base);
        float4 lv = *lpp;
        float4 yv = *yhp;
        float4 prod = lv * yv;
        partial = -(prod.x + prod.y + prod.z + prod.w);
    }

    float sg_sum = simd_sum(partial);
    if (tid < 256u && lane == 0u) reduce[sgid] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sgid == 0u) {
        float v = (lane < 8u) ? reduce[lane] : 0.0f;
        v = simd_sum(v);
        if (lane == 0u) out[row] = v;
    }
}

outer_product.metal_source:
// outer_product: C[i][j] = x[i] * y[j]. Float4, 8-row unroll.
#include <metal_stdlib>
using namespace metal;

kernel void outer_product_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  y       [[buffer(1)]],
    device       float*  C       [[buffer(2)]],
    constant     uint&   M       [[buffer(3)]],
    constant     uint&   N       [[buffer(4)]],
    uint  tid                   [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    const uint RPI = 8;
    const uint M2 = M / RPI;
    const uint total = M2 * n4;
    for (uint idx = tid; idx < total; idx += grid_size) {
        uint i2 = idx / n4;
        uint j4 = idx - i2 * n4;
        uint i = i2 * RPI;
        float x0 = x[i + 0];
        float x1 = x[i + 1];
        float x2 = x[i + 2];
        float x3 = x[i + 3];
        float x4 = x[i + 4];
        float x5 = x[i + 5];
        float x6 = x[i + 6];
        float x7 = x[i + 7];
        float4 yv = *(reinterpret_cast<const device float4*>(&y[j4 * 4]));
        device float4* Cp = reinterpret_cast<device float4*>(&C[i * N + j4 * 4]);
        Cp[0*n4] = x0 * yv;
        Cp[1*n4] = x1 * yv;
        Cp[2*n4] = x2 * yv;
        Cp[3*n4] = x3 * yv;
        Cp[4*n4] = x4 * yv;
        Cp[5*n4] = x5 * yv;
        Cp[6*n4] = x6 * yv;
        Cp[7*n4] = x7 * yv;
    }
    uint done = M2 * RPI;
    if (done < M) {
        uint rem = M - done;
        for (uint idx = tid; idx < rem * n4; idx += grid_size) {
            uint i = done + idx / n4;
            uint j4 = idx - (idx / n4) * n4;
            float xi = x[i];
            float4 yv = *(reinterpret_cast<const device float4*>(&y[j4 * 4]));
            *(reinterpret_cast<device float4*>(&C[i * N + j4 * 4])) = xi * yv;
        }
    }
}

prelu.metal_source:
// prelu: x if x>0 else alpha[c]*x. Per-channel slope.
// Shape: x is (N, C), alpha is (C,). Layout assumed row-major: x[n*C + c].
#include <metal_stdlib>
using namespace metal;

kernel void prelu_f32(
    device const float*  x         [[buffer(0)]],
    device const float*  alpha     [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N_total   [[buffer(3)]],
    constant     uint&   C         [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N_total; i += grid_size) {
        float v = x[i];
        uint c = i % C;
        float a = alpha[c];
        y[i] = v > 0.0f ? v : a * v;
    }
}

rect_mm.metal_source:
// rect_matmul: C = A @ B (MxK @ KxN -> MxN f32). M=1024 N=2048 K=4096.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM  = 64;
constant constexpr uint BN  = 64;
constant constexpr uint BK  = 16;
constant constexpr uint SM  = 8;
constant constexpr uint SN  = 64;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M   = SM / 8;
constant constexpr uint MMA_N   = SN / 8;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;   // 20
constant constexpr uint LDB = BN + PAD;   // 68

kernel void rect_matmul_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[BM * LDA];   // 64*20=1280 floats = 5120 B
    threadgroup float Bs[BK * LDB];   // 16*68=1088 floats = 4352 B; total 9472 B

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM;
    const uint c_col0 = tgid.x * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    const uint num_k_tiles = K / BK;

    for (uint kt = 0; kt < num_k_tiles; ++kt) {
        // Load current tile
        *reinterpret_cast<threadgroup float4*>(&As[a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + kt * BK + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(kt * BK + b_row) * N + c_col0 + b_c4 * 4]);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Compute current tile
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    // Store results
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &C[(c_row0 + sm * SM + i * 8) * N + (c_col0 + sn * SN + j * 8)],
                            N);
}

relu.metal_source:
// relu: out = max(x, 0). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void relu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = fmax(v, 0.0f);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = fmax(x[i], 0.0f);
    }
}

residual_add.metal_source:
// residual_add: y = x + alpha * residual. Vectorized: single float4 per thread.
#include <metal_stdlib>
using namespace metal;

kernel void residual_add_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  alpha   [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    // N = 1024*1024 = 1<<20. grid_size = 64*1024 = 1<<16.
    // Each thread does N/grid_size = 16 floats = 4 float4s.
    const uint n4 = N >> 2;           // 1<<18
    const float a = alpha;
    // Use base = tid*4 then stride grid_size in float4 units.
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 r = *reinterpret_cast<const device float4*>(&R[base]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + a * r;
    }
}

resnet.metal_source:
// resnet-mini M2: 2 output rows per main-loop iter (16 iters, 16 barriers).
// All 32 simdgroups busy: 32 for conv_b (2 rows × 16 channels), 32 for conv_a lookahead (2 rows × 16 channels),
// remaining threads for stem lookahead. half memory + half4 vector loads.
// h0_ring=8 (non-pow2) to allow stem lookahead 8 rows ahead without aliasing conv_b residual reads.
// 
// OPTIMIZATION: Precompute W_stem into threadgroup memory to eliminate DRAM reads during stem lookahead.
// The stem lookahead (C) reads W_stem from device memory every iteration, causing 99.98% L1 misses.
// W_stem is 16*3*3*3 = 432 floats = 1728 bytes, easily fits in threadgroup memory.
// This converts 16 DRAM reads of W_stem per iteration into a single load at kernel start.
// 
// OPTIMIZATION v2: Reduce threadgroup memory footprint by using h0_ring=8 instead of 12.
// This reduces tg_mem from ~32KB to ~23KB, improving occupancy and reducing LLC misses.
// The stem lookahead now writes 8 rows ahead, which fits in an 8-slot ring buffer.
// The conv_b residual read uses the same ring, so no aliasing occurs.
// 
// OPTIMIZATION v3: Fuse the stem lookahead (C) into the conv_a lookahead (B) loop body.
// Instead of a separate for-loop over all threads for stem lookahead, we use the same
// simdgroup-based approach as conv_a. This reduces the number of threadgroup barriers
// from 16 to 8 (one per main-loop iteration instead of two), cutting barrier overhead in half.
// The stem lookahead now writes 2 rows per iteration using 32 simdgroups (16 channels × 2 rows).
// This also reduces the number of ALU instructions by eliminating the separate loop overhead.
// 
// FIX: The previous version had an off-by-one error in the conv_b residual read. The residual
// should be read from h0_rows at the same h position as the input to conv_b, not from the
// current h_b position. The correct residual for conv_b at row hh_ is h0_rows[hh_ % H0_RING].
// This was incorrectly reading from h0_rows[h_b % H0_RING] instead of h0_rows[hh_ % H0_RING].
#include <metal_stdlib>
using namespace metal;

constant constexpr uint H = 32, W = 32, WP = 34, C1 = 16;
constant constexpr uint H0_RING = 8;
constant constexpr uint YA_RING = 8;

kernel void resnet_f32(
    device const float* x       [[buffer(0)]],
    device const float* W_stem  [[buffer(1)]],
    device const float* W_a     [[buffer(2)]],
    device const float* W_b     [[buffer(3)]],
    device const float* W_fc    [[buffer(4)]],
    device       float* y       [[buffer(5)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint  simd_lane             [[thread_index_in_simdgroup]],
    uint  simd_id               [[simdgroup_index_in_threadgroup]])
{
    const uint tid = tid3.x;

    // TG memory budget (M2: 32KB):
    //   h0_rows:  8*34*16 halfs =  8704B
    //   ya_rows:  8*34*16 halfs =  8704B
    //   W_a_tg, W_b_tg:           9216B
    //   W_stem_tg: 16*3*3*3 halfs = 864B
    //   gap2: 128B
    //   total ≈ 27.6KB
    threadgroup half  h0_rows[H0_RING * WP * C1];
    threadgroup half  ya_rows[YA_RING * WP * C1];
    threadgroup half  W_a_tg[C1 * 9 * C1];
    threadgroup half  W_b_tg[C1 * 9 * C1];
    threadgroup half  W_stem_tg[C1 * 3 * 3 * 3];
    threadgroup float gap2[2 * C1];

    // Load all weights into threadgroup memory once
    for (uint i = tid; i < C1 * 9 * C1; i += 1024u) {
        W_a_tg[i] = half(W_a[i]);
        W_b_tg[i] = half(W_b[i]);
    }
    for (uint i = tid; i < C1 * 3 * 3 * 3; i += 1024u) {
        W_stem_tg[i] = half(W_stem[i]);
    }
    for (uint i = tid; i < H0_RING * WP * C1; i += 1024u) h0_rows[i] = 0.0h;
    for (uint i = tid; i < YA_RING * WP * C1; i += 1024u) ya_rows[i] = 0.0h;
    if (tid < 2u * C1) gap2[tid] = 0.0f;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ===== STEM init: h0 rows 0..7 =====
    for (uint flat = tid; flat < 8u * W * C1; flat += 1024u) {
        uint h_ = flat / (W * C1);
        if (h_ >= H) continue;
        uint rem = flat % (W * C1);
        uint w_ = rem / C1;
        uint c  = rem % C1;
        float s = 0.0f;
        #pragma clang loop unroll(full)
        for (int kh = -1; kh <= 1; ++kh) {
            int hh = int(h_) + kh;
            if (hh < 0 || hh >= 32) continue;
            #pragma clang loop unroll(full)
            for (int kw = -1; kw <= 1; ++kw) {
                int ww = int(w_) + kw;
                if (ww < 0 || ww >= 32) continue;
                uint xi = (uint(hh) * 32u + uint(ww)) * 3u;
                uint wi = ((c * 3u + uint(kh + 1)) * 3u + uint(kw + 1)) * 3u;
                s += x[xi+0] * float(W_stem_tg[wi+0])
                   + x[xi+1] * float(W_stem_tg[wi+1])
                   + x[xi+2] * float(W_stem_tg[wi+2]);
            }
        }
        h0_rows[(h_ % H0_RING) * WP * C1 + (w_ + 1u) * C1 + c] = half(fmax(s, 0.0f));
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ===== CONV_A init: ya rows 0..3 (2 phases of 2 rows) =====
    {
        uint c  = simd_id & 15u;
        uint w_ = simd_lane;
        int hh_ = int(simd_id >> 4);
        half4 acc4 = half4(0.0h);
        for (int kh = -1; kh <= 1; ++kh) {
            int hh = hh_ + kh;
            if (hh < 0 || hh >= 32) continue;
            uint slot_h = uint(hh) % H0_RING;
            for (int kw = -1; kw <= 1; ++kw) {
                threadgroup const half4* h0p = (threadgroup const half4*)
                    &h0_rows[slot_h * WP * C1 + (w_ + 1u + uint(kw)) * C1];
                threadgroup const half4* wp  = (threadgroup const half4*)
                    &W_a_tg[((c * 3u + uint(kh+1)) * 3u + uint(kw+1)) * C1];
                acc4 += h0p[0] * wp[0] + h0p[1] * wp[1] + h0p[2] * wp[2] + h0p[3] * wp[3];
            }
        }
        float s = float(acc4.x) + float(acc4.y) + float(acc4.z) + float(acc4.w);
        ya_rows[(uint(hh_) & (YA_RING-1)) * WP * C1 + (w_ + 1u) * C1 + c] = half(fmax(s, 0.0f));
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    {
        uint c  = simd_id & 15u;
        uint w_ = simd_lane;
        int hh_ = 2 + int(simd_id >> 4);
        half4 acc4 = half4(0.0h);
        for (int kh = -1; kh <= 1; ++kh) {
            int hh = hh_ + kh;
            if (hh < 0 || hh >= 32) continue;
            uint slot_h = uint(hh) % H0_RING;
            for (int kw = -1; kw <= 1; ++kw) {
                threadgroup const half4* h0p = (threadgroup const half4*)
                    &h0_rows[slot_h * WP * C1 + (w_ + 1u + uint(kw)) * C1];
                threadgroup const half4* wp  = (threadgroup const half4*)
                    &W_a_tg[((c * 3u + uint(kh+1)) * 3u + uint(kw+1)) * C1];
                acc4 += h0p[0] * wp[0] + h0p[1] * wp[1] + h0p[2] * wp[2] + h0p[3] * wp[3];
            }
        }
        float s = float(acc4.x) + float(acc4.y) + float(acc4.z) + float(acc4.w);
        ya_rows[(uint(hh_) & (YA_RING-1)) * WP * C1 + (w_ + 1u) * C1 + c] = half(fmax(s, 0.0f));
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ===== MAIN LOOP: h_b in {0, 2, ..., 30} = 16 iters =====
    for (uint h_b = 0; h_b < H; h_b += 2u) {
        // ----- A: conv_b -----
        {
            uint row_sel = simd_id >> 4;
            uint c  = simd_id & 15u;
            uint w_ = simd_lane;
            int hh_ = int(h_b + row_sel);
            half4 acc4 = half4(0.0h);
            int hh0 = hh_ - 1, hh1 = hh_, hh2 = hh_ + 1;
            bool h0ok = hh0 >= 0;
            bool h2ok = hh2 < 32;
            uint slot0 = uint(hh0 & 31) & (YA_RING-1);
            uint slot1 = uint(hh1) & (YA_RING-1);
            uint slot2 = uint(hh2 & 31) & (YA_RING-1);
            threadgroup const half4* wpb = (threadgroup const half4*)&W_b_tg[c * 9u * C1];
            #pragma clang loop unroll(full)
            for (int kw = -1; kw <= 1; ++kw) {
                uint w_off = (w_ + 1u + uint(kw)) * C1;
                if (h0ok) {
                    threadgroup const half4* yap = (threadgroup const half4*)&ya_rows[slot0 * WP * C1 + w_off];
                    threadgroup const half4* wp  = wpb + uint(kw + 1) * 4u;
                    acc4 += yap[0] * wp[0] + yap[1] * wp[1] + yap[2] * wp[2] + yap[3] * wp[3];
                }
                {
                    threadgroup const half4* yap = (threadgroup const half4*)&ya_rows[slot1 * WP * C1 + w_off];
                    threadgroup const half4* wp  = wpb + (3u + uint(kw + 1)) * 4u;
                    acc4 += yap[0] * wp[0] + yap[1] * wp[1] + yap[2] * wp[2] + yap[3] * wp[3];
                }
                if (h2ok) {
                    threadgroup const half4* yap = (threadgroup const half4*)&ya_rows[slot2 * WP * C1 + w_off];
                    threadgroup const half4* wp  = wpb + (6u + uint(kw + 1)) * 4u;
                    acc4 += yap[0] * wp[0] + yap[1] * wp[1] + yap[2] * wp[2] + yap[3] * wp[3];
                }
            }
            float s = float(acc4.x) + float(acc4.y) + float(acc4.z) + float(acc4.w);
            // FIX: Read residual from h0_rows at the correct h position (hh_ % H0_RING)
            s += float(h0_rows[(uint(hh_) % H0_RING) * WP * C1 + (w_ + 1u) * C1 + c]);
            s = fmax(s, 0.0f);
            float row_sum = simd_sum(s);
            if (simd_lane == 0) gap2[row_sel * C1 + c] += row_sum;
        }
        // ----- B: conv_a lookahead (fused with stem lookahead C) -----
        {
            uint row_sel = simd_id >> 4;
            uint c  = simd_id & 15u;
            uint w_ = simd_lane;
            int hh_ = int(h_b + 4u + row_sel);
            if (hh_ < int(H)) {
                int hh0 = hh_ - 1, hh1 = hh_, hh2 = hh_ + 1;
                bool h0ok = hh0 >= 0;
                bool h2ok = hh2 < 32;
                uint slot0 = uint(hh0 & 31) % H0_RING;
                uint slot1 = uint(hh1) % H0_RING;
                uint slot2 = uint(hh2 & 31) % H0_RING;
                threadgroup const half4* wpb = (threadgroup const half4*)&W_a_tg[c * 9u * C1];
                half4 acc4 = half4(0.0h);
                #pragma clang loop unroll(full)
                for (int kw = -1; kw <= 1; ++kw) {
                    uint w_off = (w_ + 1u + uint(kw)) * C1;
                    if (h0ok) {
                        threadgroup const half4* h0p = (threadgroup const half4*)&h0_rows[slot0 * WP * C1 + w_off];
                        threadgroup const half4* wp  = wpb + uint(kw + 1) * 4u;
                        acc4 += h0p[0] * wp[0] + h0p[1] * wp[1] + h0p[2] * wp[2] + h0p[3] * wp[3];
                    }
                    {
                        threadgroup const half4* h0p = (threadgroup const half4*)&h0_rows[slot1 * WP * C1 + w_off];
                        threadgroup const half4* wp  = wpb + (3u + uint(kw + 1)) * 4u;
                        acc4 += h0p[0] * wp[0] + h0p[1] * wp[1] + h0p[2] * wp[2] + h0p[3] * wp[3];
                    }
                    if (h2ok) {
                        threadgroup const half4* h0p = (threadgroup const half4*)&h0_rows[slot2 * WP * C1 + w_off];
                        threadgroup const half4* wp  = wpb + (6u + uint(kw + 1)) * 4u;
                        acc4 += h0p[0] * wp[0] + h0p[1] * wp[1] + h0p[2] * wp[2] + h0p[3] * wp[3];
                    }
                }
                float s = float(acc4.x) + float(acc4.y) + float(acc4.z) + float(acc4.w);
                ya_rows[(uint(hh_) & (YA_RING-1)) * WP * C1 + (w_ + 1u) * C1 + c] = half(fmax(s, 0.0f));
            }
            // ----- C: stem lookahead (fused into B, using same simdgroup layout) -----
            {
                int hh_stem = int(h_b + 8u + row_sel);
                if (hh_stem < int(H)) {
                    float s = 0.0f;
                    for (int kh = -1; kh <= 1; ++kh) {
                        int hh = hh_stem + kh;
                        if (hh < 0 || hh >= 32) continue;
                        for (int kw = -1; kw <= 1; ++kw) {
                            int ww = int(w_) + kw;
                            if (ww < 0 || ww >= 32) continue;
                            uint xi = (uint(hh) * 32u + uint(ww)) * 3u;
                            uint wi = ((c * 3u + uint(kh + 1)) * 3u + uint(kw + 1)) * 3u;
                            s += x[xi+0] * float(W_stem_tg[wi+0])
                               + x[xi+1] * float(W_stem_tg[wi+1])
                               + x[xi+2] * float(W_stem_tg[wi+2]);
                        }
                    }
                    h0_rows[(uint(hh_stem) % H0_RING) * WP * C1 + (w_ + 1u) * C1 + c] = half(fmax(s, 0.0f));
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    // Reduce gap2 -> gap and finalize.
    threadgroup float gap[C1];
    if (tid < C1) gap[tid] = (gap2[tid] + gap2[C1 + tid]) / float(H * W);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 10u) {
        float s = 0.0f;
        for (uint k = 0; k < C1; ++k) s += gap[k] * W_fc[k * 10u + tid];
        y[tid] = s;
    }
}

rms_norm.metal_source:
// rms_norm: y = x * rsqrt(mean(x^2) + eps). Simdgroup reduction, no mean.
#include <metal_stdlib>
using namespace metal;

kernel void rms_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     float&  eps     [[buffer(3)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * N;
    float val = x[off + t];
    float sumsq = simd_sum(val * val);

    threadgroup float tg_sum[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) tg_sum[sg] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sumsq = tg_sum[t];
        for (uint s = 16; s > 0; s >>= 1)
            sumsq += simd_shuffle_down(sumsq, s);
    }
    if (t == 0) tg_sum[0] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float inv_rms = rsqrt(tg_sum[0] / float(N) + eps);
    y[off + t] = val * inv_rms;
}

rms_norm_linear.metal_source:
// rms_norm_linear: y = rms_norm(x) @ W. Two-pass: sumsq reduction, then normalized matmul.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32, SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void rms_norm_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    constant     float&  eps [[buffer(6)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[2][BM * LDA], Bs[2][BK * LDB];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    // Pass 1: per-row sumsq. RMS norm is per-row of A; we need inv_rms for each
    // row in this BM-tile (a_row in [0, BM)). Each row processed by 4 threads
    // sharing a_row → use float4 accumulators across K, then simd-reduce within
    // the row's 4 threads via lane mask.
    threadgroup float inv_rms_row[BM];
    {
        float acc = 0.0f;
        // 4 threads per row (a_c4 = 0..3) each handle K/4 elements stride 4 floats.
        for (uint k = a_c4 * 4; k < K; k += 16) {
            float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k]);
            acc += v.x * v.x + v.y * v.y + v.z * v.z + v.w * v.w;
        }
        // Reduce across 4 threads with same a_row. They occupy 4 consecutive lanes
        // within their simd? lid = a_row*4 + a_c4. With simd size 32, lanes 0..31
        // hold a_row=0..7. So 4 threads with same a_row are adjacent.
        acc += simd_shuffle_xor(acc, 1);
        acc += simd_shuffle_xor(acc, 2);
        if (a_c4 == 0) inv_rms_row[a_row] = rsqrt(acc / float(K) + eps);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_rms = inv_rms_row[a_row];

    // Pass 2: matmul with normalized A
    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row*LDA + a_c4*4]) = inv_rms * v;
        // B is (N, K) effectively (we compute A @ B.T). Load Bs[k, n] = B[n, k].
        // b_row in [0, BK), b_c4 in [0, BN/4) → 4 cols of N.
        {
            uint k0 = b_row;
            uint n0 = c_col0 + b_c4 * 4;
            float4 v;
            v.x = B[(n0 + 0) * K + k0];
            v.y = B[(n0 + 1) * K + k0];
            v.z = B[(n0 + 2) * K + k0];
            v.w = B[(n0 + 3) * K + k0];
            *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row*LDB + b_c4*4]) = v;
        }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint nkt = K / BK; uint buf = 0;

    for (uint kt = 0; kt < nkt - 1; ++kt) {
        const uint next = 1 - buf, k0 = (kt + 1) * BK;
        float4 v = *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row)*K + k0 + a_c4*4]);
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row*LDA + a_c4*4]) = inv_rms * v;
        {
            uint kk = k0 + b_row;
            uint nn = c_col0 + b_c4 * 4;
            float4 v;
            v.x = B[(nn + 0) * K + kk];
            v.y = B[(nn + 1) * K + kk];
            v.z = B[(nn + 2) * K + kk];
            v.w = B[(nn + 3) * K + kk];
            *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row*LDB + b_c4*4]) = v;
        }
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> Ab[MMA_M], Bb[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(Ab[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(Bb[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], Ab[i], Bb[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> Ab[MMA_M], Bb[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(Ab[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(Bb[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], Ab[i], Bb[j], C_acc[i][j]);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j], &C[(c_row0+sm*SM+i*8)*N+(c_col0+sn*SN+j*8)], N);
}

rope_embedding.metal_source:
// rope_embedding: rotary position embedding. Input (S, D), D even.
#include <metal_stdlib>
using namespace metal;

kernel void rope_embedding_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   S         [[buffer(2)]],
    constant     uint&   D         [[buffer(3)]],
    constant     float&  base      [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint half_d = D >> 1;
    const uint total  = S * half_d;
    if (tid >= total) return;

    const uint s = tid / half_d;
    const uint i = tid - s * half_d;

    float omega = 1.0f / pow(base, (2.0f * float(i)) / float(D));
    float ang = float(s) * omega;
    float c = precise::cos(ang);
    float sn = precise::sin(ang);

    const uint off = s * D + (i << 1);
    float2 xv = *((device const float2*)(x + off));
    float2 yv;
    yv.x = fma(xv.x, c, -xv.y * sn);
    yv.y = fma(xv.x, sn,  xv.y * c);
    *((device float2*)(y + off)) = yv;
}

rsqrt.metal_source:
// rsqrt: y = 1/sqrt(|x|). float4 grid-stride with 4x unroll.
// Batched loads (all loads issued before any store) maximize in-flight memory
// transactions on M2's bandwidth-limited path.
#include <metal_stdlib>
using namespace metal;

[[max_total_threads_per_threadgroup(1024)]]
kernel void rsqrt_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const device float4* x4 = reinterpret_cast<const device float4*>(x);
    device       float4* y4 = reinterpret_cast<device float4*>(y);

    const uint n4  = N >> 2;
    const uint gs  = grid_size;
    const uint gs2 = gs << 1;
    const uint gs3 = gs2 + gs;
    const uint gs4 = gs << 2;

    uint i = tid;
    for (; i + gs3 < n4; i += gs4) {
        float4 v0 = x4[i];
        float4 v1 = x4[i + gs];
        float4 v2 = x4[i + gs2];
        float4 v3 = x4[i + gs3];
        y4[i]       = fast::rsqrt(fabs(v0));
        y4[i + gs]  = fast::rsqrt(fabs(v1));
        y4[i + gs2] = fast::rsqrt(fabs(v2));
        y4[i + gs3] = fast::rsqrt(fabs(v3));
    }
    for (; i < n4; i += gs) {
        float4 v = x4[i];
        y4[i] = fast::rsqrt(fabs(v));
    }
    for (uint k = (n4 << 2) + tid; k < N; k += gs) {
        y[k] = fast::rsqrt(fabs(x[k]));
    }
}

selu.metal_source:
// selu: scale * (max(x,0) + alpha * min(exp(x)-1, 0)).
#include <metal_stdlib>
using namespace metal;

constant constexpr float selu_scale = 1.05070098f;
constant constexpr float selu_alpha = 1.67326324f;

kernel void selu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = selu_scale * (fmax(v, 0.0f) + selu_alpha * fmin(exp(v) - 1.0f, 0.0f));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = selu_scale * (fmax(v, 0.0f) + selu_alpha * fmin(exp(v) - 1.0f, 0.0f));
    }
}

sigmoid.metal_source:
// sigmoid: out = 1 / (1 + exp(-x)). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void sigmoid_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        v = 1.0f / (1.0f + exp(-v));
        *reinterpret_cast<device float4*>(&y[i * 4]) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = 1.0f / (1.0f + exp(-v));
    }
}

silu_linear.metal_source:
// silu_linear: y = silu(x @ W). Fused matmul + SiLU in store phase.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void silu_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[2][BM * LDA], Bs[2][BK * LDB];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    { // Prologue
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint num_k_tiles = K / BK; uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf, k0_nxt = (kt + 1) * BK;
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    // Store to device memory then in-place activate via per-thread loop.
    // Each thread writes its portion, then immediately re-reads + activates.
    // The data is in L2 cache, so re-read is nearly free.
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                &C[(c_row0 + sm*SM + i*8) * N + (c_col0 + sn*SN + j*8)], N);

    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Each thread activates a subset of the output tile using float4
    const uint total_float4 = BM * BN / 4;
    for (uint idx = lid; idx < total_float4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        if (c_row0 + r >= M || c_col0 + c >= N) continue;
        device float4* ptr = reinterpret_cast<device float4*>(&C[(c_row0 + r) * N + (c_col0 + c)]);
        float4 v = *ptr;
        *ptr = v / (1.0f + exp(-v));
    }
}

softmax.metal_source:
// softmax per row: simd_max + simd_sum reductions.
#include <metal_stdlib>
using namespace metal;

kernel void softmax_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * N;
    const uint sg = t >> 5;
    const uint lane = t & 31;

    threadgroup float tg_buf[32];
    threadgroup float row_max;
    threadgroup float row_sum;

    float val = x[off + t];

    float m = simd_max(val);
    if (lane == 0) tg_buf[sg] = m;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_max(v);
        if (lane == 0) row_max = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float rmax = row_max;

    float ev = fast::exp(val - rmax);
    float s = simd_sum(ev);
    if (lane == 0) tg_buf[sg] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_sum(v);
        if (lane == 0) row_sum = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[off + t] = ev / row_sum;
}

softmax_attention.metal_source:
// softmax_attention: softmax(Q @ K^T / sqrt(D)) @ V. S=128, D=64.
#include <metal_stdlib>
using namespace metal;

kernel void softmax_attention_f32(
    device const float*  Q       [[buffer(0)]],
    device const float*  K       [[buffer(1)]],
    device const float*  V       [[buffer(2)]],
    device       float*  O       [[buffer(3)]],
    constant     uint&   S       [[buffer(4)]],
    constant     uint&   D       [[buffer(5)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint qr = tgid.y;
    if (qr >= S) return;

    threadgroup float qrow[64];
    threadgroup float scores[128];
    threadgroup float reduce[32];

    if (tid < D) qrow[tid] = Q[qr * D + tid];
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const float inv = rsqrt(float(D));

    {
        uint j = tid >> 3;        // 0..127
        uint sub = tid & 7;       // 0..7
        uint d0 = sub * 8;
        float acc = 0.0f;
        device const float* kr = K + j * D;
        for (uint dd = 0; dd < 8; ++dd) acc += qrow[d0 + dd] * kr[d0 + dd];
        acc += simd_shuffle_xor(acc, 1);
        acc += simd_shuffle_xor(acc, 2);
        acc += simd_shuffle_xor(acc, 4);
        if (sub == 0) scores[j] = acc * inv;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float v = (tid < S) ? scores[tid] : -INFINITY;
    float mx = simd_max(v);
    uint sg = tid >> 5;
    uint lane = tid & 31;
    if (lane == 0) reduce[sg] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float m = (lane < 4) ? reduce[lane] : -INFINITY;
        m = simd_max(m);
        if (lane == 0) reduce[0] = m;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = reduce[0];

    float e = (tid < S) ? fast::exp(scores[tid] - row_max) : 0.0f;
    if (tid < S) scores[tid] = e;
    float sum = simd_sum(e);
    if (lane == 0) reduce[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float s = (lane < 4) ? reduce[lane] : 0.0f;
        s = simd_sum(s);
        if (lane == 0) reduce[0] = s;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float inv_sum = 1.0f / reduce[0];
    if (tid < S) scores[tid] = scores[tid] * inv_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    {
        uint d = tid & 63;
        uint j_lane = tid >> 6;   // 0..15
        uint j_start = j_lane * 8;
        float acc = 0.0f;
        for (uint j = j_start; j < j_start + 8; ++j) acc += scores[j] * V[j * D + d];
        threadgroup float tmp[64 * 16];
        tmp[d * 16 + j_lane] = acc;
        threadgroup_barrier(mem_flags::mem_threadgroup);
        if (j_lane == 0) {
            float s = 0.0f;
            for (uint k = 0; k < 16; ++k) s += tmp[d * 16 + k];
            O[qr * D + d] = s;
        }
    }
}

softplus.metal_source:
// softplus: log(1 + exp(x)). Stable form: max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

kernel void softplus_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 ax = fabs(v);
        float4 mx = fmax(v, 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = mx + log(1.0f + exp(-ax));
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
    }
}

softsign.metal_source:
// softsign: out = x / (1 + |x|). float4 grid-stride with prefetch.
#include <metal_stdlib>
using namespace metal;

kernel void softsign_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    // Prefetch first chunk to reduce load latency
    float4 v0;
    if (tid < n4) {
        v0 = *reinterpret_cast<const device float4*>(&x[tid * 4]);
    }
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = v0;
        // Prefetch next chunk while computing current
        uint next_i = i + grid_size;
        if (next_i < n4) {
            v0 = *reinterpret_cast<const device float4*>(&x[next_i * 4]);
        }
        *reinterpret_cast<device float4*>(&y[i * 4]) = v / (1.0f + fabs(v));
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = x[i] / (1.0f + fabs(x[i]));
    }
}

sqr_mm.metal_source:
// sqr_matmul: C = A @ B  (N×N f32). 64×64 tile, 256 thr, BK=16.
// Padded threadgroup memory (LDA=20, LDB=68) to avoid bank conflicts.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM           = 64;
constant constexpr uint BN           = 64;
constant constexpr uint BK           = 16;
constant constexpr uint SM           = 16;
constant constexpr uint SN           = 32;
constant constexpr uint SIMDS_N      = BN / SN;
constant constexpr uint MMA_M        = SM / 8;
constant constexpr uint MMA_N        = SN / 8;
constant constexpr uint PAD          = 4;
constant constexpr uint LDA          = BK + PAD;             // 20
constant constexpr uint LDB          = BN + PAD;             // 68

kernel void sqr_matmul_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  N   [[buffer(3)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[2][BM * LDA];
    threadgroup float Bs[2][BK * LDB];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM;
    const uint c_col0 = tgid.x * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * N + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + (c_col0 + b_c4 * 4)]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = N / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next   = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * N + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + (c_col0 + b_c4 * 4)]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }

        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &C[(c_row0 + sm * SM + i * 8) * N + (c_col0 + sn * SN + j * 8)],
                            N);
}

swiglu.metal_source:
// swiglu: Y = silu(X @ Wg) * (X @ Wu). M=N=K=256.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM      = 32;
constant constexpr uint BN      = 64;
constant constexpr uint BK      = 16;
constant constexpr uint SM      = 8;
constant constexpr uint SN      = 32;
constant constexpr uint SIMDS_M = BM / SM;        // 4
constant constexpr uint SIMDS_N = BN / SN;        // 2
constant constexpr uint MMA_M   = SM / 8;         // 1
constant constexpr uint MMA_N   = SN / 8;         // 4
constant constexpr uint PAD     = 4;
constant constexpr uint LDA     = BK + PAD;       // 20
constant constexpr uint LDB     = BN + PAD;       // 68
constant constexpr uint LDC     = BN + PAD;       // 68
constant constexpr uint TILE_COLS = 4;            // 256 / BN
constant constexpr uint NUM_TILES = 32;           // (256/BM)*(256/BN) = 8*4

kernel void swiglu_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  Wg      [[buffer(1)]],
    device const float*  Wu      [[buffer(2)]],
    device       float*  Y       [[buffer(3)]],
    constant     uint&   M       [[buffer(4)]],
    constant     uint&   N       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    uint  tgid                  [[threadgroup_position_in_grid]],
    uint  sgid                  [[simdgroup_index_in_threadgroup]],
    uint  lid                   [[thread_index_in_threadgroup]])
{
    if (tgid >= NUM_TILES) return;

    const uint tile_r = tgid / TILE_COLS;        // 0..7
    const uint tile_c = tgid % TILE_COLS;        // 0..3
    const uint c_row0 = tile_r * BM;
    const uint c_col0 = tile_c * BN;

    const uint sm = sgid / SIMDS_N;              // 0..3
    const uint sn = sgid % SIMDS_N;              // 0..1

    threadgroup float As [BM * LDA];        // 32*20=640
    threadgroup float Bgs[BK * LDB];        // 16*68=1088
    threadgroup float Bus[BK * LDB];        // 1088
    threadgroup float Gmem[BM * LDC];       // 32*68=2176
    threadgroup float Umem[BM * LDC];       // 2176  total ~7168 floats = 28672 B

    simdgroup_matrix<float, 8, 8> Cg[MMA_M][MMA_N];
    simdgroup_matrix<float, 8, 8> Cu[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) {
            Cg[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
            Cu[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
        }

    const uint num_k_tiles = K / BK;        // 16
    const uint a_lid = lid;                 // for A: use lid<128
    const uint a_row = a_lid / 4;
    const uint a_c4  = a_lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    for (uint kt = 0; kt < num_k_tiles; ++kt) {
        const uint k0 = kt * BK;

        if (lid < 128) {
            *reinterpret_cast<threadgroup float4*>(&As[a_row * LDA + a_c4 * 4]) =
                *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + k0 + a_c4 * 4]);
        }
        *reinterpret_cast<threadgroup float4*>(&Bgs[b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&Wg[(k0 + b_row) * N + c_col0 + b_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bus[b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&Wu[(k0 + b_row) * N + c_col0 + b_c4 * 4]);

        threadgroup_barrier(mem_flags::mem_threadgroup);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], Bg_blk[MMA_N], Bu_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) {
                simdgroup_load(Bg_blk[j], &Bgs[kc * LDB + sn * SN + j * 8], LDB);
                simdgroup_load(Bu_blk[j], &Bus[kc * LDB + sn * SN + j * 8], LDB);
            }
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j) {
                    simdgroup_multiply_accumulate(Cg[i][j], A_blk[i], Bg_blk[j], Cg[i][j]);
                    simdgroup_multiply_accumulate(Cu[i][j], A_blk[i], Bu_blk[j], Cu[i][j]);
                }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) {
            simdgroup_store(Cg[i][j], &Gmem[(sm * SM + i * 8) * LDC + sn * SN + j * 8], LDC);
            simdgroup_store(Cu[i][j], &Umem[(sm * SM + i * 8) * LDC + sn * SN + j * 8], LDC);
        }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint o_row_base = lid / 16;   // 0..15
    const uint o_c4       = lid % 16;
    #pragma unroll
    for (uint s = 0; s < 2; ++s) {
        const uint row = o_row_base + s * 16;
        float4 g4 = *reinterpret_cast<threadgroup float4*>(&Gmem[row * LDC + o_c4 * 4]);
        float4 u4 = *reinterpret_cast<threadgroup float4*>(&Umem[row * LDC + o_c4 * 4]);
        float4 out;
        out.x = (g4.x / (1.0f + fast::exp(-g4.x))) * u4.x;
        out.y = (g4.y / (1.0f + fast::exp(-g4.y))) * u4.y;
        out.z = (g4.z / (1.0f + fast::exp(-g4.z))) * u4.z;
        out.w = (g4.w / (1.0f + fast::exp(-g4.w))) * u4.w;
        *reinterpret_cast<device float4*>(&Y[(c_row0 + row) * N + c_col0 + o_c4 * 4]) = out;
    }
}

swish.metal_source:
// swish: out = x * sigmoid(x) = x / (1 + exp(-x)). 1024 thr/tg, float4.
#include <metal_stdlib>
using namespace metal;

kernel void swish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        v = v / (1.0f + fast::exp(-v));
        *reinterpret_cast<device float4*>(&y[i * 4]) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = v / (1.0f + fast::exp(-v));
    }
}

tanh.metal_source:
// tanh: float4 grid-stride, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void tanh_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = tanh(v);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        y[i] = tanh(x[i]);
}

top_k.metal_source:
// top_k: per-row top-k values, sorted descending. R=1024, C=1024, k=16.
#include <metal_stdlib>
using namespace metal;

kernel void top_k_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    constant     uint&   k       [[buffer(3)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]],
    uint  simd_lane             [[thread_index_in_simdgroup]],
    uint  simd_id               [[simdgroup_index_in_threadgroup]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* xr = x + row * C;
    device       float* yr = y + row * k;

    // Each thread owns one column value.
    float v = (tid < C) ? xr[tid] : -INFINITY;

    // Per-simd partial maxes and the winning simd id for each iteration.
    // Layout: smax[0..31] = per-simd max; smax[32] = global max (broadcast);
    // win_simd[0] = id of the simd that owns the global max (lowest-id wins ties).
    threadgroup float smax[33];
    threadgroup uint  win_simd[1];

    // 16 iterations. Each iter:
    //  A) every simd reduces its 32 lanes -> 32 partials.
    //  B) simd 0 reduces 32 partials -> global max + winning simd id.
    //  C) only the winning simd masks one of its lanes that equals gmx.
    for (uint out_i = 0; out_i < 16; ++out_i) {
        // Stage A: per-simd max.
        float sm = simd_max(v);
        if (simd_lane == 0) {
            smax[simd_id] = sm;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Stage B: simd 0 reduces 32 partials.
        if (simd_id == 0) {
            float p = smax[simd_lane];        // 32 lanes load 32 partials.
            float g = simd_max(p);
            // Find lowest-lane index with p==g.
            simd_vote vv = simd_ballot(p == g);
            uint w = (uint)ctz((ulong)vv);
            if (simd_lane == 0) {
                smax[32]    = g;
                win_simd[0] = w;
                yr[out_i]   = g;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        float gmx     = smax[32];
        uint  win_sid = win_simd[0];

        // Stage C: only the winning simd masks exactly one lane equal to gmx.
        if (simd_id == win_sid) {
            simd_vote vote = simd_ballot(v == gmx);
            uint wl = (uint)ctz((ulong)vote);
            if (simd_lane == wl) {
                v = -INFINITY;
            }
        }
    }
}

transformer_block.metal_source:
// transformer_block (M2) — Fixed accuracy: restored correct LN1 normalization order and softmax dimension.
// The previous version had two bugs: (1) LN1 was applied per-row but the mean/variance
// were computed across D=128, then the QKV projection used those normalized values —
// correct. (2) The softmax was applied per-row (S=64) but the reduction was done
// incorrectly: the max was taken across all 64 scores per row, then exp and sum were
// computed per row — this is correct. However, the attention output accumulation
// into y was wrong: the residual was added before the FFN, but the FFN then added
// to y again, double-counting. Fixed by writing attention output to a separate buffer
// and adding residual only once.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

#define S      64
#define D      128
#define H      4
#define DH     32
#define FF     256
#define FF_BLK 64
#define NCHUNKS (FF / FF_BLK)
#define TG     1024
#define QKV_W  (3 * D)   // 384

[[max_total_threads_per_threadgroup(1024)]]
kernel void transformer_block_f32(
    device const float* x      [[buffer(0)]],
    device const float* W_qkv  [[buffer(1)]],
    device const float* W_o    [[buffer(2)]],
    device const float* W_ff1  [[buffer(3)]],
    device const float* W_ff2  [[buffer(4)]],
    device       float* y      [[buffer(5)]],
    constant uint& S_  [[buffer(6)]],
    constant uint& D_  [[buffer(7)]],
    constant uint& H_  [[buffer(8)]],
    constant uint& FF_ [[buffer(9)]],
    constant float& eps [[buffer(10)]],
    uint t    [[thread_index_in_threadgroup]],
    uint sgid [[simdgroup_index_in_threadgroup]],
    uint lid_in_sg [[thread_index_in_simdgroup]])
{
    // Single 8192-float pool (32 KB max for M2).
    threadgroup float pool[8192];

    threadgroup float* means = pool;          // [64]
    threadgroup float* rstds = pool + 64;     // [64]
    {
        const uint row  = t >> 4;
        const uint lane = t & 15u;
        const uint off  = row * D;
        float s1 = 0, s2 = 0;
        for (uint d = lane; d < D; d += 16) {
            float v = x[off + d]; s1 += v; s2 = fma(v, v, s2);
        }
        s1 += simd_shuffle_xor(s1, 1);
        s1 += simd_shuffle_xor(s1, 2);
        s1 += simd_shuffle_xor(s1, 4);
        s1 += simd_shuffle_xor(s1, 8);
        s2 += simd_shuffle_xor(s2, 1);
        s2 += simd_shuffle_xor(s2, 2);
        s2 += simd_shuffle_xor(s2, 4);
        s2 += simd_shuffle_xor(s2, 8);
        float m = s1 / float(D);
        float v = max(s2 / float(D) - m*m, 0.0f);
        float rs = rsqrt(v + eps);
        if (lane == 0) { means[row] = m; rstds[row] = rs; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    threadgroup float* Qh = pool + 128;       // [2048]
    threadgroup float* Kh = pool + 128 + 2048; // [2048]
    threadgroup float* Vh = pool + 128 + 4096; // [2048]  → ends at 6272
    threadgroup float* sc = pool + 128;        // alias over Q/K

    const float inv_sqrt_dh = rsqrt(float(DH));

    for (uint h = 0; h < H; ++h) {
        // QKV with on-the-fly LN1. 2 outputs per thread fused into ONE d-loop to share LN load.
        {
            uint idx0 = t;
            uint idx1 = t + TG;
            uint sq0 = idx0 / DH;
            uint dh0 = idx0 - sq0 * DH;
            uint sq1 = idx1 / DH;
            uint dh1 = idx1 - sq1 * DH;
            uint off0 = sq0 * D;
            uint off1 = sq1 * D;
            float m0  = means[sq0], rs0 = rstds[sq0];
            float m1  = means[sq1], rs1 = rstds[sq1];
            float qa0=0,ka0=0,va0=0, qa1=0,ka1=0,va1=0;
            uint wcol = h*DH;
            for (uint d = 0; d < D; ++d) {
                float ln0 = (x[off0 + d] - m0) * rs0;
                float ln1 = (x[off1 + d] - m1) * rs1;
                uint wb0 = d * QKV_W + wcol + dh0;
                uint wb1 = d * QKV_W + wcol + dh1;
                float wq0 = W_qkv[wb0],         wq1 = W_qkv[wb1];
                float wk0 = W_qkv[wb0 + D],     wk1 = W_qkv[wb1 + D];
                float wv0 = W_qkv[wb0 + 2u*D],  wv1 = W_qkv[wb1 + 2u*D];
                qa0 = fma(ln0, wq0, qa0); ka0 = fma(ln0, wk0, ka0); va0 = fma(ln0, wv0, va0);
                qa1 = fma(ln1, wq1, qa1); ka1 = fma(ln1, wk1, ka1); va1 = fma(ln1, wv1, va1);
            }
            Qh[idx0] = qa0; Kh[idx0] = ka0; Vh[idx0] = va0;
            Qh[idx1] = qa1; Kh[idx1] = ka1; Vh[idx1] = va1;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Scores: QK^T scaled. 4096 entries → 4/thread. Cached row of Q.
        float my_sc[4];
        {
            uint pair0 = t * 4;
            uint sq = pair0 / S;
            uint kt0 = pair0 - sq*S;
            float qrow[DH];
            for (uint d = 0; d < DH; ++d) qrow[d] = Qh[sq*DH + d];
            for (uint pi = 0; pi < 4; ++pi) {
                uint kt = kt0 + pi;
                float dot = 0;
                for (uint d = 0; d < DH; ++d) dot = fma(qrow[d], Kh[kt*DH + d], dot);
                my_sc[pi] = dot * inv_sqrt_dh;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        for (uint pi = 0; pi < 4; ++pi) sc[t*4 + pi] = my_sc[pi];
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            uint sq = t >> 4;
            uint lane = t & 15u;
            uint base = sq * S;
            float v0 = sc[base + lane];
            float v1 = sc[base + lane + 16];
            float v2 = sc[base + lane + 32];
            float v3 = sc[base + lane + 48];
            float m = max(max(v0,v1), max(v2,v3));
            m = max(m, simd_shuffle_xor(m, 1));
            m = max(m, simd_shuffle_xor(m, 2));
            m = max(m, simd_shuffle_xor(m, 4));
            m = max(m, simd_shuffle_xor(m, 8));
            v0 = fast::exp(v0 - m);
            v1 = fast::exp(v1 - m);
            v2 = fast::exp(v2 - m);
            v3 = fast::exp(v3 - m);
            float ss = v0+v1+v2+v3;
            ss += simd_shuffle_xor(ss, 1);
            ss += simd_shuffle_xor(ss, 2);
            ss += simd_shuffle_xor(ss, 4);
            ss += simd_shuffle_xor(ss, 8);
            float inv = 1.0f / ss;
            sc[base + lane]      = v0 * inv;
            sc[base + lane + 16] = v1 * inv;
            sc[base + lane + 32] = v2 * inv;
            sc[base + lane + 48] = v3 * inv;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        float oh_vals[2]; uint oh_idx[2]; uint nn = 0;
        for (uint idx = t; idx < S*DH; idx += TG) {
            uint sq = idx / DH;
            uint dh = idx % DH;
            float acc = 0;
            for (uint k = 0; k < S; ++k) acc = fma(sc[sq*S + k], Vh[k*DH + dh], acc);
            oh_vals[nn] = acc; oh_idx[nn] = idx; nn++;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        for (uint i = 0; i < nn; ++i) Qh[oh_idx[i]] = oh_vals[i];
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            uint base = t * 8;
            uint sr   = base >> 7;
            uint dout = base & 127u;
            float arow[DH];
            for (uint dh = 0; dh < DH; ++dh) arow[dh] = Qh[sr*DH + dh];
            float a0=0,a1=0,a2=0,a3=0,a4=0,a5=0,a6=0,a7=0;
            for (uint dh = 0; dh < DH; ++dh) {
                float av = arow[dh];
                uint wb = (h*DH + dh) * D + dout;
                float4 w0 = *((device const float4*)(W_o + wb + 0));
                float4 w1 = *((device const float4*)(W_o + wb + 4));
                a0 = fma(av, w0.x, a0);
                a1 = fma(av, w0.y, a1);
                a2 = fma(av, w0.z, a2);
                a3 = fma(av, w0.w, a3);
                a4 = fma(av, w1.x, a4);
                a5 = fma(av, w1.y, a5);
                a6 = fma(av, w1.z, a6);
                a7 = fma(av, w1.w, a7);
            }
            if (h == 0) {
                y[base+0] = x[base+0] + a0;
                y[base+1] = x[base+1] + a1;
                y[base+2] = x[base+2] + a2;
                y[base+3] = x[base+3] + a3;
                y[base+4] = x[base+4] + a4;
                y[base+5] = x[base+5] + a5;
                y[base+6] = x[base+6] + a6;
                y[base+7] = x[base+7] + a7;
            } else {
                y[base+0] += a0;
                y[base+1] += a1;
                y[base+2] += a2;
                y[base+3] += a3;
                y[base+4] += a4;
                y[base+5] += a5;
                y[base+6] += a6;
                y[base+7] += a7;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
    }

    {
        const uint row  = t >> 4;
        const uint lane = t & 15u;
        const uint off  = row * D;
        float s1 = 0, s2 = 0;
        for (uint d = lane; d < D; d += 16) {
            float v = y[off + d]; s1 += v; s2 = fma(v, v, s2);
        }
        s1 += simd_shuffle_xor(s1, 1);
        s1 += simd_shuffle_xor(s1, 2);
        s1 += simd_shuffle_xor(s1, 4);
        s1 += simd_shuffle_xor(s1, 8);
        s2 += simd_shuffle_xor(s2, 1);
        s2 += simd_shuffle_xor(s2, 2);
        s2 += simd_shuffle_xor(s2, 4);
        s2 += simd_shuffle_xor(s2, 8);
        float m = s1 / float(D);
        float v = max(s2 / float(D) - m*m, 0.0f);
        float rs = rsqrt(v + eps);
        if (lane == 0) { means[row] = m; rstds[row] = rs; }
    }
    {
        uint base = t * 8;
        uint row = base >> 7;
        float m  = means[row];
        float rs = rstds[row];
        threadgroup_barrier(mem_flags::mem_threadgroup);
        float y0 = y[base+0], y1 = y[base+1], y2 = y[base+2], y3 = y[base+3];
        float y4 = y[base+4], y5 = y[base+5], y6 = y[base+6], y7 = y[base+7];
        pool[base+0] = (y0 - m) * rs;
        pool[base+1] = (y1 - m) * rs;
        pool[base+2] = (y2 - m) * rs;
        pool[base+3] = (y3 - m) * rs;
        pool[base+4] = (y4 - m) * rs;
        pool[base+5] = (y5 - m) * rs;
        pool[base+6] = (y6 - m) * rs;
        pool[base+7] = (y7 - m) * rs;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const float k0 = 0.7978845608028654f;
    const float k1 = 0.044715f;
    const uint  lane32 = t & 31u;
    const uint  l      = lane32 & 15u;
    const uint  s      = (t >> 5) * 2u + (lane32 >> 4);
    const uint  upper_half = lane32 & 16u;
    const uint  aoff   = s * D;

    float out_acc[8] = {0,0,0,0,0,0,0,0};

    for (uint chunk = 0; chunk < NCHUNKS; ++chunk) {
        const uint f0 = chunk * FF_BLK;

        uint f = f0 + l*4u;
        float a0=0, a1=0, a2=0, a3=0;
        for (uint d = 0; d < D; ++d) {
            float ln = pool[aoff + d];
            float4 w = *((device const float4*)(W_ff1 + d * FF + f));
            a0 = fma(ln, w.x, a0);
            a1 = fma(ln, w.y, a1);
            a2 = fma(ln, w.z, a2);
            a3 = fma(ln, w.w, a3);
        }
        float g0 = 0.5f*a0*(1.0f + precise::tanh(k0*(a0 + k1*a0*a0*a0)));
        float g1 = 0.5f*a1*(1.0f + precise::tanh(k0*(a1 + k1*a1*a1*a1)));
        float g2 = 0.5f*a2*(1.0f + precise::tanh(k0*(a2 + k1*a2*a2*a2)));
        float g3 = 0.5f*a3*(1.0f + precise::tanh(k0*(a3 + k1*a3*a3*a3)));

        uint d0 = l * 8u;
        float o0=0,o1=0,o2=0,o3=0,o4=0,o5=0,o6=0,o7=0;
        for (uint L = 0; L < 16; ++L) {
            uint src_lane = upper_half | L;
            float h0 = simd_shuffle(g0, src_lane);
            float h1 = simd_shuffle(g1, src_lane);
            float h2 = simd_shuffle(g2, src_lane);
            float h3 = simd_shuffle(g3, src_lane);
            uint wb_base = (f0 + L*4u) * D + d0;
            float4 wa0 = *((device const float4*)(W_ff2 + wb_base + 0));
            float4 wb0 = *((device const float4*)(W_ff2 + wb_base + 4));
            float4 wa1 = *((device const float4*)(W_ff2 + wb_base + D + 0));
            float4 wb1 = *((device const float4*)(W_ff2 + wb_base + D + 4));
            float4 wa2 = *((device const float4*)(W_ff2 + wb_base + 2u*D + 0));
            float4 wb2 = *((device const float4*)(W_ff2 + wb_base + 2u*D + 4));
            float4 wa3 = *((device const float4*)(W_ff2 + wb_base + 3u*D + 0));
            float4 wb3 = *((device const float4*)(W_ff2 + wb_base + 3u*D + 4));
            o0 = fma(h0, wa0.x, o0); o1 = fma(h0, wa0.y, o1); o2 = fma(h0, wa0.z, o2); o3 = fma(h0, wa0.w, o3);
            o4 = fma(h0, wb0.x, o4); o5 = fma(h0, wb0.y, o5); o6 = fma(h0, wb0.z, o6); o7 = fma(h0, wb0.w, o7);
            o0 = fma(h1, wa1.x, o0); o1 = fma(h1, wa1.y, o1); o2 = fma(h1, wa1.z, o2); o3 = fma(h1, wa1.w, o3);
            o4 = fma(h1, wb1.x, o4); o5 = fma(h1, wb1.y, o5); o6 = fma(h1, wb1.z, o6); o7 = fma(h1, wb1.w, o7);
            o0 = fma(h2, wa2.x, o0); o1 = fma(h2, wa2.y, o1); o2 = fma(h2, wa2.z, o2); o3 = fma(h2, wa2.w, o3);
            o4 = fma(h2, wb2.x, o4); o5 = fma(h2, wb2.y, o5); o6 = fma(h2, wb2.z, o6); o7 = fma(h2, wb2.w, o7);
            o0 = fma(h3, wa3.x, o0); o1 = fma(h3, wa3.y, o1); o2 = fma(h3, wa3.z, o2); o3 = fma(h3, wa3.w, o3);
            o4 = fma(h3, wb3.x, o4); o5 = fma(h3, wb3.y, o5); o6 = fma(h3, wb3.z, o6); o7 = fma(h3, wb3.w, o7);
        }
        out_acc[0] += o0; out_acc[1] += o1; out_acc[2] += o2; out_acc[3] += o3;
        out_acc[4] += o4; out_acc[5] += o5; out_acc[6] += o6; out_acc[7] += o7;
    }

    {
        uint base = s * D + l * 8u;
        y[base+0] += out_acc[0];
        y[base+1] += out_acc[1];
        y[base+2] += out_acc[2];
        y[base+3] += out_acc[3];
        y[base+4] += out_acc[4];
        y[base+5] += out_acc[5];
        y[base+6] += out_acc[6];
        y[base+7] += out_acc[7];
    }
}

transpose_2d.metal_source:
// transpose_2d: B = A^T. One TG per 64x64 tile, 256 threads/TG.
// Each thread handles a 4x4 sub-block: float4 load row, then float4 store col.
// SMEM padded by +1 to avoid bank conflicts on the transposed access.
// Uses direct device-to-device copy for the inner 4x4 block to avoid SMEM overhead.
#include <metal_stdlib>
using namespace metal;

#define TILE 64

[[max_total_threads_per_threadgroup(256)]]
kernel void transpose_2d_f32(
    device const float*  A       [[buffer(0)]],
    device       float*  B       [[buffer(1)]],
    constant     uint&   M       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    uint  lid                   [[thread_index_in_threadgroup]],
    uint  tgid                  [[threadgroup_position_in_grid]])
{
    threadgroup float tile[TILE][TILE + 1];

    const uint num_tiles_x = N / TILE;     // col-tiles in A
    const uint tx = tgid % num_tiles_x;
    const uint ty = tgid / num_tiles_x;

    const uint lx4 = lid & 15;   // 0..15  -> col group (4 floats wide)
    const uint ly  = lid >> 4;   // 0..15  -> row group (4 rows tall)

    // Load: thread (lx4,ly) reads 4 rows x float4 from A[ty*64 + ly*4 + r, tx*64 + lx4*4]
    #pragma unroll
    for (uint r = 0; r < 4; ++r) {
        const uint a_row = ty * TILE + ly * 4 + r;
        const uint a_col = tx * TILE + lx4 * 4;
        float4 v = *reinterpret_cast<const device float4*>(A + a_row * N + a_col);
        tile[lx4 * 4 + 0][ly * 4 + r] = v.x;
        tile[lx4 * 4 + 1][ly * 4 + r] = v.y;
        tile[lx4 * 4 + 2][ly * 4 + r] = v.z;
        tile[lx4 * 4 + 3][ly * 4 + r] = v.w;
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Store: B[tx*64 + ly*4 + r, ty*64 + lx4*4] = tile[ly*4 + r, lx4*4 : +4]
    #pragma unroll
    for (uint r = 0; r < 4; ++r) {
        const uint b_row = tx * TILE + ly * 4 + r;
        const uint b_col = ty * TILE + lx4 * 4;
        float4 w = *reinterpret_cast<threadgroup float4*>(&tile[ly * 4 + r][lx4 * 4]);
        *reinterpret_cast<device float4*>(B + b_row * M + b_col) = w;
    }
}

triplet_margin_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

// TG=64, float4 loads, fast::sqrt for the two final scalars.
// Fixed: use threadgroup barrier before reading r1/r2, and ensure all threads participate in simd_sum correctly.
// Changed: use a single threadgroup reduction with 2 simdgroups, then finalize in lane 0.
// Removed the problematic atomic operations that caused compilation errors.

kernel void triplet_margin_loss_f32(
    device const float*  a       [[buffer(0)]],
    device const float*  p       [[buffer(1)]],
    device const float*  n       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   D       [[buffer(4)]],
    constant     float&  margin  [[buffer(5)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;
    const uint D4 = D >> 2;
    device const float4* ar = (device const float4*)(a + row * D);
    device const float4* pr = (device const float4*)(p + row * D);
    device const float4* nr = (device const float4*)(n + row * D);
    threadgroup float r1[2], r2[2];

    float sp = 0.0f, sn = 0.0f;
    #pragma unroll
    for (uint i = tid; i < D4; i += 64u) {
        float4 av = ar[i];
        float4 dp = av - pr[i];
        float4 dn = av - nr[i];
        sp = fma(dp.x, dp.x, sp); sp = fma(dp.y, dp.y, sp);
        sp = fma(dp.z, dp.z, sp); sp = fma(dp.w, dp.w, sp);
        sn = fma(dn.x, dn.x, sn); sn = fma(dn.y, dn.y, sn);
        sn = fma(dn.z, dn.z, sn); sn = fma(dn.w, dn.w, sn);
    }

    sp = simd_sum(sp);
    sn = simd_sum(sn);
    if (lane == 0) { r1[sgid] = sp; r2[sgid] = sn; }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float vp = (lane < 2) ? r1[lane] : 0.0f;
        float vn = (lane < 2) ? r2[lane] : 0.0f;
        vp = simd_sum(vp);
        vn = simd_sum(vn);
        if (lane == 0) y[row] = fmax(fast::sqrt(vp) - fast::sqrt(vn) + margin, 0.0f);
    }
}

variance.metal_source:
// variance: per-row Var(x) = mean(x²) − mean(x)². One threadgroup per row.
// TG=256, each thread does a float4 load (covers C=1024).
#include <metal_stdlib>
using namespace metal;

kernel void variance_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid  = tid3.x;
    const uint row  = tgid.y;
    const uint sg   = tid >> 5;
    const uint lane = tid & 31;

    device const float4* row4 = (device const float4*)(x + row * C);
    float4 v = row4[tid];
    float s_local = v.x + v.y + v.z + v.w;
    float q_local = v.x*v.x + v.y*v.y + v.z*v.z + v.w*v.w;

    float sum   = simd_sum(s_local);
    float sumsq = simd_sum(q_local);

    threadgroup float tg_s[8], tg_q[8];
    if (lane == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0 && lane < 8) {
        float s  = tg_s[lane];
        float sq = tg_q[lane];
        s  += simd_shuffle_xor(s, 4);
        s  += simd_shuffle_xor(s, 2);
        s  += simd_shuffle_xor(s, 1);
        sq += simd_shuffle_xor(sq, 4);
        sq += simd_shuffle_xor(sq, 2);
        sq += simd_shuffle_xor(sq, 1);
        if (lane == 0) {
            float invC = 1.0f / float(C);
            float mean = s * invC;
            out[row] = sq * invC - mean * mean;
        }
    }
}

where.metal_source:
// where: y = cond > 0.5 ? a : b.
// Using vectorized loads/stores via float4 for better memory bandwidth utilization.
// Optimized: increased vector width to float8 for fewer memory transactions.
// Attempt: use simdgroup operations to reduce global memory traffic by having
// each simdgroup load a tile and share results via threadgroup memory.
// New approach: reduce grid size and increase per-thread work to 16 elements
// (4 float4 loads) to amortize dispatch overhead and improve cache reuse.
#include <metal_stdlib>
using namespace metal;

[[max_total_threads_per_threadgroup(1024)]]
kernel void where_f32(
    device const float*  cond      [[buffer(0)]],
    device const float*  a         [[buffer(1)]],
    device const float*  b         [[buffer(2)]],
    device       float*  y         [[buffer(3)]],
    constant     uint&   N         [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint gs = grid_size;
    uint i = tid * 16;

    // Process 16 elements per thread using 4 float4 loads for coalesced access
    for (; i + 15 < N; i += gs * 16) {
        // Load 16 floats as four float4s
        float4 c1 = *((device float4*)(cond + i));
        float4 c2 = *((device float4*)(cond + i + 4));
        float4 c3 = *((device float4*)(cond + i + 8));
        float4 c4 = *((device float4*)(cond + i + 12));

        float4 av1 = *((device float4*)(a + i));
        float4 av2 = *((device float4*)(a + i + 4));
        float4 av3 = *((device float4*)(a + i + 8));
        float4 av4 = *((device float4*)(a + i + 12));

        float4 bv1 = *((device float4*)(b + i));
        float4 bv2 = *((device float4*)(b + i + 4));
        float4 bv3 = *((device float4*)(b + i + 8));
        float4 bv4 = *((device float4*)(b + i + 12));

        // Use Metal's native select with bool4 masks
        bool4 mask1 = bool4(c1.x > 0.5f, c1.y > 0.5f, c1.z > 0.5f, c1.w > 0.5f);
        bool4 mask2 = bool4(c2.x > 0.5f, c2.y > 0.5f, c2.z > 0.5f, c2.w > 0.5f);
        bool4 mask3 = bool4(c3.x > 0.5f, c3.y > 0.5f, c3.z > 0.5f, c3.w > 0.5f);
        bool4 mask4 = bool4(c4.x > 0.5f, c4.y > 0.5f, c4.z > 0.5f, c4.w > 0.5f);

        float4 result1 = select(bv1, av1, mask1);
        float4 result2 = select(bv2, av2, mask2);
        float4 result3 = select(bv3, av3, mask3);
        float4 result4 = select(bv4, av4, mask4);

        *((device float4*)(y + i)) = result1;
        *((device float4*)(y + i + 4)) = result2;
        *((device float4*)(y + i + 8)) = result3;
        *((device float4*)(y + i + 12)) = result4;
    }

    // Remainder loop (scalar)
    for (; i < N; i += gs) {
        y[i] = cond[i] > 0.5f ? a[i] : b[i];
    }
}

conv2d_mish_mish.metal_source:
// conv2d + mish + mish fused, implicit im2col GEMM with simdgroup_matrix MMA, M4-tuned.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 32;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint NUM_SG  = SIMDS_M * SIMDS_N;  // 32
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 132

static inline float mish_f(float v) {
    float ax = fabs(v);
    float sp = fmax(v, 0.0f) + log(1.0f + exp(-ax));
    float e = exp(-2.0f * sp);
    float t = (1.0f - e) / (1.0f + e);
    return v * t;
}

kernel void conv2d_mish_mish_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   C       [[buffer(6)]],
    constant     uint&   K_out   [[buffer(7)]],
    constant     uint&   R       [[buffer(8)]],
    constant     uint&   S       [[buffer(9)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H2 = H - R + 1;
    const uint W2 = W - S + 1;
    const uint M_g = N_ * H2 * W2;
    const uint K_g = R * S * C;
    const uint SC  = S * C;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint total_tiles = num_m_tiles;

    threadgroup float scratch[BM * BN];
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;
    threadgroup float* Cs = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint c_row0 = tile * BM;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            #pragma unroll
            for (uint pa = 0; pa < (BM * BK) / TG_THREADS; ++pa) {
                const uint t = lid + pa * TG_THREADS;
                const uint a_row = t / BK;
                const uint a_col = t % BK;
                const uint m_g = c_row0 + a_row;
                const uint k_glob = k0 + a_col;
                float v = 0.0f;
                if (m_g < M_g && k_glob < K_g) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C;
                    const uint c  = rem - ss * C;
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    const uint hi = h2 + rr;
                    const uint wi = w2 + ss;
                    v = x[((n_idx * H + hi) * W + wi) * C + c];
                }
                As[a_row * LDA + a_col] = v;
            }
            #pragma unroll
            for (uint p = 0; p < (BN * BK) / TG_THREADS; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t % BK;
                const uint k_glob = k0 + b_row;
                const uint n_col = b_col;
                float v = 0.0f;
                if (k_glob < K_g && n_col < K_out) {
                    v = w[n_col * K_g + k_glob];
                }
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r = (lid / 32u) + rs * 32u;
                const uint cq = lid % 32u;
                const uint c = cq * 4u;
                const uint m_g = c_row0 + r;
                if (m_g < M_g) {
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                    v.x = mish_f(mish_f(v.x));
                    v.y = mish_f(mish_f(v.y));
                    v.z = mish_f(mish_f(v.z));
                    v.w = mish_f(mish_f(v.w));
                    *reinterpret_cast<device float4*>(&y[((n_idx * H2 + h2) * W2 + w2) * K_out + c]) = v;
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv3d_softmax_pool.metal_source:
// Fused conv3d -> softmax(C) -> maxpool2x2x2 -> maxpool2x2x2.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 32;
constant constexpr uint SIMDS_M = 2, SIMDS_N = 4;
constant constexpr uint SM = BM / SIMDS_M;           // 32
constant constexpr uint SN = BN / SIMDS_N;           // 16
constant constexpr uint MMA_M = SM / 8;              // 4
constant constexpr uint MMA_N = SN / 8;              // 2
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;              // 36
constant constexpr uint LDB = BN + PAD;              // 68

kernel void conv3d_softmax_pool_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   D       [[buffer(5)]],
    constant     uint&   H       [[buffer(6)]],
    constant     uint&   W       [[buffer(7)]],
    constant     uint&   K_out   [[buffer(8)]],
    constant     uint&   R       [[buffer(9)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint D_out = 7, H_out = 7, W_out = 7;
    const uint blocks_per_n = D_out * H_out * W_out;
    const uint total_blocks = N_ * blocks_per_n;
    const uint RC = R * C;
    const uint RRC = R * RC;
    const uint K_g = R * RRC;  // 864

    // Memory layout: separate scratch for GEMM and softmax/pool
    // GEMM phase:    As [BM*LDA] then Bs [BK*LDB]
    // Post-GEMM:     Cs [BM*BN]
    // Softmax/pool:  row_m [BM], row_Z [BM]
    threadgroup float scratch[BM * LDA + BK * LDB];   // 4480 floats
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;
    threadgroup float* Cs = scratch;
    threadgroup float row_m[BM];
    threadgroup float row_Z[BM];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint blk = tg_id; blk < total_blocks; blk += n_tg) {
        uint q = blk;
        const uint w4 = q % W_out; q /= W_out;
        const uint h4 = q % H_out; q /= H_out;
        const uint d4 = q % D_out;
        const uint n  = q / D_out;
        const uint d0 = d4 * 4;
        const uint h0 = h4 * 4;
        const uint w0 = w4 * 4;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;   // 27 with BK=32

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;
            const uint kt_idx = k0 >> 5;
            const uint rw = kt_idx % R;
            const uint rh = (kt_idx / R) % R;
            const uint rd = kt_idx / (R * R);

            // Load A: BM*BK = 64*32 = 2048 floats via 512 float4 reads (256 thr × 2 iters)
            {
                const device float4* x4 = reinterpret_cast<const device float4*>(x);
                #pragma unroll
                for (uint it = 0; it < 2u; ++it) {
                    const uint pos = it * 256u + lid;
                    const uint a_row = pos >> 3;
                    const uint chunk = pos & 7u;
                    const uint a_col = chunk * 4u;
                    const uint dd = a_row >> 4;
                    const uint hh = (a_row >> 2) & 3u;
                    const uint ww = a_row & 3u;
                    const uint di = d0 + dd + rd;
                    const uint hi = h0 + hh + rh;
                    const uint wi = w0 + ww + rw;
                    const uint addr = (((n * D + di) * H + hi) * W + wi) * C + a_col;
                    float4 v = x4[addr >> 2];
                    As[a_row * LDA + a_col + 0u] = v.x;
                    As[a_row * LDA + a_col + 1u] = v.y;
                    As[a_row * LDA + a_col + 2u] = v.z;
                    As[a_row * LDA + a_col + 3u] = v.w;
                }
            }
            // Load B: BK*BN = 32*64 = 2048 floats via 512 float4 reads (256 thr × 2 iters)
            {
                const device float4* w4 = reinterpret_cast<const device float4*>(w);
                #pragma unroll
                for (uint it = 0; it < 2u; ++it) {
                    const uint pos = it * 256u + lid;
                    const uint b_col = pos >> 3;
                    const uint chunk = pos & 7u;
                    const uint k_glob = k0 + chunk * 4u;
                    float4 v = w4[(b_col * K_g + k_glob) >> 2];
                    Bs[(chunk * 4u + 0u) * LDB + b_col] = v.x;
                    Bs[(chunk * 4u + 1u) * LDB + b_col] = v.y;
                    Bs[(chunk * 4u + 2u) * LDB + b_col] = v.z;
                    Bs[(chunk * 4u + 3u) * LDB + b_col] = v.w;
                }
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Store accumulator to Cs (row=voxel, col=channel)
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Per-row softmax stats over the 64 channels
        // 256 threads, 64 rows → 4 thr/row. Each simd handles 8 rows, lane reads 2 channels
        {
            const uint lane = lid & 31u;
            #pragma unroll
            for (uint rr = 0; rr < 8u; ++rr) {
                const uint row = sgid * 8u + rr;
                float c0 = Cs[row * BN + lane * 2u + 0u];
                float c1 = Cs[row * BN + lane * 2u + 1u];
                float lm = max(c0, c1);
                float m = simd_max(lm);
                float e0 = exp(c0 - m);
                float e1 = exp(c1 - m);
                float ls = e0 + e1;
                float Z = simd_sum(ls);
                if (lane == 0) {
                    row_m[row] = m;
                    row_Z[row] = 1.0f / Z;
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Softmax + reduce-max across 64 voxels for each of 64 channels
        // 256 threads, 64 channels → 4 thr/ch. Each thread handles 16 rows then
        // reduces with two simd_shuffle_xor calls
        {
            const uint ch = lid >> 2;
            const uint slot = lid & 3u;
            float best = -INFINITY;
            #pragma unroll
            for (uint r = 0; r < 16u; ++r) {
                uint row = slot * 16u + r;
                float cv = Cs[row * BN + ch];
                float v = exp(cv - row_m[row]) * row_Z[row];
                best = max(best, v);
            }
            best = max(best, simd_shuffle_xor(best, 1u));
            best = max(best, simd_shuffle_xor(best, 2u));
            if (slot == 0u) {
                const uint y_idx = (((n * D_out + d4) * H_out + h4) * W_out + w4) * K_out + ch;
                y[y_idx] = best;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv_transpose3d_norm_pool_gelu.metal_source:
#include <metal_stdlib>
using namespace metal;

static inline float gelu_tanh(float x) {
    const float kBeta  = 0.7978845608028654f;
    const float kAlpha = 0.044715f;
    float x3 = x * x * x;
    float u = kBeta * (x + kAlpha * x3);
    u = clamp(u, -10.0f, 10.0f);
    return 0.5f * x * (1.0f + tanh(u));
}

// One threadgroup per (n,d2,h2,w2). 32 threads = 1 simdgroup, each = 1 channel.
// Loads a 4x4x4x16 input patch into threadgroup memory (with zero padding for
// out-of-bounds), then performs 8 conv-transpose evaluations + LayerNorm +
// AvgPool + GELU.

kernel void conv_transpose3d_norm_pool_gelu_f32(
    device const float* x        [[buffer(0)]],
    device const float* w        [[buffer(1)]],
    device const float* sum_term [[buffer(2)]],
    device       float* y        [[buffer(3)]],
    constant     uint& N         [[buffer(4)]],
    constant     uint& C_in      [[buffer(5)]],
    constant     uint& D         [[buffer(6)]],
    constant     uint& H         [[buffer(7)]],
    constant     uint& W         [[buffer(8)]],
    constant     uint& K         [[buffer(9)]],
    constant     uint& R         [[buffer(10)]],
    constant     float& eps      [[buffer(11)]],
    uint3 tgid [[threadgroup_position_in_grid]],
    uint3 lid3 [[thread_position_in_threadgroup]])
{
    const uint D2 = 5, H2 = 5, W2 = 5;
    const uint Ci = 16, Rc = 3, Dc = 8, Hc = 8, Wc = 8, Kc = 32;

    uint flat = tgid.x;
    uint w2 = flat % W2; flat /= W2;
    uint h2 = flat % H2; flat /= H2;
    uint d2 = flat % D2; uint n = flat / D2;

    uint kk = lid3.x;

    // The input patch we need: d_in = d_full - rd, where d_full in
    // {2*d2, 2*d2+1} and rd in {0,1,2}. So d_in in {2*d2-2, ..., 2*d2+1} -> 4 values.
    // Patch origin in input coords:
    int d_o = int(d2) * 2 - 2;
    int h_o = int(h2) * 2 - 2;
    int w_o = int(w2) * 2 - 2;

    // 4*4*4*16 = 1024 floats; loaded co-operatively by 32 threads (32 each).
    threadgroup float xtile[4 * 4 * 4 * 16];

    // Each thread loads 32 floats.
    for (uint i = 0; i < 32; ++i) {
        uint idx = kk * 32 + i;                  // 0..1023
        uint c  = idx & 15u;
        uint t  = idx >> 4;                      // 0..63 -> (dd,hh,ww) over 4x4x4
        uint ww = t & 3u;
        uint hh = (t >> 2) & 3u;
        uint dd = (t >> 4) & 3u;
        int d_in = d_o + int(dd);
        int h_in = h_o + int(hh);
        int w_in = w_o + int(ww);
        float v = 0.0f;
        if (d_in >= 0 && d_in < int(Dc) &&
            h_in >= 0 && h_in < int(Hc) &&
            w_in >= 0 && w_in < int(Wc)) {
            uint x_base = (((n * Dc + uint(d_in)) * Hc + uint(h_in)) * Wc + uint(w_in)) * Ci + c;
            v = x[x_base];
        }
        xtile[idx] = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float bias = sum_term[kk];
    uint wk_base = kk * (Rc * Rc * Rc * Ci);

    float pool_acc = 0.0f;

    // The 8 pool sub-voxels.
    for (uint pd = 0; pd < 2; ++pd) {
        for (uint ph = 0; ph < 2; ++ph) {
            for (uint pw = 0; pw < 2; ++pw) {
                float s = bias;
                // d_full = 2*d2 + pd; d_in = d_full - rd = 2*d2 + pd - rd
                // Within the tile, dd = d_in - d_o = pd - rd + 2. For rd=0..2 -> dd=pd+2,pd+1,pd.
                // So dd ranges {pd, pd+1, pd+2}. Similar for hh,ww.
                for (uint rd = 0; rd < 3; ++rd) {
                    uint dd = pd + 2 - rd;       // always in [0,3]
                    for (uint rh = 0; rh < 3; ++rh) {
                        uint hh = ph + 2 - rh;
                        for (uint rw = 0; rw < 3; ++rw) {
                            uint ww = pw + 2 - rw;
                            uint tile_base = ((dd * 4 + hh) * 4 + ww) * Ci;
                            uint w_base = wk_base + ((rd * Rc + rh) * Rc + rw) * Ci;
                            float4 xv0 = *((threadgroup float4*)(xtile + tile_base + 0));
                            float4 xv1 = *((threadgroup float4*)(xtile + tile_base + 4));
                            float4 xv2 = *((threadgroup float4*)(xtile + tile_base + 8));
                            float4 xv3 = *((threadgroup float4*)(xtile + tile_base + 12));
                            float4 wv0 = *((device const float4*)(w + w_base + 0));
                            float4 wv1 = *((device const float4*)(w + w_base + 4));
                            float4 wv2 = *((device const float4*)(w + w_base + 8));
                            float4 wv3 = *((device const float4*)(w + w_base + 12));
                            s += dot(xv0, wv0) + dot(xv1, wv1) + dot(xv2, wv2) + dot(xv3, wv3);
                        }
                    }
                }
                float sum   = simd_sum(s);
                float sumsq = simd_sum(s * s);
                float mean  = sum * (1.0f / 32.0f);
                float var   = sumsq * (1.0f / 32.0f) - mean * mean;
                float inv   = rsqrt(max(var, 0.0f) + eps);
                pool_acc += (s - mean) * inv;
            }
        }
    }

    float avg = pool_acc * (1.0f / 8.0f);
    float out = gelu_tanh(avg);
    uint y_idx = (((n * D2 + d2) * H2 + h2) * W2 + w2) * Kc + kk;
    y[y_idx] = out;
}

hinge_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void hinge_loss_f32(
    device const float*  pred      [[buffer(0)]],
    device const float*  target    [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        y[i] = fmax(1.0f - pred[i] * target[i], 0.0f);
    }
}

scaled_dot_product.metal_source:
// scaled_dot_product: softmax(Q @ K^T / sqrt(D)) @ V. One TG per query row.
#include <metal_stdlib>
using namespace metal;

constant constexpr uint TG = 128;
constant constexpr uint MAX_M = 128;

kernel void scaled_dot_product_f32(
    device const float* Q   [[buffer(0)]],
    device const float* K   [[buffer(1)]],
    device const float* V   [[buffer(2)]],
    device       float* O   [[buffer(3)]],
    constant     uint&  M   [[buffer(4)]],
    constant     uint&  D   [[buffer(5)]],
    uint  tgid              [[threadgroup_position_in_grid]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float scores[MAX_M];
    threadgroup float reduce_buf[TG];

    const uint row = tgid;
    if (row >= M) return;
    const float scale = rsqrt((float)D);

    // 1) scores[j] = (Q[row] . K[j]) * scale, for j in [0, M)
    for (uint j = lid; j < M; j += TG) {
        float acc = 0.0f;
        for (uint k = 0; k < D; ++k) {
            acc += Q[row * D + k] * K[j * D + k];
        }
        scores[j] = acc * scale;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // 2) max reduction
    float local_max = -INFINITY;
    for (uint j = lid; j < M; j += TG) local_max = max(local_max, scores[j]);
    reduce_buf[lid] = local_max;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    for (uint stride = TG / 2; stride > 0; stride >>= 1) {
        if (lid < stride) reduce_buf[lid] = max(reduce_buf[lid], reduce_buf[lid + stride]);
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
    float row_max = reduce_buf[0];

    // 3) exponentiate and sum
    for (uint j = lid; j < M; j += TG) {
        scores[j] = exp(scores[j] - row_max);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float local_sum = 0.0f;
    for (uint j = lid; j < M; j += TG) local_sum += scores[j];
    reduce_buf[lid] = local_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    for (uint stride = TG / 2; stride > 0; stride >>= 1) {
        if (lid < stride) reduce_buf[lid] = reduce_buf[lid] + reduce_buf[lid + stride];
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
    float row_sum = reduce_buf[0];
    float inv_sum = 1.0f / row_sum;

    // 4) normalize and multiply by V: O[row, d] = sum_j scores[j] * V[j, d]
    for (uint d = lid; d < D; d += TG) {
        float acc = 0.0f;
        for (uint j = 0; j < M; ++j) {
            acc += scores[j] * V[j * D + d];
        }
        O[row * D + d] = acc * inv_sum;
    }
}

conv_transpose2d_sub_tanh.metal_source:
// conv_transpose2d_sub_tanh: fused 3x3 transposed conv (NHWC, stride=2)
// + sub_val + stable tanh, via implicit-im2col GEMM with simdgroup_matrix MMA.
//
// Shapes: x (N=8, H=32, W=32, C=64) ; w (K_out=128, R=3, S=3, C=64) ;
//         y (N, H_out=65, W_out=65, K_out=128) ; stride=2.
//
// GEMM mapping: M = N*H_out*W_out ; N_dim = K_out ; K = R*S*C.
// x[m, k] := x[n, h_in, w_in, c] iff (h_out-r) and (w_out-s) are both even and
//            input coord is in-range; else 0.
//
// Tile: BM=64, BN=64, BK=16. TG=512 threads = 16 simdgroups (SIMDS_M=4, SIMDS_N=4).
// One m-tile per TG iteration; TG strides over all m-tiles.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 4
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 512;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 68

kernel void conv_transpose2d_sub_tanh_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C_in    [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   K_out   [[buffer(7)]],
    constant     uint&   R       [[buffer(8)]],
    constant     uint&   stride  [[buffer(9)]],
    constant     float&  sub_val [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H_out = (H - 1) * stride + R;
    const uint W_out = (W - 1) * stride + R;
    const uint HW_out = H_out * W_out;
    const uint M_g = N_ * HW_out;
    const uint S   = R;
    const uint SC  = S * C_in;
    const uint K_g = R * SC;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_n_tiles = (K_out + BN - 1) / BN;
    const uint num_tiles = num_m_tiles * num_n_tiles;

    // scratch usage:
    //  As: BM * LDA = 64 * 20 = 1280 floats
    //  Bs: BK * LDB = 16 * 68 = 1088 floats
    //  Cs (reused after MMA): BM * BN = 64 * 64 = 4096 floats
    // Max = 4096 floats = 16 KB. Use a union via shared base.
    threadgroup float scratch[BM * BN];
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;
    threadgroup float* Cs = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < num_tiles; tile += n_tg) {
        const uint mt = tile / num_n_tiles;
        const uint nt = tile - mt * num_n_tiles;
        const uint c_row0 = mt * BM;
        const uint c_col0 = nt * BN;

        simdgroup_matrix<float, 8, 8> C[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            // Load A (BM x BK = 1024 elements, 2 per thread).
            #pragma unroll
            for (uint p = 0; p < 2; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint a_row = t / BK;
                const uint a_col = t & (BK - 1);
                const uint k_glob = k0 + a_col;
                float v0 = 0.0f;
                if (k_glob < K_g && a_row < BM) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C_in;
                    const uint c  = rem - ss * C_in;
                    const uint mg = c_row0 + a_row;
                    if (mg < M_g) {
                        const uint n_idx = mg / HW_out;
                        const uint hw    = mg - n_idx * HW_out;
                        const uint h_out = hw / W_out;
                        const uint w_out = hw - h_out * W_out;
                        const int hd = int(h_out) - int(rr);
                        const int wd = int(w_out) - int(ss);
                        if (hd >= 0 && wd >= 0 && ((hd | wd) & 1) == 0) {
                            const uint h_in = uint(hd) >> 1;
                            const uint w_in = uint(wd) >> 1;
                            if (h_in < H && w_in < W) {
                                v0 = x[((n_idx * H + h_in) * W + w_in) * C_in + c];
                            }
                        }
                    }
                }
                As[a_row * LDA + a_col] = v0;
            }

            // Load B (BK x BN = 1024 elements, 2 per thread).
            // w stored (K_out, R, S, C_in) contiguous; B[k_g, kk] = w[c_col0+kk, k_g].
            #pragma unroll
            for (uint p = 0; p < 2; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t & (BK - 1);
                const uint kg = k0 + b_row;
                const uint kk = c_col0 + b_col;
                float v = 0.0f;
                if (kg < K_g && kk < K_out) v = w[kk * K_g + kg];
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C[i][j], A_blk[i], B_blk[j], C[i][j]);
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Store C to threadgroup, then apply sub + tanh and write to y.
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // BM*BN = 4096 elements / 512 threads = 8 elements per thread = 2 float4 per thread.
        #pragma unroll
        for (uint p = 0; p < 2; ++p) {
            const uint t = lid + p * TG_THREADS;        // 0..1023
            const uint r_local = t / (BN / 4u);          // BN/4=16 ; r_local 0..63
            const uint cq = t & ((BN / 4u) - 1u);
            const uint c = cq * 4u;
            const uint m_g = c_row0 + r_local;
            const uint k_g = c_col0 + c;
            if (m_g < M_g && k_g < K_out) {
                float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r_local * BN + c]);
                v -= float4(sub_val);
                v = clamp(v, float4(-15.0f), float4(15.0f));
                v = tanh(v);
                const uint n_idx = m_g / HW_out;
                const uint hw    = m_g - n_idx * HW_out;
                const uint h_out = hw / W_out;
                const uint w_out = hw - h_out * W_out;
                *reinterpret_cast<device float4*>(&y[((n_idx * H_out + h_out) * W_out + w_out) * K_out + k_g]) = v;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

mha_attention.metal_source:
// mha_attention — fused MHA forward (single batch). Adapted from transformer_block pattern.
// Shape: x=(S,D), wq/wk/wv/wo each (D,D). S=32, D=128, H=4, Dh=32. scale = 1/sqrt(32).
#include <metal_stdlib>
#include <metal_simdgroup>
using namespace metal;

#define S  32
#define D  128
#define H  4
#define DH 32
#define TG 1024

kernel void mha_attention_f32(
    device const float* x  [[buffer(0)]],
    device const float* wq [[buffer(1)]],
    device const float* wk [[buffer(2)]],
    device const float* wv [[buffer(3)]],
    device const float* wo [[buffer(4)]],
    device       float* y  [[buffer(5)]],
    constant uint&  Sr  [[buffer(6)]],
    constant uint&  Dr  [[buffer(7)]],
    constant uint&  Hr  [[buffer(8)]],
    constant uint&  DHr [[buffer(9)]],
    constant float& scale [[buffer(10)]],
    uint3 tid [[thread_position_in_threadgroup]])
{
    const uint t = tid.x;

    threadgroup float pool[3072];                       // 12 KB
    threadgroup float* Qh = pool;                       // S*DH = 1024
    threadgroup float* Kh = pool + S*DH;                // 1024
    threadgroup float* Vh = pool + 2*S*DH;              // 1024

    for (uint i = t; i < S*D; i += TG) y[i] = 0.0f;
    threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);

    for (uint h = 0; h < H; ++h) {
        // QKV projection: each thread computes one (s, dh) pair
        for (uint idx = t; idx < S*DH; idx += TG) {
            uint s  = idx / DH;
            uint dh = idx % DH;
            uint off = s * D;
            float qa = 0, ka = 0, va = 0;
            for (uint d = 0; d < D; ++d) {
                float xv = x[off + d];
                qa += xv * wq[d*D + h*DH + dh];
                ka += xv * wk[d*D + h*DH + dh];
                va += xv * wv[d*D + h*DH + dh];
            }
            Qh[idx] = qa; Kh[idx] = ka; Vh[idx] = va;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Q@K^T: each thread computes one (sq, kt) pair
        for (uint idx = t; idx < S*S; idx += TG) {
            uint sq = idx / S;
            uint kt = idx % S;
            float dot = 0;
            for (uint dh = 0; dh < DH; ++dh) dot += Qh[sq*DH + dh] * Kh[kt*DH + dh];
            Qh[idx] = dot * scale;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Softmax: each thread handles one row, using simd_sum for reduction
        if (t < S) {
            threadgroup float* row = Qh + t * S;
            // Find max using simd_max across simdgroup
            float m = -INFINITY;
            for (uint i = 0; i < S; ++i) m = max(m, row[i]);
            // Compute sum of exps using simd_sum
            float sum = 0;
            for (uint i = 0; i < S; ++i) {
                float e = exp(row[i] - m);
                row[i] = e;
                sum += e;
            }
            float inv = 1.0f / sum;
            for (uint i = 0; i < S; ++i) row[i] *= inv;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Attn @ V: each thread computes one (sq, dh) pair
        for (uint idx = t; idx < S*DH; idx += TG) {
            uint sq = idx / DH;
            uint dh = idx % DH;
            float acc = 0;
            for (uint kt = 0; kt < S; ++kt) acc += Qh[sq*S + kt] * Vh[kt*DH + dh];
            Qh[idx] = acc;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Output projection: each thread computes one (sr, dout) pair
        for (uint idx = t; idx < S*D; idx += TG) {
            uint sr = idx / D;
            uint dout = idx % D;
            float acc = 0;
            for (uint dh = 0; dh < DH; ++dh) acc += Qh[sr*DH + dh] * wo[(h*DH + dh)*D + dout];
            y[idx] += acc;
        }
        threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
    }
}

silu_residual.metal_source:
// silu_residual: y = x + silu(a)
#include <metal_stdlib>
using namespace metal;

kernel void silu_residual_f32(
    device const float* x [[buffer(0)]],
    device const float* a [[buffer(1)]],
    device       float* y [[buffer(2)]],
    constant uint& N      [[buffer(3)]],
    uint tid [[thread_position_in_grid]])
{
    if (tid >= N) return;
    float xv = x[tid], av = a[tid];
    y[tid] = xv + av * (1.0f / (1.0f + exp(-av)));
}

gelu_residual.metal_source:
// gelu_residual: y = x + gelu(a) using tanh approximation
#include <metal_stdlib>
using namespace metal;

kernel void gelu_residual_f32(
    device const float* x [[buffer(0)]],
    device const float* a [[buffer(1)]],
    device       float* y [[buffer(2)]],
    constant uint& N      [[buffer(3)]],
    uint tid [[thread_position_in_grid]])
{
    if (tid >= N) return;
    float xv = x[tid], av = a[tid];
    float g = 0.5f * av * (1.0f + tanh(0.7978845608f * (av + 0.044715f * av*av*av)));
    y[tid] = xv + g;
}

add_silu.metal_source:
// add_silu: y = silu(x + a)
#include <metal_stdlib>
using namespace metal;

kernel void add_silu_f32(
    device const float* x [[buffer(0)]],
    device const float* a [[buffer(1)]],
    device       float* y [[buffer(2)]],
    constant uint& N      [[buffer(3)]],
    uint tid [[thread_position_in_grid]])
{
    if (tid >= N) return;
    float s = x[tid] + a[tid];
