conv2d_mish_mish.metal_source:
// conv2d + mish + mish fused, implicit im2col GEMM with simdgroup_matrix MMA, M4-tuned.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 32;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint NUM_SG  = SIMDS_M * SIMDS_N;  // 32
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 132

static inline float mish_f(float v) {
    float ax = fabs(v);
    float sp = fmax(v, 0.0f) + log(1.0f + exp(-ax));
    float e = exp(-2.0f * sp);
    float t = (1.0f - e) / (1.0f + e);
    return v * t;
}

kernel void conv2d_mish_mish_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   C       [[buffer(6)]],
    constant     uint&   K_out   [[buffer(7)]],
    constant     uint&   R       [[buffer(8)]],
    constant     uint&   S       [[buffer(9)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H2 = H - R + 1;
    const uint W2 = W - S + 1;
    const uint M_g = N_ * H2 * W2;
    const uint K_g = R * S * C;
    const uint SC  = S * C;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint total_tiles = num_m_tiles;

    threadgroup float scratch[BM * BN];
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;
    threadgroup float* Cs = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint c_row0 = tile * BM;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            #pragma unroll
            for (uint pa = 0; pa < (BM * BK) / TG_THREADS; ++pa) {
                const uint t = lid + pa * TG_THREADS;
                const uint a_row = t / BK;
                const uint a_col = t % BK;
                const uint m_g = c_row0 + a_row;
                const uint k_glob = k0 + a_col;
                float v = 0.0f;
                if (m_g < M_g && k_glob < K_g) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C;
                    const uint c  = rem - ss * C;
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    const uint hi = h2 + rr;
                    const uint wi = w2 + ss;
                    v = x[((n_idx * H + hi) * W + wi) * C + c];
                }
                As[a_row * LDA + a_col] = v;
            }
            #pragma unroll
            for (uint p = 0; p < (BN * BK) / TG_THREADS; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t % BK;
                const uint k_glob = k0 + b_row;
                const uint n_col = b_col;
                float v = 0.0f;
                if (k_glob < K_g && n_col < K_out) {
                    v = w[n_col * K_g + k_glob];
                }
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        {
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r = (lid / 32u) + rs * 32u;
                const uint cq = lid % 32u;
                const uint c = cq * 4u;
                const uint m_g = c_row0 + r;
                if (m_g < M_g) {
                    const uint n_idx = m_g / (H2 * W2);
                    const uint hw = m_g - n_idx * (H2 * W2);
                    const uint h2 = hw / W2;
                    const uint w2 = hw - h2 * W2;
                    float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                    v.x = mish_f(mish_f(v.x));
                    v.y = mish_f(mish_f(v.y));
                    v.z = mish_f(mish_f(v.z));
                    v.w = mish_f(mish_f(v.w));
                    *reinterpret_cast<device float4*>(&y[((n_idx * H2 + h2) * W2 + w2) * K_out + c]) = v;
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv2d_relu_bias.metal_source:
// conv2d_relu_bias: fused 3x3 conv (NHWC) + bias + ReLU, NHWC f32.
// Implicit-im2col GEMM via simdgroup_matrix MMA. Each TG processes 2 consecutive
// m-tiles, sharing per-kt B (weight) load → halves B bandwidth and reuses each
// loaded B-block across two simdgroup_matrix accumulators.
// Grid-agnostic: each TG strides over its share of m-tile groups via tg_id.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 16;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 132

kernel void conv2d_relu_bias_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device const float*  b       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   N_      [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   C       [[buffer(7)]],
    constant     uint&   K_out   [[buffer(8)]],
    constant     uint&   R       [[buffer(9)]],
    constant     uint&   S       [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H2 = (H - R) + 1;
    const uint W2 = (W - S) + 1;
    const uint HW2 = H2 * W2;
    const uint M_g = N_ * HW2;
    const uint K_g = R * S * C;
    const uint SC  = S * C;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_groups = (num_m_tiles + 1u) / 2u;  // pairs of 2

    // Scratch (8192 floats = 32KB):
    //   As0: 0    .. 1280 (BM*LDA)
    //   As1: 1280 .. 2560
    //   Bs:  2560 .. 4672 (BK*LDB = 2112)
    //   Cs:  0    .. 8192 (overlaps after MMA barrier)
    threadgroup float scratch[BM * BN];
    threadgroup float* As0 = scratch;
    threadgroup float* As1 = scratch + BM * LDA;
    threadgroup float* Bs  = scratch + 2u * BM * LDA;
    threadgroup float* Cs  = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint grp = tg_id; grp < num_groups; grp += n_tg) {
        const uint tile0 = grp * 2u;
        const uint c_row0_0 = tile0 * BM;
        const uint c_row0_1 = (tile0 + 1u) * BM;
        const bool has1 = (tile0 + 1u) < num_m_tiles;

        simdgroup_matrix<float, 8, 8> C0[MMA_M][MMA_N];
        simdgroup_matrix<float, 8, 8> C1[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) {
                C0[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
                C1[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
            }

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            // Load A0, A1 (BM x BK each): 64*16 = 1024 → 1/thread each
            {
                const uint a_row = lid / BK;
                const uint a_col = lid & (BK - 1);
                const uint k_glob = k0 + a_col;
                float v0 = 0.0f, v1 = 0.0f;
                if (k_glob < K_g) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C;
                    const uint c  = rem - ss * C;
                    {
                        const uint mg = c_row0_0 + a_row;
                        if (mg < M_g) {
                            const uint n_idx = mg / HW2;
                            const uint hw    = mg - n_idx * HW2;
                            const uint h2    = hw / W2;
                            const uint w2    = hw - h2 * W2;
                            v0 = x[((n_idx * H + h2 + rr) * W + w2 + ss) * C + c];
                        }
                    }
                    if (has1) {
                        const uint mg = c_row0_1 + a_row;
                        if (mg < M_g) {
                            const uint n_idx = mg / HW2;
                            const uint hw    = mg - n_idx * HW2;
                            const uint h2    = hw / W2;
                            const uint w2    = hw - h2 * W2;
                            v1 = x[((n_idx * H + h2 + rr) * W + w2 + ss) * C + c];
                        }
                    }
                }
                As0[a_row * LDA + a_col] = v0;
                As1[a_row * LDA + a_col] = v1;
            }

            // Load B (BK x BN): 16*128 = 2048 → 2/thread
            #pragma unroll
            for (uint p = 0; p < 2; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t & (BK - 1);
                const uint kg = k0 + b_row;
                float v = 0.0f;
                if (kg < K_g) v = w[b_col * K_g + kg];
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            // MMA: each kc step loads B once, both A blocks, MMA both tiles.
            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A0_blk[MMA_M], A1_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i) {
                    simdgroup_load(A0_blk[i], &As0[(sm * SM + i * 8u) * LDA + kc], LDA);
                    simdgroup_load(A1_blk[i], &As1[(sm * SM + i * 8u) * LDA + kc], LDA);
                }
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j) {
                        simdgroup_multiply_accumulate(C0[i][j], A0_blk[i], B_blk[j], C0[i][j]);
                        simdgroup_multiply_accumulate(C1[i][j], A1_blk[i], B_blk[j], C1[i][j]);
                    }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Epilogue tile 0.
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C0[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);
        #pragma unroll
        for (uint rs = 0; rs < 2; ++rs) {
            const uint r = (lid / 32u) + rs * 32u;
            const uint cq = lid & 31u;
            const uint c = cq * 4u;
            const uint m_g = c_row0_0 + r;
            if (m_g < M_g) {
                float4 v  = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                float4 bv = *reinterpret_cast<device const float4*>(&b[c]);
                v += bv;
                v = fmax(v, float4(0.0f));
                const uint n_idx = m_g / HW2;
                const uint hw    = m_g - n_idx * HW2;
                const uint h2    = hw / W2;
                const uint w2    = hw - h2 * W2;
                *reinterpret_cast<device float4*>(&y[((n_idx * H2 + h2) * W2 + w2) * K_out + c]) = v;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Epilogue tile 1.
        if (has1) {
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_store(C1[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
            threadgroup_barrier(mem_flags::mem_threadgroup);
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r = (lid / 32u) + rs * 32u;
                const uint cq = lid & 31u;
                const uint c = cq * 4u;
                const uint m_g = c_row0_1 + r;
                if (m_g < M_g) {
                    float4 v  = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                    float4 bv = *reinterpret_cast<device const float4*>(&b[c]);
                    v += bv;
                    v = fmax(v, float4(0.0f));
                    const uint n_idx = m_g / HW2;
                    const uint hw    = m_g - n_idx * HW2;
                    const uint h2    = hw / W2;
                    const uint w2    = hw - h2 * W2;
                    *reinterpret_cast<device float4*>(&y[((n_idx * H2 + h2) * W2 + w2) * K_out + c]) = v;
                }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }
    }
}

conv3d_div_pool_sum.metal_source:
// Single-threadgroup design (1024 threads = 32 simdgroups).
// Each SG handles k=sg and k=sg+32 over all (n,d2,h2,w2) tiles.
// Per tile: each lane reads its 27 patch elements DIRECTLY from device (no tg load),
// computes 27 FMAs against pre-cached weights, simd_sum, max(k0,k1), then
// cross-SG max via tg mem.
//
// Key optimizations vs prior version:
//   - Eliminated threadgroup patch staging (no patch[864] tg buffer, no patch-load barrier).
//   - Each lane streams its strided slice of the input patch directly into regs.
//   - Input layout: x[n,d,h,w,c], lane reads c=lane%32, j indexes (rd,rh,rw,cvec) in
//     the order matching the prior patch[lane + 32*j] mapping:
//       index i = lane + 32*j, with j∈[0,27)
//       spatial = i>>3 = (lane>>3) + 4*j  (since lane = 32 = 8*4? no: i>>3 across i)
//   - Let me redo: i = lane + 32*j. spatial = i / 8. cvec = i & 7. So as j increments,
//     spatial advances by 4. We need per-lane: list of (rd,rh,rw,cvec) for j=0..26.
//     Lane-dependent path — precompute per-lane (rd_base,rh_base,rw_base,cvec_base) and step.
//   - Simpler: compute (rd,rh,rw,cvec) at runtime per j (cheap).
#include <metal_stdlib>
using namespace metal;

kernel void conv3d_div_pool_sum_f32(
    device const float* x [[buffer(0)]],
    device const float* w [[buffer(1)]],
    device       float* y [[buffer(2)]],
    constant     uint& N  [[buffer(3)]],
    constant     uint& C  [[buffer(4)]],
    constant     uint& D  [[buffer(5)]],
    constant     uint& H  [[buffer(6)]],
    constant     uint& W  [[buffer(7)]],
    constant     uint& K  [[buffer(8)]],
    constant     uint& R  [[buffer(9)]],
    constant     float& div_val  [[buffer(10)]],
    constant     float& bias_val [[buffer(11)]],
    uint tid [[thread_index_in_threadgroup]],
    uint sg  [[simdgroup_index_in_threadgroup]],
    uint lane[[thread_index_in_simdgroup]])
{
    constexpr uint Cc=32, Rc=3, Dc=32, Hc=32, Wc=32, Nc=4;
    constexpr uint D2=Dc-Rc+1, H2=Hc-Rc+1, W2=Wc-Rc+1;
    constexpr uint VOL = D2*H2*W2;
    constexpr uint PATCH = Cc*Rc*Rc*Rc;      // 864
    constexpr uint TG = 1024;
    constexpr uint NSG = TG / 32;            // 32

    constexpr uint TPB = 10;  // tiles per batch between barriers
    threadgroup float sgmax_buf[2][TPB][NSG];

    const float final_scale = (1.0f / div_val) / float(VOL);

    // Preload weight slices for k0=sg, k1=sg+32 into registers.
    float wreg0[27];
    float wreg1[27];
    {
        const device float* wk0 = w + (uint)sg          * PATCH;
        const device float* wk1 = w + (uint)(sg + 32u)  * PATCH;
        #pragma unroll
        for (uint j = 0; j < 27; ++j) {
            uint off = lane + 32u*j;
            wreg0[j] = wk0[off];
            wreg1[j] = wk1[off];
        }
    }

    // Precompute per-lane (rd,rh,rw,cvec_off) for each j=0..26.
    // i = lane + 32*j. spatial = i/8 (0..107). cvec = i & 7 (which float4 within C=32).
    // spatial = rd*9 + rh*3 + rw. Each spatial position has 8 vec4s (32 floats / 4).
    // But here we want a single float per lane (not vec4): the patch[i] is a SCALAR.
    // patch was loaded as p4[i] = x4[x_idx + cvec], so patch float i corresponds to
    // x[n,d2+rd,h2+rh,w2+rw, (cvec*4 + (i mod 4))]. Let me recompute carefully:
    //   p4 indexed by i (vec4-index 0..215). For each i: spatial=i>>3, cvec=i&7.
    //   p4[i] is a float4 of the 4 channel-elements (cvec*4 .. cvec*4+3) at that spatial.
    // But we read patch[lane + 32*j] which is a SCALAR (float). lane+32*j is a float index 0..863.
    // patch float index I corresponds to p4 vec4 index I>>2, lane within vec4 I&3.
    // I = lane + 32*j. I>>2 = (lane>>2) + 8*j  (since 32/4=8). I&3 = lane & 3.
    // So float at I lives in p4 vec4 index P = (lane>>2) + 8*j, scalar offset (lane & 3).
    // p4[P] = x4[x_idx_base + cvec], where for P: spatial = P>>3 = ((lane>>2) + 8*j) >> 3.
    //   For j in [0,27), P ranges (lane>>2) + 0,8,16,...,208. spatial = P>>3, cvec = P&7.
    //   With lane>>2 in [0,8): P = (lane>>2) + 8j. P&7 = lane>>2. P>>3 = j.
    //   So spatial = j, cvec = lane>>2. spatial = j means rd = j/9, rh = (j%9)/3, rw = j%3.
    // Channel index within C=32: c = cvec*4 + (lane & 3) = (lane>>2)*4 + (lane & 3)
    //                          = (lane & ~3) + (lane & 3) = lane.  (since lane<32)
    // So patch[lane + 32*j] = x[n, d2 + rd(j), h2 + rh(j), w2 + rw(j), lane].
    //
    // BEAUTIFUL: each lane reads channel c=lane for j=0..26 at (rd,rh,rw)=(j/9,(j%9)/3,j%3).

    float running_sum = 0.0f;
    uint pp = 0;

    // Precompute the 27 (rd,rh,rw) offsets as flat x-index strides at lane channel.
    // Stride per (rd,rh,rw): rd*Hc*Wc*Cc + rh*Wc*Cc + rw*Cc.
    // We'll compute base = ((n*Dc+d2)*Hc+h2)*Wc+w2)*Cc + lane, then add stride[j].
    uint strides[27];
    #pragma unroll
    for (uint j = 0; j < 27; ++j) {
        uint rd = j / 9u;
        uint rem = j - rd*9u;
        uint rh = rem / 3u;
        uint rw = rem - rh*3u;
        strides[j] = (rd*Hc + rh)*Wc*Cc + rw*Cc;
    }

    for (uint n = 0; n < Nc; ++n) {
        for (uint d2 = 0; d2 < D2; ++d2) {
        for (uint h2 = 0; h2 < H2; ++h2) {
        // W2=30, batches of TPB=3 → 10 batches.
        for (uint w2b = 0; w2b < W2; w2b += TPB) {
            float per_sg_max_t[TPB];
            #pragma unroll
            for (uint t = 0; t < TPB; ++t) {
                uint w2 = w2b + t;
                uint base = ((((n*Dc + d2)*Hc + h2)*Wc + w2)*Cc) + lane;
                float preg[27];
                #pragma unroll
                for (uint j = 0; j < 27; ++j) preg[j] = x[base + strides[j]];
                float s0 = 0.0f, s1 = 0.0f;
                #pragma unroll
                for (uint j = 0; j < 27; ++j) {
                    s0 = fma(preg[j], wreg0[j], s0);
                    s1 = fma(preg[j], wreg1[j], s1);
                }
                s0 = simd_sum(s0);
                s1 = simd_sum(s1);
                per_sg_max_t[t] = max(s0, s1);
            }

            if (lane == 0) {
                #pragma unroll
                for (uint t = 0; t < TPB; ++t)
                    sgmax_buf[pp][t][sg] = per_sg_max_t[t];
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);

            float acc = 0.0f;
            #pragma unroll
            for (uint t = 0; t < TPB; ++t) {
                float v = sgmax_buf[pp][t][lane];
                v = simd_max(v);
                acc += v;
            }
            running_sum += acc;
            pp ^= 1u;
        }}}
    }

    if (tid == 0) {
        y[0] = running_sum * final_scale + float(Nc) * bias_val;
    }
}

conv3d_multi_act_bias.metal_source:
// conv3d implicit im2col GEMM with simdgroup_matrix MMA, fused activation+bias epilogue.
// NDHWC, k=3, stride=1. x (4,32,32,32,32), w (64,3,3,3,32), b(64) -> y (4,30,30,30,64).
// GEMM: M = 4*30^3 = 108000, N = 64, K = 27*32 = 864.
// Activation chain (post-conv): relu -> leaky(0.01) -> gelu -> sigmoid + bias.
//   For x>=0 leaky_relu is identity. So fused fn collapses to:
//     v = max(conv, 0); v = gelu_erf(v); v = sigmoid(v); v += b[k].

#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 8;
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 1
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 68

static inline float gelu_erf_poly(float x) {
    const float k = 0.70710678f;
    float z = x * k;
    float t = 1.0f / (1.0f + 0.3275911f * fabs(z));
    float y = 1.0f - (((((1.061405429f * t - 1.453152027f) * t)
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f)
              * t * exp(-z * z);
    float erfz = copysign(y, z);
    return 0.5f * x * (1.0f + erfz);
}

static inline float fused_act(float x, float bias) {
    float v = fmax(x, 0.0f);            // relu (leaky no-op since v>=0)
    v = gelu_erf_poly(v);               // gelu
    v = 1.0f / (1.0f + exp(-v));        // sigmoid (v bounded since x>=0 -> gelu>=0 -> sig in [0.5,1])
    return v + bias;
}

kernel void conv3d_multi_act_bias_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device const float*  b       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   N_      [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   D       [[buffer(6)]],
    constant     uint&   H       [[buffer(7)]],
    constant     uint&   W       [[buffer(8)]],
    constant     uint&   K_out   [[buffer(9)]],
    constant     uint&   R       [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint D2 = D - R + 1;
    const uint H2 = H - R + 1;
    const uint W2 = W - R + 1;
    const uint HW2 = H2 * W2;
    const uint DHW2 = D2 * HW2;
    const uint M_g = N_ * DHW2;
    const uint RC = R * C;
    const uint RRC = R * RC;
    const uint K_g = R * RRC;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_n_tiles = (K_out + BN - 1) / BN;
    const uint total_tiles = num_m_tiles * num_n_tiles;

    threadgroup float As[BM * LDA];
    threadgroup float Bs[BK * LDB];
    threadgroup float Cs[BM * BN];

    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;

    for (uint tile = tg_id; tile < total_tiles; tile += n_tg) {
        const uint mtile = tile / num_n_tiles;
        const uint ntile = tile % num_n_tiles;
        const uint c_row0 = mtile * BM;
        const uint c_col0 = ntile * BN;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        // Per-thread A-row coords (constant over k-loop).
        const uint a_row = lid / 16u;
        const uint a_col0 = lid % 16u;
        const uint m_g_A = c_row0 + a_row;
        uint a_n=0, a_d=0, a_h=0, a_w=0;
        bool a_valid_row = m_g_A < M_g;
        if (a_valid_row) {
            a_n = m_g_A / DHW2;
            uint q = m_g_A - a_n * DHW2;
            a_d = q / HW2;
            q -= a_d * HW2;
            a_h = q / W2;
            a_w = q - a_h * W2;
        }

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            // Load A: 64*16 = 1024 elems, 1/thread.
            {
                const uint a_col = a_col0;
                const uint k_glob = k0 + a_col;
                const uint rd = k_glob / RRC;
                uint rem = k_glob - rd * RRC;
                const uint rh = rem / RC;
                rem -= rh * RC;
                const uint rw = rem / C;
                const uint c  = rem - rw * C;

                float v = 0.0f;
                if (a_valid_row && k_glob < K_g) {
                    const uint di = a_d + rd;
                    const uint hi = a_h + rh;
                    const uint wi = a_w + rw;
                    v = x[(((a_n * D + di) * H + hi) * W + wi) * C + c];
                }
                As[a_row * LDA + a_col] = v;
            }
            // Load B: 16 rows × 64 cols = 1024 elems.
            {
                const uint b_col = lid / BK;
                const uint b_row = lid % BK;
                const uint k_glob = k0 + b_row;
                const uint n_col = c_col0 + b_col;
                float v = 0.0f;
                if (k_glob < K_g && n_col < K_out) {
                    v = w[n_col * K_g + k_glob];
                }
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Epilogue: fused activation + bias, store with float4.
        {
            const uint idx = lid;
            const uint r = (idx * 4u) / BN;
            const uint c = (idx * 4u) % BN;
            const uint m_g = c_row0 + r;
            if (m_g < M_g) {
                const uint n_idx = m_g / DHW2;
                uint q = m_g - n_idx * DHW2;
                const uint d_idx = q / HW2;
                q -= d_idx * HW2;
                const uint h_idx = q / W2;
                const uint w_idx = q - h_idx * W2;
                float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
                const uint nc = c_col0 + c;
                // Load 4 biases.
                float4 bv;
                if (nc + 3 < K_out) {
                    bv = *reinterpret_cast<device const float4*>(&b[nc]);
                } else {
                    bv = float4(0.0f);
                    for (uint kk = 0; kk < 4u; ++kk)
                        if (nc + kk < K_out) ((thread float*)&bv)[kk] = b[nc + kk];
                }
                v.x = fused_act(v.x, bv.x);
                v.y = fused_act(v.y, bv.y);
                v.z = fused_act(v.z, bv.z);
                v.w = fused_act(v.w, bv.w);
                const uint y_base = (((n_idx * D2 + d_idx) * H2 + h_idx) * W2 + w_idx) * K_out + nc;
                if (nc + 3 < K_out) {
                    *reinterpret_cast<device float4*>(&y[y_base]) = v;
                } else {
                    float vs[4] = {v.x, v.y, v.z, v.w};
                    for (uint kk = 0; kk < 4u; ++kk) {
                        if (nc + kk < K_out)
                            y[y_base + kk] = vs[kk];
                    }
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv3d_softmax_pool.metal_source:
// Fused conv3d -> softmax(C) -> maxpool2x2x2 -> maxpool2x2x2.
// One threadgroup per output block (n, d4, h4, w4) in (4,7,7,7) = 1372 blocks.
//
// GEMM: M=64 (voxels in 4x4x4), N=64 (K_out channels), K=R^3*C = 864.
// Tile BM=64, BN=64, BK=32. 8 simdgroups (SIMDS_M=2, SIMDS_N=4); 256 threads/TG.
// Per simd: SM=32, SN=16 → MMA_M=4, MMA_N=2 = 8 MMAs × 4 inner kc steps = 32 MMAs / K-tile.
//
// Key optimizations vs previous version:
//   * Hoist 3D index decomposition out of inner load loop — since BK == C == 32 and
//     k0 % 32 == 0, (rd, rh, rw) are constant per kt iter, and c == a_col.
//   * float4 vector loads from device → threadgroup for both x and w.
//   * Simdgroup-shuffle reduction for the 4-way partial-max merge after softmax.
//   * Reciprocal of row-sum stored once so per-cell uses multiply not divide.
//   * fast::exp for the softmax.
//   * Reduced threadgroup memory by overlapping GEMM scratch (As/Bs) with post-GEMM Cs.

#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 32;
constant constexpr uint SIMDS_M = 2, SIMDS_N = 4;
constant constexpr uint SM = BM / SIMDS_M;           // 32
constant constexpr uint SN = BN / SIMDS_N;           // 16
constant constexpr uint MMA_M = SM / 8;              // 4
constant constexpr uint MMA_N = SN / 8;              // 2
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;              // 36
constant constexpr uint LDB = BN + PAD;              // 68

kernel void conv3d_softmax_pool_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   D       [[buffer(5)]],
    constant     uint&   H       [[buffer(6)]],
    constant     uint&   W       [[buffer(7)]],
    constant     uint&   K_out   [[buffer(8)]],
    constant     uint&   R       [[buffer(9)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint D_out = 7, H_out = 7, W_out = 7;
    const uint blocks_per_n = D_out * H_out * W_out;
    const uint total_blocks = N_ * blocks_per_n;
    const uint RC = R * C;
    const uint RRC = R * RC;
    const uint K_g = R * RRC;  // 864

    // Memory layout (overlap GEMM scratch with softmax/maxpool scratch).
    // GEMM phase:    As [BM*LDA] then Bs [BK*LDB] in the same buffer.
    // Post-GEMM:     Cs [BM*BN] reuses the start of the buffer.
    // Max needed:    max(BM*LDA + BK*LDB, BM*BN) = max(2304+2176, 4096) = 4480 floats (~18KB).
    threadgroup float scratch[BM * LDA + BK * LDB];   // 4480 floats
    threadgroup float* As = scratch;
    threadgroup float* Bs = scratch + BM * LDA;
    threadgroup float* Cs = scratch;
    threadgroup float row_m[BM];
    threadgroup float row_Z[BM];   // stores 1 / Z so per-cell softmax uses multiply

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint blk = tg_id; blk < total_blocks; blk += n_tg) {
        uint q = blk;
        const uint w4 = q % W_out; q /= W_out;
        const uint h4 = q % H_out; q /= H_out;
        const uint d4 = q % D_out;
        const uint n  = q / D_out;
        const uint d0 = d4 * 4;
        const uint h0 = h4 * 4;
        const uint w0 = w4 * 4;

        simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

        const uint num_k_tiles = (K_g + BK - 1) / BK;   // 27 with BK=32

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;
            // Since BK == C == 32 and k0 % 32 == 0, the convolution offsets (rd, rh, rw)
            // are constant across the entire K-tile and c == a_col.
            const uint kt_idx = k0 >> 5;
            const uint rw = kt_idx % R;
            const uint rh = (kt_idx / R) % R;
            const uint rd = kt_idx / (R * R);

            // Load A: BM*BK = 64*32 = 2048 floats via 512 float4 reads (256 thr × 2 iters).
            // pos = it*256 + lid. a_row = pos / 8 ∈ [0,64). chunk = pos % 8 ∈ [0,8). a_col = chunk*4.
            {
                const device float4* x4 = reinterpret_cast<const device float4*>(x);
                #pragma unroll
                for (uint it = 0; it < 2u; ++it) {
                    const uint pos = it * 256u + lid;
                    const uint a_row = pos >> 3;
                    const uint chunk = pos & 7u;
                    const uint a_col = chunk * 4u;
                    const uint dd = a_row >> 4;
                    const uint hh = (a_row >> 2) & 3u;
                    const uint ww = a_row & 3u;
                    const uint di = d0 + dd + rd;
                    const uint hi = h0 + hh + rh;
                    const uint wi = w0 + ww + rw;
                    const uint addr = (((n * D + di) * H + hi) * W + wi) * C + a_col;
                    float4 v = x4[addr >> 2];
                    As[a_row * LDA + a_col + 0u] = v.x;
                    As[a_row * LDA + a_col + 1u] = v.y;
                    As[a_row * LDA + a_col + 2u] = v.z;
                    As[a_row * LDA + a_col + 3u] = v.w;
                }
            }
            // Load B: BK*BN = 32*64 = 2048 floats via 512 float4 reads (256 thr × 2 iters).
            // pos = it*256 + lid. b_col = pos / 8 ∈ [0,64). chunk = pos % 8 ∈ [0,8). k_glob = k0 + chunk*4.
            {
                const device float4* w4 = reinterpret_cast<const device float4*>(w);
                #pragma unroll
                for (uint it = 0; it < 2u; ++it) {
                    const uint pos = it * 256u + lid;
                    const uint b_col = pos >> 3;
                    const uint chunk = pos & 7u;
                    const uint k_glob = k0 + chunk * 4u;
                    // K_g = 27*BK exactly; BN = K_out = 64 → no bounds needed.
                    float4 v = w4[(b_col * K_g + k_glob) >> 2];
                    Bs[(chunk * 4u + 0u) * LDB + b_col] = v.x;
                    Bs[(chunk * 4u + 1u) * LDB + b_col] = v.y;
                    Bs[(chunk * 4u + 2u) * LDB + b_col] = v.z;
                    Bs[(chunk * 4u + 3u) * LDB + b_col] = v.w;
                }
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    simdgroup_load(A_blk[i], &As[(sm * SM + i * 8u) * LDA + kc], LDA);
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j)
                        simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Store accumulator to Cs (row=voxel, col=channel).
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C_acc[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Per-row softmax stats over the 64 channels.
        // 256 threads, 64 rows → 4 thr/row. We use: each simd handles 8 rows, lane reads 2 channels.
        // simd_max / simd_sum reduce across the 32 lanes of a simdgroup ⇒ 64 channels total.
        {
            const uint lane = lid & 31u;
            #pragma unroll
            for (uint rr = 0; rr < 8u; ++rr) {
                const uint row = sgid * 8u + rr;
                float c0 = Cs[row * BN + lane * 2u + 0u];
                float c1 = Cs[row * BN + lane * 2u + 1u];
                float lm = max(c0, c1);
                float m = simd_max(lm);
                float e0 = fast::exp(c0 - m);
                float e1 = fast::exp(c1 - m);
                float ls = e0 + e1;
                float Z = simd_sum(ls);
                if (lane == 0) {
                    row_m[row] = m;
                    row_Z[row] = 1.0f / Z;
                }
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Softmax + reduce-max across 64 voxels for each of 64 channels.
        // 256 threads, 64 channels → 4 thr/ch. Each thread handles 16 rows then
        // reduces with two simd_shuffle_xor calls (lanes 4k..4k+3 hold partials for one channel).
        {
            const uint ch = lid >> 2;
            const uint slot = lid & 3u;
            float best = -INFINITY;
            #pragma unroll
            for (uint r = 0; r < 16u; ++r) {
                uint row = slot * 16u + r;
                float cv = Cs[row * BN + ch];
                float v = fast::exp(cv - row_m[row]) * row_Z[row];
                best = max(best, v);
            }
            best = max(best, simd_shuffle_xor(best, 1u));
            best = max(best, simd_shuffle_xor(best, 2u));
            if (slot == 0u) {
                const uint y_idx = (((n * D_out + d4) * H_out + h4) * W_out + w4) * K_out + ch;
                y[y_idx] = best;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }
}

conv_transpose2d_clamp_scale_div.metal_source:
// conv_transpose2d_clamp_scale_div: fused 3x3 transposed conv (NHWC, stride=2)
// + bias + clamp[-1,1] * scale + clamp[-1,1] / div.
// Implicit-im2col GEMM via simdgroup_matrix MMA. Each TG processes 2 consecutive
// m-tiles, sharing per-kt B (weight) load → halves B bandwidth.
// Grid-agnostic: each TG strides over its share of m-tile groups via tg_id.
//
// Shapes: x (N=8, H=32, W=32, C=64) ; w (K_out=128, R=3, S=3, C=64) ;
//         y (N, H_out=65, W_out=65, K_out=128) ; stride=2.
//
// GEMM mapping: M = N*H_out*W_out = 33800 ; N_dim = K_out = 128 ; K = R*S*C = 576.
// x[m, k] := x[n, h_in, w_in, c] if (h_out-r) and (w_out-s) are both even and
//            the input coord is in-range; else 0.
// w[k, k_out] := w[k_out, r, s, c] (already stored in (K_out, R, S, C)).
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 16;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 132

kernel void conv_transpose2d_clamp_scale_div_f32(
    device const float*  x      [[buffer(0)]],
    device const float*  w      [[buffer(1)]],
    device const float*  b      [[buffer(2)]],
    device       float*  y      [[buffer(3)]],
    constant     uint&   N_     [[buffer(4)]],
    constant     uint&   C_in   [[buffer(5)]],
    constant     uint&   H      [[buffer(6)]],
    constant     uint&   W      [[buffer(7)]],
    constant     uint&   K_out  [[buffer(8)]],
    constant     uint&   R      [[buffer(9)]],
    constant     uint&   stride [[buffer(10)]],
    constant     float&  scale  [[buffer(11)]],
    constant     float&  div    [[buffer(12)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H_out = (H - 1) * stride + R;  // 65
    const uint W_out = (W - 1) * stride + R;  // 65
    const uint HW_out = H_out * W_out;
    const uint M_g = N_ * HW_out;
    const uint S   = R;
    const uint SC  = S * C_in;
    const uint K_g = R * SC;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_groups = (num_m_tiles + 1u) / 2u;

    const float inv_div = 1.0f / div;

    threadgroup float scratch[BM * BN];
    threadgroup float* As0 = scratch;
    threadgroup float* As1 = scratch + BM * LDA;
    threadgroup float* Bs  = scratch + 2u * BM * LDA;
    threadgroup float* Cs  = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint grp = tg_id; grp < num_groups; grp += n_tg) {
        const uint tile0 = grp * 2u;
        const uint c_row0_0 = tile0 * BM;
        const uint c_row0_1 = (tile0 + 1u) * BM;
        const bool has1 = (tile0 + 1u) < num_m_tiles;

        simdgroup_matrix<float, 8, 8> C0[MMA_M][MMA_N];
        simdgroup_matrix<float, 8, 8> C1[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) {
                C0[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
                C1[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
            }

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            // Load A0, A1 (BM x BK each): 1 element/thread
            {
                const uint a_row = lid / BK;
                const uint a_col = lid & (BK - 1);
                const uint k_glob = k0 + a_col;
                float v0 = 0.0f, v1 = 0.0f;
                if (k_glob < K_g) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C_in;
                    const uint c  = rem - ss * C_in;

                    // Tile 0
                    {
                        const uint mg = c_row0_0 + a_row;
                        if (mg < M_g) {
                            const uint n_idx = mg / HW_out;
                            const uint hw    = mg - n_idx * HW_out;
                            const uint h_out = hw / W_out;
                            const uint w_out = hw - h_out * W_out;
                            const int hd = int(h_out) - int(rr);
                            const int wd = int(w_out) - int(ss);
                            if (hd >= 0 && wd >= 0 && ((hd | wd) & 1) == 0) {
                                const uint h_in = uint(hd) >> 1;
                                const uint w_in = uint(wd) >> 1;
                                if (h_in < H && w_in < W) {
                                    v0 = x[((n_idx * H + h_in) * W + w_in) * C_in + c];
                                }
                            }
                        }
                    }
                    // Tile 1
                    if (has1) {
                        const uint mg = c_row0_1 + a_row;
                        if (mg < M_g) {
                            const uint n_idx = mg / HW_out;
                            const uint hw    = mg - n_idx * HW_out;
                            const uint h_out = hw / W_out;
                            const uint w_out = hw - h_out * W_out;
                            const int hd = int(h_out) - int(rr);
                            const int wd = int(w_out) - int(ss);
                            if (hd >= 0 && wd >= 0 && ((hd | wd) & 1) == 0) {
                                const uint h_in = uint(hd) >> 1;
                                const uint w_in = uint(wd) >> 1;
                                if (h_in < H && w_in < W) {
                                    v1 = x[((n_idx * H + h_in) * W + w_in) * C_in + c];
                                }
                            }
                        }
                    }
                }
                As0[a_row * LDA + a_col] = v0;
                As1[a_row * LDA + a_col] = v1;
            }

            // Load B (BK x BN): 2 elements/thread.
            // B[k, kk] = w[kk, k_glob] where w is stored (K_out, R, S, C_in) contiguous.
            #pragma unroll
            for (uint p = 0; p < 2; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t & (BK - 1);
                const uint kg = k0 + b_row;
                float v = 0.0f;
                if (kg < K_g) v = w[b_col * K_g + kg];
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A0_blk[MMA_M], A1_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i) {
                    simdgroup_load(A0_blk[i], &As0[(sm * SM + i * 8u) * LDA + kc], LDA);
                    simdgroup_load(A1_blk[i], &As1[(sm * SM + i * 8u) * LDA + kc], LDA);
                }
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j) {
                        simdgroup_multiply_accumulate(C0[i][j], A0_blk[i], B_blk[j], C0[i][j]);
                        simdgroup_multiply_accumulate(C1[i][j], A1_blk[i], B_blk[j], C1[i][j]);
                    }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Epilogue tile 0: bias + clamp*scale + clamp*inv_div.
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C0[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);
        #pragma unroll
        for (uint rs = 0; rs < 2; ++rs) {
            const uint r_local = (lid / 32u) + rs * 32u;
            const uint cq = lid & 31u;
            const uint c = cq * 4u;
            const uint m_g = c_row0_0 + r_local;
            if (m_g < M_g) {
                float4 v  = *reinterpret_cast<threadgroup float4*>(&Cs[r_local * BN + c]);
                float4 bv = *reinterpret_cast<device const float4*>(&b[c]);
                v += bv;
                v = clamp(v, float4(-1.0f), float4(1.0f)) * scale;
                v = clamp(v, float4(-1.0f), float4(1.0f)) * inv_div;
                const uint n_idx = m_g / HW_out;
                const uint hw    = m_g - n_idx * HW_out;
                const uint h_out = hw / W_out;
                const uint w_out = hw - h_out * W_out;
                *reinterpret_cast<device float4*>(&y[((n_idx * H_out + h_out) * W_out + w_out) * K_out + c]) = v;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        if (has1) {
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_store(C1[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
            threadgroup_barrier(mem_flags::mem_threadgroup);
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r_local = (lid / 32u) + rs * 32u;
                const uint cq = lid & 31u;
                const uint c = cq * 4u;
                const uint m_g = c_row0_1 + r_local;
                if (m_g < M_g) {
                    float4 v  = *reinterpret_cast<threadgroup float4*>(&Cs[r_local * BN + c]);
                    float4 bv = *reinterpret_cast<device const float4*>(&b[c]);
                    v += bv;
                    v = clamp(v, float4(-1.0f), float4(1.0f)) * scale;
                    v = clamp(v, float4(-1.0f), float4(1.0f)) * inv_div;
                    const uint n_idx = m_g / HW_out;
                    const uint hw    = m_g - n_idx * HW_out;
                    const uint h_out = hw / W_out;
                    const uint w_out = hw - h_out * W_out;
                    *reinterpret_cast<device float4*>(&y[((n_idx * H_out + h_out) * W_out + w_out) * K_out + c]) = v;
                }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }
    }
}

conv_transpose2d_sub_tanh.metal_source:
// conv_transpose2d_sub_tanh: fused 3x3 transposed conv (NHWC, stride=2)
// + sub_val + stable tanh, via implicit-im2col GEMM with simdgroup_matrix MMA.
// Each TG processes 2 consecutive m-tiles, sharing per-kt B (weight) load.
// Grid-agnostic: TG strides over m-tile groups via tg_id.
//
// Shapes: x (N=8, H=32, W=32, C=64) ; w (K_out=128, R=3, S=3, C=64) ;
//         y (N, H_out=65, W_out=65, K_out=128) ; stride=2.
//
// GEMM mapping: M = N*H_out*W_out = 33800 ; N_dim = K_out = 128 ; K = R*S*C = 576.
// x[m, k] := x[n, h_in, w_in, c] iff (h_out-r) and (w_out-s) are both even and
//            input coord is in-range; else 0.  Parity folded into A-load.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 128, BK = 16;
constant constexpr uint SM = 16, SN = 16;
constant constexpr uint SIMDS_M = BM / SM;   // 4
constant constexpr uint SIMDS_N = BN / SN;   // 8
constant constexpr uint MMA_M = SM / 8;      // 2
constant constexpr uint MMA_N = SN / 8;      // 2
constant constexpr uint TG_THREADS = 1024;
constant constexpr uint PAD = 4;
constant constexpr uint LDA = BK + PAD;      // 20
constant constexpr uint LDB = BN + PAD;      // 132

inline float safe_tanh(float v) {
    return precise::tanh(clamp(v, -30.0f, 30.0f));
}

kernel void conv_transpose2d_sub_tanh_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N_      [[buffer(3)]],
    constant     uint&   C_in    [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   K_out   [[buffer(7)]],
    constant     uint&   R       [[buffer(8)]],
    constant     uint&   stride  [[buffer(9)]],
    constant     float&  sub_val [[buffer(10)]],
    uint tg_id   [[threadgroup_position_in_grid]],
    uint sgid    [[simdgroup_index_in_threadgroup]],
    uint lid     [[thread_index_in_threadgroup]],
    uint n_tg    [[threadgroups_per_grid]])
{
    const uint H_out = (H - 1) * stride + R;  // 65
    const uint W_out = (W - 1) * stride + R;  // 65
    const uint HW_out = H_out * W_out;
    const uint M_g = N_ * HW_out;
    const uint S   = R;
    const uint SC  = S * C_in;
    const uint K_g = R * SC;
    const uint num_m_tiles = (M_g + BM - 1) / BM;
    const uint num_groups = (num_m_tiles + 1u) / 2u;

    threadgroup float scratch[BM * BN];
    threadgroup float* As0 = scratch;
    threadgroup float* As1 = scratch + BM * LDA;
    threadgroup float* Bs  = scratch + 2u * BM * LDA;
    threadgroup float* Cs  = scratch;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;

    for (uint grp = tg_id; grp < num_groups; grp += n_tg) {
        const uint tile0 = grp * 2u;
        const uint c_row0_0 = tile0 * BM;
        const uint c_row0_1 = (tile0 + 1u) * BM;
        const bool has1 = (tile0 + 1u) < num_m_tiles;

        simdgroup_matrix<float, 8, 8> C0[MMA_M][MMA_N];
        simdgroup_matrix<float, 8, 8> C1[MMA_M][MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) {
                C0[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
                C1[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);
            }

        const uint num_k_tiles = (K_g + BK - 1) / BK;

        for (uint kt = 0; kt < num_k_tiles; ++kt) {
            const uint k0 = kt * BK;

            // Load A0, A1 (BM x BK each): 1 element/thread.
            {
                const uint a_row = lid / BK;
                const uint a_col = lid & (BK - 1);
                const uint k_glob = k0 + a_col;
                float v0 = 0.0f, v1 = 0.0f;
                if (k_glob < K_g) {
                    const uint rr = k_glob / SC;
                    const uint rem = k_glob - rr * SC;
                    const uint ss = rem / C_in;
                    const uint c  = rem - ss * C_in;

                    // Tile 0
                    {
                        const uint mg = c_row0_0 + a_row;
                        if (mg < M_g) {
                            const uint n_idx = mg / HW_out;
                            const uint hw    = mg - n_idx * HW_out;
                            const uint h_out = hw / W_out;
                            const uint w_out = hw - h_out * W_out;
                            const int hd = int(h_out) - int(rr);
                            const int wd = int(w_out) - int(ss);
                            if (hd >= 0 && wd >= 0 && ((hd | wd) & 1) == 0) {
                                const uint h_in = uint(hd) >> 1;
                                const uint w_in = uint(wd) >> 1;
                                if (h_in < H && w_in < W) {
                                    v0 = x[((n_idx * H + h_in) * W + w_in) * C_in + c];
                                }
                            }
                        }
                    }
                    // Tile 1
                    if (has1) {
                        const uint mg = c_row0_1 + a_row;
                        if (mg < M_g) {
                            const uint n_idx = mg / HW_out;
                            const uint hw    = mg - n_idx * HW_out;
                            const uint h_out = hw / W_out;
                            const uint w_out = hw - h_out * W_out;
                            const int hd = int(h_out) - int(rr);
                            const int wd = int(w_out) - int(ss);
                            if (hd >= 0 && wd >= 0 && ((hd | wd) & 1) == 0) {
                                const uint h_in = uint(hd) >> 1;
                                const uint w_in = uint(wd) >> 1;
                                if (h_in < H && w_in < W) {
                                    v1 = x[((n_idx * H + h_in) * W + w_in) * C_in + c];
                                }
                            }
                        }
                    }
                }
                As0[a_row * LDA + a_col] = v0;
                As1[a_row * LDA + a_col] = v1;
            }

            // Load B (BK x BN): 2 elements/thread.
            // B[k, kk] = w[kk, k_glob] where w is stored (K_out, R, S, C_in) contiguous.
            #pragma unroll
            for (uint p = 0; p < 2; ++p) {
                const uint t = lid + p * TG_THREADS;
                const uint b_col = t / BK;
                const uint b_row = t & (BK - 1);
                const uint kg = k0 + b_row;
                float v = 0.0f;
                if (kg < K_g) v = w[b_col * K_g + kg];
                Bs[b_row * LDB + b_col] = v;
            }

            threadgroup_barrier(mem_flags::mem_threadgroup);

            #pragma unroll
            for (uint kc = 0; kc < BK; kc += 8u) {
                simdgroup_matrix<float, 8, 8> A0_blk[MMA_M], A1_blk[MMA_M], B_blk[MMA_N];
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i) {
                    simdgroup_load(A0_blk[i], &As0[(sm * SM + i * 8u) * LDA + kc], LDA);
                    simdgroup_load(A1_blk[i], &As1[(sm * SM + i * 8u) * LDA + kc], LDA);
                }
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8u], LDB);
                #pragma unroll
                for (uint i = 0; i < MMA_M; ++i)
                    #pragma unroll
                    for (uint j = 0; j < MMA_N; ++j) {
                        simdgroup_multiply_accumulate(C0[i][j], A0_blk[i], B_blk[j], C0[i][j]);
                        simdgroup_multiply_accumulate(C1[i][j], A1_blk[i], B_blk[j], C1[i][j]);
                    }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Epilogue tile 0: (sum - sub_val) -> safe_tanh
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_store(C0[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
        threadgroup_barrier(mem_flags::mem_threadgroup);
        #pragma unroll
        for (uint rs = 0; rs < 2; ++rs) {
            const uint r_local = (lid / 32u) + rs * 32u;
            const uint cq = lid & 31u;
            const uint c = cq * 4u;
            const uint m_g = c_row0_0 + r_local;
            if (m_g < M_g) {
                float4 v  = *reinterpret_cast<threadgroup float4*>(&Cs[r_local * BN + c]);
                v -= float4(sub_val);
                v = clamp(v, float4(-15.0f), float4(15.0f));
                v = tanh(v);
                const uint n_idx = m_g / HW_out;
                const uint hw    = m_g - n_idx * HW_out;
                const uint h_out = hw / W_out;
                const uint w_out = hw - h_out * W_out;
                *reinterpret_cast<device float4*>(&y[((n_idx * H_out + h_out) * W_out + w_out) * K_out + c]) = v;
            }
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        if (has1) {
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_store(C1[i][j], &Cs[(sm * SM + i * 8u) * BN + sn * SN + j * 8u], BN);
            threadgroup_barrier(mem_flags::mem_threadgroup);
            #pragma unroll
            for (uint rs = 0; rs < 2; ++rs) {
                const uint r_local = (lid / 32u) + rs * 32u;
                const uint cq = lid & 31u;
                const uint c = cq * 4u;
                const uint m_g = c_row0_1 + r_local;
                if (m_g < M_g) {
                    float4 v  = *reinterpret_cast<threadgroup float4*>(&Cs[r_local * BN + c]);
                    v -= float4(sub_val);
                    v = clamp(v, float4(-15.0f), float4(15.0f));
                    v = tanh(v);
                    const uint n_idx = m_g / HW_out;
                    const uint hw    = m_g - n_idx * HW_out;
                    const uint h_out = hw / W_out;
                    const uint w_out = hw - h_out * W_out;
                    *reinterpret_cast<device float4*>(&y[((n_idx * H_out + h_out) * W_out + w_out) * K_out + c]) = v;
                }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }
    }
}

conv_transpose3d_norm_pool_gelu.metal_source:
#include <metal_stdlib>
using namespace metal;

static inline float gelu_tanh(float x) {
    const float kBeta  = 0.7978845608028654f;
    const float kAlpha = 0.044715f;
    float x3 = x * x * x;
    float u = kBeta * (x + kAlpha * x3);
    u = clamp(u, -10.0f, 10.0f);
    return 0.5f * x * (1.0f + tanh(u));
}

// One threadgroup per (n,d2,h2,w2). 32 threads = 1 simdgroup, each = 1 channel.
// Loads a 4x4x4x16 input patch into threadgroup memory (with zero padding for
// out-of-bounds), then performs 8 conv-transpose evaluations + LayerNorm +
// AvgPool + GELU.

kernel void conv_transpose3d_norm_pool_gelu_f32(
    device const float* x        [[buffer(0)]],
    device const float* w        [[buffer(1)]],
    device const float* sum_term [[buffer(2)]],
    device       float* y        [[buffer(3)]],
    constant     uint& N         [[buffer(4)]],
    constant     uint& C_in      [[buffer(5)]],
    constant     uint& D         [[buffer(6)]],
    constant     uint& H         [[buffer(7)]],
    constant     uint& W         [[buffer(8)]],
    constant     uint& K         [[buffer(9)]],
    constant     uint& R         [[buffer(10)]],
    constant     float& eps      [[buffer(11)]],
    uint3 tgid [[threadgroup_position_in_grid]],
    uint3 lid3 [[thread_position_in_threadgroup]])
{
    const uint D2 = 5, H2 = 5, W2 = 5;
    const uint Ci = 16, Rc = 3, Dc = 8, Hc = 8, Wc = 8, Kc = 32;

    uint flat = tgid.x;
    uint w2 = flat % W2; flat /= W2;
    uint h2 = flat % H2; flat /= H2;
    uint d2 = flat % D2; uint n = flat / D2;

    uint kk = lid3.x;

    // The input patch we need: d_in = d_full - rd, where d_full in
    // {2*d2, 2*d2+1} and rd in {0,1,2}. So d_in in {2*d2-2, ..., 2*d2+1} -> 4 values.
    // Patch origin in input coords:
    int d_o = int(d2) * 2 - 2;
    int h_o = int(h2) * 2 - 2;
    int w_o = int(w2) * 2 - 2;

    // 4*4*4*16 = 1024 floats; loaded co-operatively by 32 threads (32 each).
    threadgroup float xtile[4 * 4 * 4 * 16];

    // Each thread loads 32 floats.
    for (uint i = 0; i < 32; ++i) {
        uint idx = kk * 32 + i;                  // 0..1023
        uint c  = idx & 15u;
        uint t  = idx >> 4;                      // 0..63 -> (dd,hh,ww) over 4x4x4
        uint ww = t & 3u;
        uint hh = (t >> 2) & 3u;
        uint dd = (t >> 4) & 3u;
        int d_in = d_o + int(dd);
        int h_in = h_o + int(hh);
        int w_in = w_o + int(ww);
        float v = 0.0f;
        if (d_in >= 0 && d_in < int(Dc) &&
            h_in >= 0 && h_in < int(Hc) &&
            w_in >= 0 && w_in < int(Wc)) {
            uint x_base = (((n * Dc + uint(d_in)) * Hc + uint(h_in)) * Wc + uint(w_in)) * Ci + c;
            v = x[x_base];
        }
        xtile[idx] = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float bias = sum_term[kk];
    uint wk_base = kk * (Rc * Rc * Rc * Ci);

    float pool_acc = 0.0f;

    // The 8 pool sub-voxels.
    for (uint pd = 0; pd < 2; ++pd) {
        for (uint ph = 0; ph < 2; ++ph) {
            for (uint pw = 0; pw < 2; ++pw) {
                float s = bias;
                // d_full = 2*d2 + pd; d_in = d_full - rd = 2*d2 + pd - rd
                // Within the tile, dd = d_in - d_o = pd - rd + 2. For rd=0..2 -> dd=pd+2,pd+1,pd.
                // So dd ranges {pd, pd+1, pd+2}. Similar for hh,ww.
                for (uint rd = 0; rd < 3; ++rd) {
                    uint dd = pd + 2 - rd;       // always in [0,3]
                    for (uint rh = 0; rh < 3; ++rh) {
                        uint hh = ph + 2 - rh;
                        for (uint rw = 0; rw < 3; ++rw) {
                            uint ww = pw + 2 - rw;
                            uint tile_base = ((dd * 4 + hh) * 4 + ww) * Ci;
                            uint w_base = wk_base + ((rd * Rc + rh) * Rc + rw) * Ci;
                            float4 xv0 = *((threadgroup float4*)(xtile + tile_base + 0));
                            float4 xv1 = *((threadgroup float4*)(xtile + tile_base + 4));
                            float4 xv2 = *((threadgroup float4*)(xtile + tile_base + 8));
                            float4 xv3 = *((threadgroup float4*)(xtile + tile_base + 12));
                            float4 wv0 = *((device const float4*)(w + w_base + 0));
                            float4 wv1 = *((device const float4*)(w + w_base + 4));
                            float4 wv2 = *((device const float4*)(w + w_base + 8));
                            float4 wv3 = *((device const float4*)(w + w_base + 12));
                            s += dot(xv0, wv0) + dot(xv1, wv1) + dot(xv2, wv2) + dot(xv3, wv3);
                        }
                    }
                }
                float sum   = simd_sum(s);
                float sumsq = simd_sum(s * s);
                float mean  = sum * (1.0f / 32.0f);
                float var   = sumsq * (1.0f / 32.0f) - mean * mean;
                float inv   = rsqrt(max(var, 0.0f) + eps);
                pool_acc += (s - mean) * inv;
            }
        }
    }

    float avg = pool_acc * (1.0f / 8.0f);
    float out = gelu_tanh(avg);
    uint y_idx = (((n * D2 + d2) * H2 + h2) * W2 + w2) * Kc + kk;
    y[y_idx] = out;
}

cosine_similarity.metal_source:
// cosine_similarity: x·y / (|x| * |y|) per row. Three simd_sum reductions.
#include <metal_stdlib>
using namespace metal;

kernel void cosine_similarity_f32(
    device const float*  x   [[buffer(0)]],
    device const float*  y   [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   D   [[buffer(3)]],
    uint3 tid               [[thread_position_in_threadgroup]],
    uint3 tgid              [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * D;
    const uint sg = t >> 5;

    float xi = x[off + t];
    float yi = y[off + t];
    float dot_v = xi * yi;
    float sq_x  = xi * xi;
    float sq_y  = yi * yi;

    float dot_sum  = simd_sum(dot_v);
    float sq_x_sum = simd_sum(sq_x);
    float sq_y_sum = simd_sum(sq_y);

    threadgroup float tg_dot[32], tg_sqx[32], tg_sqy[32];
    if ((t & 31) == 0) {
        tg_dot[sg] = dot_sum;
        tg_sqx[sg] = sq_x_sum;
        tg_sqy[sg] = sq_y_sum;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        float d = tg_dot[t], sx = tg_sqx[t], sy = tg_sqy[t];
        for (uint s = 16; s > 0; s >>= 1) {
            d  += simd_shuffle_down(d,  s);
            sx += simd_shuffle_down(sx, s);
            sy += simd_shuffle_down(sy, s);
        }
        if (t == 0) {
            float eps = 1e-8f;
            out[row] = d / (sqrt(sx) * sqrt(sy) + eps);
        }
    }
}

cross_entropy_loss.metal_source:
// cross_entropy_loss: per-row -sum(y * log_softmax(L))
//                   = lse * sum(y) - sum(y * L)
// where lse = row_max + log(sum_c exp(L_c - row_max))
//
// Fused reductions: pass 1 computes row_max, sum_y, sum_yl simultaneously.
// Pass 2 computes sum_exp.  Then write out[row] = lse*sum_y - sum_yl.
#include <metal_stdlib>
using namespace metal;

kernel void cross_entropy_loss_f32(
    device const float*  L        [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint tid  = tid3.x;
    const uint row  = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;

    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;

    threadgroup float r0[32]; // max
    threadgroup float r1[32]; // sum_y
    threadgroup float r2[32]; // sum_yl
    threadgroup float r3[32]; // sum_exp
    threadgroup float sc[3];  // [row_max, sum_y, sum_yl] – not strictly needed but keeps clarity

    float lv = lp[tid];
    float yv = yp[tid];

    // ---- pass 1: max, sum(y), sum(y*l) ----
    float mx  = simd_max(lv);
    float sy  = simd_sum(yv);
    float syl = simd_sum(yv * lv);
    if (lane == 0) { r0[sgid] = mx; r1[sgid] = sy; r2[sgid] = syl; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float row_max, sum_y, sum_yl;
    if (sgid == 0) {
        float v0 = r0[lane];
        float v1 = r1[lane];
        float v2 = r2[lane];
        v0 = simd_max(v0);
        v1 = simd_sum(v1);
        v2 = simd_sum(v2);
        if (lane == 0) { sc[0] = v0; sc[1] = v1; sc[2] = v2; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    row_max = sc[0];
    sum_y   = sc[1];
    sum_yl  = sc[2];

    // ---- pass 2: sum(exp(l - row_max)) ----
    float e  = fast::exp(lv - row_max);
    float se = simd_sum(e);
    if (lane == 0) r3[sgid] = se;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sgid == 0) {
        float v = r3[lane];
        v = simd_sum(v);
        if (lane == 0) {
            float lse = row_max + fast::log(v);
            out[row] = lse * sum_y - sum_yl;
        }
    }
}

cumprod.metal_source:
// cumprod: float4-per-thread 2-level prefix product.
// 256 threads/TG (8 simdgroups), each handles 4 contiguous elements via float4 load/store.
#include <metal_stdlib>
using namespace metal;

kernel void cumprod_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;        // 0..7
    const uint sl = t & 31;

    const uint base = row * N + t * 4;
    float4 v = *reinterpret_cast<const device float4*>(&x[base]);

    // Local cumulative product within float4.
    float4 lp;
    lp.x = v.x;
    lp.y = lp.x * v.y;
    lp.z = lp.y * v.z;
    lp.w = lp.z * v.w;

    // simd_prefix_inclusive over float4 totals.
    float local_scan = simd_prefix_inclusive_product(lp.w);

    // Cross-simd: 8 simdgroups in TG.
    threadgroup float tg_totals[8];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float v8 = (sl < 8) ? tg_totals[sl] : 1.0f;
        float pre = simd_prefix_exclusive_product(v8);
        if (sl < 8) tg_totals[sl] = pre;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float thread_excl_in_simd = local_scan / lp.w;
    float thread_offset = tg_totals[sg] * thread_excl_in_simd;

    float4 out;
    out.x = thread_offset * lp.x;
    out.y = thread_offset * lp.y;
    out.z = thread_offset * lp.z;
    out.w = thread_offset * lp.w;

    *reinterpret_cast<device float4*>(&y[base]) = out;
}

cumsum.metal_source:
// cumsum: 2-level prefix scan using hardware simd_prefix_inclusive_sum.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;        // simdgroup index (0..31)
    const uint sl = t & 31;         // lane within simdgroup (0..31)

    float val = x[row * N + t];

    float local_scan = simd_prefix_inclusive_sum(val);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) {
        my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    }
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * N + t] = local_scan + tg_totals[sg];
}

cumsum_exclusive.metal_source:
// cumsum_exclusive: per-row exclusive prefix sum. Two-level scan via simd hardware.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_exclusive_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5;
    const uint sl = t & 31;

    float v = x[row * C + t];
    float local_scan = simd_prefix_inclusive_sum(v);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * C + t] = local_scan + tg_totals[sg] - v;
}

cumsum_reverse.metal_source:
// cumsum_reverse: 2-level prefix scan on reversed elements per row.
#include <metal_stdlib>
using namespace metal;

kernel void cumsum_reverse_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint sg = t >> 5, sl = t & 31;
    const uint rev_t = N - 1 - t;

    float val = x[row * N + rev_t];
    float local_scan = simd_prefix_inclusive_sum(val);

    threadgroup float tg_totals[32];
    if (sl == 31) tg_totals[sg] = local_scan;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float my_offset = 0.0f;
    if (sg == 0) my_offset = simd_prefix_exclusive_sum(tg_totals[sl]);
    if (t < 32) tg_totals[t] = my_offset;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[row * N + rev_t] = local_scan + tg_totals[sg];
}

depthwise_conv2d.metal_source:
// depthwise_conv2d: NHWC, groups == C. x (N,H,W,C), w (C,R,S,1), y (N,H2,W2,C).
#include <metal_stdlib>
using namespace metal;

kernel void depthwise_conv2d_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  w       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   H       [[buffer(5)]],
    constant     uint&   W       [[buffer(6)]],
    constant     uint&   R       [[buffer(7)]],
    constant     uint&   S       [[buffer(8)]],
    constant     uint&   stride  [[buffer(9)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - R) / stride + 1;
    const uint W2 = (W - S) / stride + 1;
    const uint HW2C = H2 * W2 * C;
    const uint W2C = W2 * C;
    const uint total = N * HW2C;
    const uint sH = W * C;
    const uint sN = H * sH;

    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint q = idx;
        uint n  = q / HW2C;  q -= n * HW2C;
        uint h2 = q / W2C;   q -= h2 * W2C;
        uint w2 = q / C;
        uint c  = q - w2 * C;

        uint wb = c * 9; // R*S = 9
        float w00 = w[wb + 0]; float w01 = w[wb + 1]; float w02 = w[wb + 2];
        float w10 = w[wb + 3]; float w11 = w[wb + 4]; float w12 = w[wb + 5];
        float w20 = w[wb + 6]; float w21 = w[wb + 7]; float w22 = w[wb + 8];

        uint xb = n * sN + (h2 * stride) * sH + (w2 * stride) * C + c;

        float x00 = x[xb           ]; float x01 = x[xb +     C]; float x02 = x[xb + 2*C];
        float x10 = x[xb + sH      ]; float x11 = x[xb + sH + C]; float x12 = x[xb + sH + 2*C];
        float x20 = x[xb + 2*sH    ]; float x21 = x[xb + 2*sH + C]; float x22 = x[xb + 2*sH + 2*C];

        float sum = x00*w00 + x01*w01 + x02*w02
                  + x10*w10 + x11*w11 + x12*w12
                  + x20*w20 + x21*w21 + x22*w22;

        y[idx] = sum;
    }
}

dot_product.metal_source:
// dot_product: x^T y. Single reduction via simd_sum + cross-simdgroup sum.
#include <metal_stdlib>
using namespace metal;

kernel void dot_product_f32(
    device const float*  x  [[buffer(0)]],
    device const float*  y  [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   N  [[buffer(3)]],
    uint  tid              [[thread_position_in_threadgroup]])
{
    const uint tg_size = 1024;
    float sum = 0.0f;
    for (uint i = tid; i < N; i += tg_size)
        sum += x[i] * y[i];

    float sg_sum = simd_sum(sum);

    threadgroup float tg[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) tg[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sg_sum = tg[tid];
        for (uint s = 16; s > 0; s >>= 1)
            sg_sum += simd_shuffle_down(sg_sum, s);
    }
    if (tid == 0) *out = sg_sum;
}

dropout.metal_source:
// dropout (inverted): y = mask * x * (1/(1-p)).
// N=1M, n4=256K, grid=64K -> exactly 4 float4 per thread (16 floats = 64B).
// Block layout (contiguous): each simdgroup issues a 2 KB coalesced device
// read; 4 such requests fly per thread to saturate memory parallelism while
// keeping per-thread cache locality at one cache line per stream.
#include <metal_stdlib>
using namespace metal;

kernel void dropout_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  M       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  p       [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    const float scale = 1.0f / (1.0f - p);
    const device float4* X4 = reinterpret_cast<const device float4*>(X);
    const device float4* M4 = reinterpret_cast<const device float4*>(M);
    device       float4* Y4 = reinterpret_cast<device float4*>(Y);
    const uint n4 = N >> 2;
    const uint gs = grid_size;

    const uint base = tid * 4u;
    if (base + 3u < n4) {
        float4 x0 = X4[base + 0];
        float4 x1 = X4[base + 1];
        float4 x2 = X4[base + 2];
        float4 x3 = X4[base + 3];
        float4 m0 = M4[base + 0];
        float4 m1 = M4[base + 1];
        float4 m2 = M4[base + 2];
        float4 m3 = M4[base + 3];
        Y4[base + 0] = m0 * x0 * scale;
        Y4[base + 1] = m1 * x1 * scale;
        Y4[base + 2] = m2 * x2 * scale;
        Y4[base + 3] = m3 * x3 * scale;
        return;
    }
    for (uint i = tid; i < n4; i += gs) {
        Y4[i] = M4[i] * X4[i] * scale;
    }
}

elu.metal_source:
// elu: x if x>0 else α*(exp(x)-1). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void elu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    constant     float&  alpha     [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 neg = alpha * (exp(min(v, float4(0.0f))) - 1.0f);
        float4 out = select(neg, v, v > 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = out;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = v > 0.0f ? v : alpha * (exp(v) - 1.0f);
    }
}

embedding.metal_source:
// embedding: out[s, d] = table[(uint)indices[s], d]. (S,) × (V, D) → (S, D).
#include <metal_stdlib>
using namespace metal;

kernel void embedding_f32(
    device const float*  indices  [[buffer(0)]],
    device const float*  table    [[buffer(1)]],
    device       float*  y        [[buffer(2)]],
    constant     uint&   S        [[buffer(3)]],
    constant     uint&   V        [[buffer(4)]],
    constant     uint&   D        [[buffer(5)]],
    uint tid                     [[thread_position_in_grid]])
{
    const uint total = S * D;
    const uint grid_size = 64 * 1024;
    for (uint i = tid; i < total; i += grid_size) {
        uint s = i / D;
        uint d = i % D;
        uint idx = clamp(uint(indices[s]), 0u, V - 1u);
        y[i] = table[idx * D + d];
    }
}

exp.metal_source:
// exp: float4 grid-stride loop. Memory-bound elementwise.
#include <metal_stdlib>
using namespace metal;

kernel void exp_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        float4 r;
        r.x = fast::exp(v.x);
        r.y = fast::exp(v.y);
        r.z = fast::exp(v.z);
        r.w = fast::exp(v.w);
        *(reinterpret_cast<device float4*>(&y[i * 4])) = r;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = fast::exp(x[i]);
    }
}

frobenius_norm.metal_source:
// frobenius_norm: ||x||_F = sqrt(sum(x*x)). Single TG, 1024 threads. N=1024*1024.
#include <metal_stdlib>
using namespace metal;

kernel void frobenius_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    threadgroup float reduce[32];

    device const float4* x4 = (device const float4*)x;
    const uint N4 = N >> 2;

    float s = 0.0f;
    for (uint i = tid; i < N4; i += TG) {
        float4 v = x4[i];
        s += dot(v, v);
    }
    s = simd_sum(s);
    if ((tid & 31) == 0) reduce[tid >> 5] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        s = reduce[tid];
        s = simd_sum(s);
        if (tid == 0) y[0] = sqrt(s);
    }
}

fused_add_rms_norm.metal_source:
// fused_add_rms_norm: y = (x+r) * rsqrt(mean((x+r)^2) + eps). Per-row.
// D=1024, TG=1024. Single-simdgroup-per-row: only sg 0 (32 lanes) works,
// each lane handles 8 float4 = 32 elements. Two-pass (recompute) keeps
// register pressure low so the 1024-thread TG dispatches.
#include <metal_stdlib>
using namespace metal;

kernel void fused_add_rms_norm_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   D       [[buffer(3)]],
    constant     float&  eps     [[buffer(4)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid3.x;
    if (t >= 32u) return;

    const uint row = tgid.y;

    device const float4* xr = (device const float4*)(X + row * D);
    device const float4* rr = (device const float4*)(R + row * D);
    device       float4* yr = (device       float4*)(Y + row * D);

    float sumsq = 0.0f;
    #pragma unroll
    for (uint k = 0; k < 8; ++k) {
        uint i = k * 32u + t;
        float4 v = xr[i] + rr[i];
        sumsq += dot(v, v);
    }

    sumsq = simd_sum(sumsq);
    float inv = rsqrt(sumsq / float(D) + eps);

    #pragma unroll
    for (uint k = 0; k < 8; ++k) {
        uint i = k * 32u + t;
        float4 v = xr[i] + rr[i];
        yr[i] = v * inv;
    }
}

gelu.metal_source:
// gelu: 0.5 * x * (1 + tanh(sqrt(2/pi) * (x + 0.044715 * x^3))).
#include <metal_stdlib>
using namespace metal;

constant constexpr float gelu_k = 0.79788456f;

kernel void gelu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = 0.5f * v * (1.0f + tanh(gelu_k * (v + 0.044715f * v * v * v)));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = 0.5f * v * (1.0f + tanh(gelu_k * (v + 0.044715f * v * v * v)));
    }
}

gelu_linear.metal_source:
// gelu_linear: y = gelu(x @ W). Fused matmul + erf-GELU in store phase.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

// erf via 6th-order rational approximation (Abramowitz & Stegun 7.1.26), |err| < 1.5e-7.
// Vectorized to evaluate 4 lanes in parallel — saves scalar tail vs the original loop.
static inline float4 erf4(float4 z) {
    float4 az = fabs(z);
    float4 t  = 1.0f / (1.0f + 0.3275911f * az);
    float4 p  = ((((1.061405429f * t - 1.453152027f) * t
              + 1.421413741f) * t - 0.284496736f) * t + 0.254829592f) * t;
    float4 y  = 1.0f - p * exp(-z * z);
    return copysign(y, z);
}
static inline float4 gelu4(float4 v) {
    const float k = 0.70710678118654752f; // 1/sqrt(2)
    return 0.5f * v * (1.0f + erf4(v * k));
}

constant constexpr uint BM  = 64, BN  = 64, BK  = 16;
constant constexpr uint SM  = 16, SN  = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;

kernel void gelu_linear_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  M   [[buffer(3)]],
    constant     uint&  N   [[buffer(4)]],
    constant     uint&  K   [[buffer(5)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float shared[2 * BM * LDA + 2 * BK * LDB];
    threadgroup float (*As)[BM * LDA] = (threadgroup float (*)[BM * LDA]) &shared[0];
    threadgroup float (*Bs)[BK * LDB] = (threadgroup float (*)[BK * LDB]) &shared[2 * BM * LDA];
    const uint sm = sgid / SIMDS_N, sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM, c_col0 = tgid.x * BN;
    const uint a_row = lid / 4, a_c4 = lid % 4, b_row = lid / 16, b_c4 = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    { // Prologue
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    const uint num_k_tiles = K / BK; uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf, k0_nxt = (kt + 1) * BK;
        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);
        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup); buf = next;
    }
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i) simdgroup_load(A_blk[i], &As[buf][(sm*SM+i*8)*LDA+kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j) simdgroup_load(B_blk[j], &Bs[buf][kc*LDB+sn*SN+j*8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);
    threadgroup float* Cs = &shared[0];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j], &Cs[(sm*SM + i*8) * BN + sn*SN + j*8], BN);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    #pragma unroll
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
        *reinterpret_cast<device float4*>(&C[(c_row0 + r) * N + (c_col0 + c)]) = gelu4(v);
    }
}

group_norm.metal_source:
// group_norm: normalize per-sample per-group over (CG, H, W) where CG = C/G.
#include <metal_stdlib>
using namespace metal;

kernel void group_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     uint&   G       [[buffer(6)]],
    constant     float&  eps     [[buffer(7)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint ng  = tgid.y;     // 0 .. N*G - 1
    const uint n   = ng / G;
    const uint g   = ng % G;
    const uint CG  = C / G;
    const uint block = CG * H * W;
    device const float* base_in  = X + (n * C + g * CG) * H * W;
    device       float* base_out = Y + (n * C + g * CG) * H * W;

    float sum = 0.0f, sumsq = 0.0f;
    for (uint i = tid; i < block; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(block);
    float var  = max(tg_q[0] / float(block) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    for (uint i = tid; i < block; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

hardsigmoid.metal_source:
// hardsigmoid: clamp(x/6 + 0.5, 0, 1).
#include <metal_stdlib>
using namespace metal;

kernel void hardsigmoid_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = clamp(v / 6.0f + 0.5f, 0.0f, 1.0f);
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = clamp(x[i] / 6.0f + 0.5f, 0.0f, 1.0f);
    }
}

hardswish.metal_source:
// hardswish: x * clamp(x+3, 0, 6) / 6. Float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void hardswish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v * clamp(v + 3.0f, 0.0f, 6.0f) / 6.0f;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        y[i] = x[i] * clamp(x[i] + 3.0f, 0.0f, 6.0f) / 6.0f;
}

hardtanh.metal_source:
// hardtanh: out = clamp(x, -1, 1). float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void hardtanh_f32(
