}

huber_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

// Memory-bound elementwise. N=1M, grid=64K threads => 16 elements/thread.
// Use float4 vectorized loads/stores: 4 float4 per thread = 16 elements,
// fully utilizing 128B loads and halving instruction count.
kernel void huber_loss_f32(
    device const float*  pred      [[buffer(0)]],
    device const float*  target    [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  delta     [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint N4 = N >> 2;
    device const float4* pred4 = reinterpret_cast<device const float4*>(pred);
    device const float4* tgt4  = reinterpret_cast<device const float4*>(target);
    device       float4* y4    = reinterpret_cast<device       float4*>(y);
    const float half_delta = 0.5f * delta;

    // Branchless: let m = min(|r|, delta). Then loss = 0.5*m^2 + delta*(|r| - m).
    //   if |r| <= delta: m=|r|, second term=0, result = 0.5*r^2.
    //   if |r| > delta:  m=delta, result = 0.5*delta^2 + delta*(|r| - delta).
    for (uint i = tid; i < N4; i += grid_size) {
        float4 r = pred4[i] - tgt4[i];
        float4 a = fabs(r);
        float4 m = fmin(a, delta);
        y4[i] = fma(0.5f * m, m, delta * (a - m));
    }

    // Tail (N not divisible by 4) — ranks past N4*4
    uint base = N4 << 2;
    for (uint i = base + tid; i < N; i += grid_size) {
        float r = pred[i] - target[i];
        float a = fabs(r);
        float m = fmin(a, delta);
        y[i] = fma(0.5f * m, m, delta * (a - m));
    }
}

instance_norm.metal_source:
// instance_norm: normalize per-sample per-channel over (H, W).
#include <metal_stdlib>
using namespace metal;

kernel void instance_norm_f32(
    device const float*  X       [[buffer(0)]],
    device       float*  Y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    constant     uint&   H       [[buffer(4)]],
    constant     uint&   W       [[buffer(5)]],
    constant     float&  eps     [[buffer(6)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint TG = 1024;
    const uint tid = tid3.x;
    const uint nc = tgid.y;
    const uint HW = H * W;
    device const float* base_in  = X + nc * HW;
    device       float* base_out = Y + nc * HW;

    float sum = 0.0f, sumsq = 0.0f;
    for (uint i = tid; i < HW; i += TG) {
        float v = base_in[i];
        sum   += v;
        sumsq += v * v;
    }
    sum   = simd_sum(sum);
    sumsq = simd_sum(sumsq);

    threadgroup float tg_s[32], tg_q[32];
    uint sg = tid >> 5;
    if ((tid & 31) == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (tid < 32) {
        sum   = tg_s[tid];
        sumsq = tg_q[tid];
        for (uint s = 16; s > 0; s >>= 1) {
            sum   += simd_shuffle_down(sum,   s);
            sumsq += simd_shuffle_down(sumsq, s);
        }
        if (tid == 0) { tg_s[0] = sum; tg_q[0] = sumsq; }
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float mean = tg_s[0] / float(HW);
    float var  = max(tg_q[0] / float(HW) - mean * mean, 0.0f);
    float inv  = rsqrt(var + eps);
    for (uint i = tid; i < HW; i += TG)
        base_out[i] = (base_in[i] - mean) * inv;
}

kl_div_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void kl_div_loss_f32(
    device const float*  log_pred  [[buffer(0)]],
    device const float*  target    [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        float t = fabs(target[i]) + 1e-6f;
        float lp = -fabs(log_pred[i]);
        y[i] = t * (log(t) - lp);
    }
}

l1_norm.metal_source:
// l1_norm: sum(abs(x)) per row. Simdgroup reduction.
#include <metal_stdlib>
using namespace metal;

kernel void l1_norm_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    float val = fabs(x[row * N + t]);
    float sum = simd_sum(val);

    threadgroup float tg_sum[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) tg_sum[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sum = tg_sum[t];
        for (uint s = 16; s > 0; s >>= 1)
            sum += simd_shuffle_down(sum, s);
    }
    if (t == 0) y[row] = sum;
}

l2_norm.metal_source:
// l2_norm: sqrt(sum(x^2)) per row. Simdgroup reduction.
#include <metal_stdlib>
using namespace metal;

kernel void l2_norm_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    float val = x[row * N + t];
    float sumsq = simd_sum(val * val);

    threadgroup float tg_sum[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) tg_sum[sg] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sumsq = tg_sum[t];
        for (uint s = 16; s > 0; s >>= 1)
            sumsq += simd_shuffle_down(sumsq, s);
    }
    if (t == 0) y[row] = sqrt(sumsq);
}

leaky_relu.metal_source:
// leaky_relu: out = max(x, 0) + slope * min(x, 0). 1024 thr/tg, float4.
#include <metal_stdlib>
using namespace metal;

kernel void leaky_relu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    constant     float&  slope     [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        v = fmax(v, 0.0f) + slope * fmin(v, 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = fmax(v, 0.0f) + slope * fmin(v, 0.0f);
    }
}

linear_bias.metal_source:
// linear_bias: y = x @ W + b. (M,K)@(K,N)+(N,). M=N=K=256.
// Fuses bias-add into the epilogue via threadgroup memory to avoid the
// store-then-reload of Y that the original kernel performed.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 16;
constant constexpr uint SM = 16, SN = 32;
constant constexpr uint SIMDS_N = BN / SN;
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;
constant constexpr uint PAD = 4, LDA = BK + PAD, LDB = BN + PAD;
constant constexpr uint LDC = BN + PAD;
constant constexpr uint TILES_N = 256 / BN;   // 4
constant constexpr uint ACTIVE_TG = TILES_N * (256 / BM);  // 16

kernel void linear_bias_f32(
    device const float* X    [[buffer(0)]],
    device const float* W    [[buffer(1)]],
    device const float* Bias [[buffer(2)]],
    device       float* Y    [[buffer(3)]],
    constant     uint&  M    [[buffer(4)]],
    constant     uint&  N    [[buffer(5)]],
    constant     uint&  K    [[buffer(6)]],
    uint tgid_lin            [[threadgroup_position_in_grid]],
    uint sgid                [[simdgroup_index_in_threadgroup]],
    uint lid                 [[thread_index_in_threadgroup]])
{
    if (tgid_lin >= ACTIVE_TG) return;
    const uint tx = tgid_lin % TILES_N;
    const uint ty = tgid_lin / TILES_N;

    // Union the A/B staging buffers with the C epilogue staging buffer to
    // stay within the 32 KB threadgroup-memory budget. A/B are dead by the
    // time we need C/bias.
    threadgroup float scratch[4736];  // = max(2*BM*LDA + 2*BK*LDB, BM*LDC + BN)
    threadgroup float (*As)[BM * LDA] = reinterpret_cast<threadgroup float (*)[BM * LDA]>(scratch);
    threadgroup float (*Bs)[BK * LDB] = reinterpret_cast<threadgroup float (*)[BK * LDB]>(scratch + 2 * BM * LDA);
    threadgroup float* Cs        = scratch;
    threadgroup float* bias_tile = scratch + BM * LDC;

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;
    const uint c_col0 = tx * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[b_row * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = K / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + a_row) * K + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[(k0_nxt + b_row) * N + c_col0 + b_c4 * 4]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    // Stage the matmul tile into threadgroup memory so we can fuse the
    // bias-add into the final device write (no read-modify-write on Y).
    // Barrier first: the matmul tail above still reads Bs[buf], whose region
    // aliases bias_tile in the unioned scratch. Wait for all simdgroups to
    // finish their tail loads before we clobber that memory.
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (lid < BN)
        bias_tile[lid] = Bias[c_col0 + lid];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &Cs[(sm * SM + i * 8) * LDC + sn * SN + j * 8],
                            LDC);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint total_f4 = BM * BN / 4;
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * LDC + c]);
        float4 b = *reinterpret_cast<threadgroup float4*>(&bias_tile[c]);
        *reinterpret_cast<device float4*>(&Y[(c_row0 + r) * N + c_col0 + c]) = v + b;
    }
}

llama_attention.metal_source:
// llama_attention: GQA + RoPE attention (no KV cache, no LN).
#include <metal_stdlib>
using namespace metal;

#define S    64
#define D    128
#define HH   4
#define HKV  2
#define DH   32
#define G    2
#define TG   1024

// v3 optimizations vs baseline (24KB TG):
//   - Within a kv-group, fuse the G=2 query heads in the attention pass so each
//     Kh/Vh threadgroup read is reused across both heads (halves TG reads).
//   - float2 reads from Kh/Vh in the inner kt loop.
//   - Keep TG memory at 24KB (Kh + Vh + single oh) for occupancy parity.
//   - Process head 0 output projection while still holding head 1 attention
//     result in registers.
//
// TG memory: Kh (8KB) + Vh (8KB) + oh (8KB) = 24KB.

kernel void llama_attention_f32(
    device const float* x      [[buffer(0)]],
    device const float* W_qkv  [[buffer(1)]],
    device const float* W_o    [[buffer(2)]],
    device       float* y      [[buffer(3)]],
    constant uint& S_   [[buffer(4)]],
    constant uint& D_   [[buffer(5)]],
    constant uint& H_   [[buffer(6)]],
    constant uint& Hkv_ [[buffer(7)]],
    constant float& base [[buffer(8)]],
    uint3 tid [[thread_position_in_threadgroup]])
{
    const uint t = tid.x;
    constexpr uint QKV_W = D + 2u * HKV * DH;   // 256

    threadgroup float Kh[S * DH];
    threadgroup float Vh[S * DH];
    threadgroup float oh[S * DH];

    const float inv_sqrt_dh = rsqrt(float(DH));
    const float two_over_dh = 2.0f / float(DH);
    const float log_base    = fast::log(base);

    const uint sq   = t >> 4;
    const uint lane = t & 15;
    const uint i_pair = lane;
    const uint dh0 = 2 * i_pair;
    const uint dh1 = dh0 + 1;
    const uint off = sq * D;

    const float pos    = float(sq);
    const float omega  = fast::exp(log_base * (-two_over_dh * float(i_pair)));
    const float ang    = pos * omega;
    const float c_rope = fast::cos(ang);
    const float s_rope = fast::sin(ang);

    // Fused projection of Q (all heads) and K, V (all kv-heads) in one sweep.
    float qreg0[HH], qreg1[HH];
    float kreg0[HKV], kreg1[HKV];
    float vreg0[HKV], vreg1[HKV];
    #pragma unroll
    for (uint h = 0; h < HH; ++h) { qreg0[h] = 0.f; qreg1[h] = 0.f; }
    #pragma unroll
    for (uint kv = 0; kv < HKV; ++kv) {
        kreg0[kv] = 0.f; kreg1[kv] = 0.f;
        vreg0[kv] = 0.f; vreg1[kv] = 0.f;
    }

    for (uint d = 0; d < D; ++d) {
        float xv = x[off + d];
        const device float2* wrow2 =
            (const device float2*)(W_qkv + d * QKV_W) + i_pair;
        #pragma unroll
        for (uint h = 0; h < HH; ++h) {
            float2 w = wrow2[h * (DH/2)];
            qreg0[h] += xv * w.x;
            qreg1[h] += xv * w.y;
        }
        const uint k_pair_off = D / 2;
        const uint v_pair_off = (D + HKV*DH) / 2;
        #pragma unroll
        for (uint kv = 0; kv < HKV; ++kv) {
            float2 wk = wrow2[k_pair_off + kv * (DH/2)];
            float2 wv = wrow2[v_pair_off + kv * (DH/2)];
            kreg0[kv] += xv * wk.x;
            kreg1[kv] += xv * wk.y;
            vreg0[kv] += xv * wv.x;
            vreg1[kv] += xv * wv.y;
        }
    }
    // RoPE Q.
    #pragma unroll
    for (uint h = 0; h < HH; ++h) {
        float q0 = qreg0[h], q1 = qreg1[h];
        qreg0[h] = q0 * c_rope - q1 * s_rope;
        qreg1[h] = q0 * s_rope + q1 * c_rope;
    }
    // RoPE K.
    #pragma unroll
    for (uint kv = 0; kv < HKV; ++kv) {
        float k0 = kreg0[kv], k1 = kreg1[kv];
        kreg0[kv] = k0 * c_rope - k1 * s_rope;
        kreg1[kv] = k0 * s_rope + k1 * c_rope;
    }

    for (uint kvh = 0; kvh < HKV; ++kvh) {
        Kh[sq*DH + dh0] = kreg0[kvh];
        Kh[sq*DH + dh1] = kreg1[kvh];
        Vh[sq*DH + dh0] = vreg0[kvh];
        Vh[sq*DH + dh1] = vreg1[kvh];
        threadgroup_barrier(mem_flags::mem_threadgroup);

        // Q regs for both query heads in this kv-group.
        const float qa0 = qreg0[kvh*G + 0];
        const float qa1 = qreg1[kvh*G + 0];
        const float qb0 = qreg0[kvh*G + 1];
        const float qb1 = qreg1[kvh*G + 1];

        float outA0 = 0.f, outA1 = 0.f, mA = -INFINITY, lA = 0.f;
        float outB0 = 0.f, outB1 = 0.f, mB = -INFINITY, lB = 0.f;

        for (uint kt = 0; kt < S; ++kt) {
            const threadgroup float2* Kh2 = (const threadgroup float2*)(Kh + kt*DH);
            const threadgroup float2* Vh2 = (const threadgroup float2*)(Vh + kt*DH);
            float2 kv2 = Kh2[i_pair];
            float2 vv2 = Vh2[i_pair];

            // Head A.
            {
                float partial = qa0 * kv2.x + qa1 * kv2.y;
                partial += simd_shuffle_xor(partial, 1);
                partial += simd_shuffle_xor(partial, 2);
                partial += simd_shuffle_xor(partial, 4);
                partial += simd_shuffle_xor(partial, 8);
                float score = partial * inv_sqrt_dh;
                float mn = max(mA, score);
                float alpha = fast::exp(mA - mn);
                float beta  = fast::exp(score - mn);
                outA0 = outA0 * alpha + beta * vv2.x;
                outA1 = outA1 * alpha + beta * vv2.y;
                lA = lA * alpha + beta;
                mA = mn;
            }
            // Head B.
            {
                float partial = qb0 * kv2.x + qb1 * kv2.y;
                partial += simd_shuffle_xor(partial, 1);
                partial += simd_shuffle_xor(partial, 2);
                partial += simd_shuffle_xor(partial, 4);
                partial += simd_shuffle_xor(partial, 8);
                float score = partial * inv_sqrt_dh;
                float mn = max(mB, score);
                float alpha = fast::exp(mB - mn);
                float beta  = fast::exp(score - mn);
                outB0 = outB0 * alpha + beta * vv2.x;
                outB1 = outB1 * alpha + beta * vv2.y;
                lB = lB * alpha + beta;
                mB = mn;
            }
        }

        // Reuse Kh as a second oh buffer (Kh no longer needed for this kvh).
        // Barrier first: ensure all threads have finished reading Kh in the
        // attention loop before any thread overwrites it.
        threadgroup_barrier(mem_flags::mem_threadgroup);
        threadgroup float* ohA = oh;
        threadgroup float* ohB = Kh;
        {
            float invA = 1.0f / lA;
            float invB = 1.0f / lB;
            ohA[sq*DH + dh0] = outA0 * invA;
            ohA[sq*DH + dh1] = outA1 * invA;
            ohB[sq*DH + dh0] = outB0 * invB;
            ohB[sq*DH + dh1] = outB1 * invB;
            threadgroup_barrier(mem_flags::mem_threadgroup);
        }

        // Fused output projection: y += ohA @ W_o[hA] + ohB @ W_o[hB].
        {
            const uint hA = kvh * G + 0;
            const uint hB = kvh * G + 1;
            for (uint idx = t; idx < S*D; idx += TG) {
                const uint sr   = idx / D;
                const uint dout = idx % D;
                float acc = 0.f;
                const threadgroup float* ohA_row = ohA + sr*DH;
                const threadgroup float* ohB_row = ohB + sr*DH;
                const device float* WoA = W_o + hA*DH*D + dout;
                const device float* WoB = W_o + hB*DH*D + dout;
                #pragma unroll 8
                for (uint dh = 0; dh < DH; ++dh) {
                    acc += ohA_row[dh] * WoA[dh*D];
                    acc += ohB_row[dh] * WoB[dh*D];
                }
                if (kvh == 0) { y[idx] = acc; } else { y[idx] += acc; }
            }
            threadgroup_barrier(mem_flags::mem_threadgroup | mem_flags::mem_device);
        }
    }
}

log.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void log_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    // Mirror baseline: log(|x| + tiny) to keep random-normal inputs finite.
    for (uint i = tid; i < N; i += grid_size) {
        y[i] = log(fabs(x[i]) + 1e-30f);
    }
}

log_softmax_cross_entropy.metal_source:
// log_softmax_cross_entropy: fused log_softmax + NLL. Output (N,).
// Optimization: combine the per-row sum_exp, sum(yv), sum(yv*lv) into a
// single reduction pass after computing row_max. Then
//     loss = lse * sum_yv - sum_yv_lv,
// where lse = row_max + log(sum_exp). This removes one whole reduction
// round trip vs. computing nll = yv*(lse - lv) and reducing it separately.
//
// Disjoint scratch slots per reduction phase to avoid any inter-phase
// races in the cross-simdgroup step.
#include <metal_stdlib>
using namespace metal;

kernel void log_softmax_cross_entropy_f32(
    device const float*  L        [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint tid  = tid3.x;
    const uint row  = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;
    device const float* lp = L  + row * C;
    device const float* yp = Yh + row * C;

    // Disjoint scratch slots for each reduction to make the cross-simdgroup
    // step race-free without needing barriers to "clear" slots.
    threadgroup float red_max[32];
    threadgroup float red_e  [32];
    threadgroup float red_y  [32];
    threadgroup float red_yl [32];
    threadgroup float row_max_s;
    threadgroup float lse_s;

    float lv = lp[tid];
    float yv = yp[tid];

    // ---- Phase A: row_max ----
    float mx = simd_max(lv);
    if (lane == 0) red_max[sgid] = mx;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float v = simd_max(red_max[lane]);
        if (lane == 0) row_max_s = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float row_max = row_max_s;

    // ---- Phase B: in parallel sum(exp(lv-max)), sum(yv), sum(yv*lv) ----
    float e   = fast::exp(lv - row_max);
    float yvl = yv * lv;

    float s_e  = simd_sum(e);
    float s_y  = simd_sum(yv);
    float s_yl = simd_sum(yvl);
    if (lane == 0) {
        red_e [sgid] = s_e;
        red_y [sgid] = s_y;
        red_yl[sgid] = s_yl;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float ve  = simd_sum(red_e [lane]);
        float vy  = simd_sum(red_y [lane]);
        float vyl = simd_sum(red_yl[lane]);
        if (lane == 0) {
            float lse = row_max + fast::log(ve);
            lse_s = lse;
            out[row] = lse * vy - vyl;
        }
    }
    (void)lse_s; // suppress unused warning; not read by other threads
}

logsigmoid.metal_source:
// logsigmoid: numerically stable log(sigmoid(x)).
#include <metal_stdlib>
using namespace metal;

inline float logsigmoid_scalar(float v) {
    if (v > 0.0f) {
        return -log(1.0f + exp(-v));
    } else {
        return v - log(1.0f + exp(v));
    }
}

kernel void logsigmoid_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = float4(
            logsigmoid_scalar(v.x),
            logsigmoid_scalar(v.y),
            logsigmoid_scalar(v.z),
            logsigmoid_scalar(v.w));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = logsigmoid_scalar(x[i]);
    }
}

manhattan_similarity.metal_source:
// manhattan_similarity: L1 distance per row. simd_sum(|x - y|).
#include <metal_stdlib>
using namespace metal;

kernel void manhattan_similarity_f32(
    device const float*  x   [[buffer(0)]],
    device const float*  y   [[buffer(1)]],
    device       float*  out [[buffer(2)]],
    constant     uint&   D   [[buffer(3)]],
    uint3 tid               [[thread_position_in_threadgroup]],
    uint3 tgid              [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * D;
    const uint sg = t >> 5;
    const uint lane = t & 31;

    float sum = simd_sum(fabs(x[off + t] - y[off + t]));

    threadgroup float tg[32];
    if (lane == 0) tg[sg] = sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float v = tg[lane];
        v = simd_sum(v);
        if (lane == 0) out[row] = v;
    }
}

masked_cumsum.metal_source:
// masked_cumsum: per-row cumsum(x * mask). Two-level scan with float4 loads.
// 1024-col row -> 256 active threads * float4 = 1024 elements per TG.
#include <metal_stdlib>
using namespace metal;

kernel void masked_cumsum_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  m       [[buffer(1)]],
    device       float*  y       [[buffer(2)]],
    constant     uint&   C       [[buffer(3)]],
    uint3 tid                    [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    constexpr uint NSG = 8;        // 256/32
    threadgroup float tg_totals[NSG];

    const uint t   = tid.x;
    const uint row = tgid.y;
    const uint sg  = t >> 5;
    const uint sl  = t & 31;
    const bool active = (t < 256u);

    float4 s = float4(0.0f);
    float local_inc = 0.0f;
    float local_exc = 0.0f;
    uint base = 0u;

    if (active) {
        base = row * C + (t << 2);
        // Issue both loads early for ILP
        float4 xv = *reinterpret_cast<device const float4*>(x + base);
        float4 mv = *reinterpret_cast<device const float4*>(m + base);
        float4 v = xv * mv;
        s.x = v.x;
        s.y = s.x + v.y;
        s.z = s.y + v.z;
        s.w = s.z + v.w;
        local_inc = simd_prefix_inclusive_sum(s.w);
        local_exc = local_inc - s.w;

        if (sl == 31u) tg_totals[sg] = local_inc;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0u) {
        float v8 = (sl < NSG) ? tg_totals[sl] : 0.0f;
        float prefix = simd_prefix_exclusive_sum(v8);
        if (sl < NSG) tg_totals[sl] = prefix;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (active) {
        float off = tg_totals[sg] + local_exc;
        float4 out = s + off;
        *reinterpret_cast<device float4*>(y + base) = out;
    }
}

matmul_gelu_softmax.metal_source:
// matmul_gelu_softmax: y = softmax(GELU(x @ w), axis=-1)
// x (256,256), w (256,256), output (256,256). Grid (256,256,1) TG (256,1,1).
// BM=16, BN=256, BK=8. 16 TGs across 10 M4 cores. Double-buffered B.
//
// 8 simdgroups (256 threads). SIMDS_M=2, SIMDS_N=4 (SM=8, SN=64). MMA_M=1, MMA_N=8.
// Softmax: 16 threads/row, simd_shuffle_xor stride 1..8 inside a 16-lane half.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 16;
constant constexpr uint BN = 256;
constant constexpr uint BK = 16;
constant constexpr uint LDA = BK;
constant constexpr uint LDB = BN;
constant constexpr uint LDC = BN;

constant constexpr uint SIMDS_M = 2;
constant constexpr uint SIMDS_N = 4;
constant constexpr uint SM = BM / SIMDS_M;  // 8
constant constexpr uint SN = BN / SIMDS_N;  // 64
constant constexpr uint MMA_N = SN / 8;     // 8

kernel void matmul_gelu_softmax_f32(
    device const float* X [[buffer(0)]],
    device const float* W [[buffer(1)]],
    device       float* Y [[buffer(2)]],
    constant     uint&  M [[buffer(3)]],
    constant     uint&  N [[buffer(4)]],
    constant     uint&  K [[buffer(5)]],
    uint3 tgid            [[threadgroup_position_in_grid]],
    uint  sgid            [[simdgroup_index_in_threadgroup]],
    uint  lid             [[thread_index_in_threadgroup]])
{
    const uint ty = tgid.y;
    if (ty >= 16) return;

    threadgroup float As[BM * LDA];        // 16*16*4 = 1024 B
    // Bs (BK*LDB=16*256=16384 B) and Cs (BM*LDC=16*256=16384 B) overlay the
    // same TG buffer: Bs lifetime ends before Cs begins (after MMA finishes).
    threadgroup float shared_bc[BM * LDC]; // 16384 B
    threadgroup float* Bs = shared_bc;     // alias during matmul
    threadgroup float* Cs = shared_bc;     // alias after matmul

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_N];
    #pragma unroll
    for (uint j = 0; j < MMA_N; ++j)
        C_acc[j] = simdgroup_matrix<float, 8, 8>(0.0f);

    const uint num_k_tiles = K / BK;       // 32

    for (uint kt = 0; kt < num_k_tiles; ++kt) {
        const uint k0 = kt * BK;
        // A: 16 rows × 16 cols = 256 floats = 64 float4 → 64 threads.
        if (lid < 64) {
            uint ar = lid >> 2;
            uint ac4 = lid & 3;
            *reinterpret_cast<threadgroup float4*>(&As[ar * LDA + ac4 * 4]) =
                *reinterpret_cast<const device float4*>(&X[(c_row0 + ar) * K + k0 + ac4 * 4]);
        }
        // B: 16 rows × 256 cols = 1024 float4 → 4 per thread.
        #pragma unroll
        for (uint q = 0; q < 4; ++q) {
            uint idx = q * 256 + lid;
            uint br = idx / 64;
            uint bc4 = idx % 64;
            *reinterpret_cast<threadgroup float4*>(&Bs[br * LDB + bc4 * 4]) =
                *reinterpret_cast<const device float4*>(&W[(k0 + br) * N + bc4 * 4]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk, B_blk[MMA_N];
            simdgroup_load(A_blk, &As[(sm * SM) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[j], A_blk, B_blk[j], C_acc[j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
    }

    #pragma unroll
    for (uint j = 0; j < MMA_N; ++j)
        simdgroup_store(C_acc[j], &Cs[(sm * SM) * LDC + sn * SN + j * 8], LDC);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // ---- Softmax phase (same as before)
    const uint r = lid >> 4;
    const uint lane16 = lid & 15;
    const uint col_base = lane16 * 16;

    const float k_inv_sqrt2 = 0.70710678118654752f;
    float vals[16];
    float local_max = -INFINITY;

    threadgroup const float* Crow = &Cs[r * LDC + col_base];
    #pragma unroll
    for (uint t = 0; t < 16; t += 4) {
        float4 v = *reinterpret_cast<threadgroup const float4*>(Crow + t);
        float ss[4] = { v.x, v.y, v.z, v.w };
        #pragma unroll
        for (uint u = 0; u < 4; ++u) {
            float s = ss[u];
            float z = s * k_inv_sqrt2;
            float at = 1.0f / (1.0f + 0.3275911f * fabs(z));
            float yp = 1.0f - (((((1.061405429f * at - 1.453152027f) * at)
                          + 1.421413741f) * at - 0.284496736f) * at + 0.254829592f) * at * fast::exp(-z * z);
            float erfz = copysign(yp, z);
            float gv = 0.5f * s * (1.0f + erfz);
            vals[t + u] = gv;
            local_max = fmax(local_max, gv);
        }
    }
    float rmax = local_max;
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 1));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 2));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 4));
    rmax = fmax(rmax, simd_shuffle_xor(rmax, 8));

    float local_sum = 0.0f;
    #pragma unroll
    for (uint u = 0; u < 16; ++u) {
        float e = fast::exp(vals[u] - rmax);
        vals[u] = e;
        local_sum += e;
    }
    float rsum = local_sum;
    rsum += simd_shuffle_xor(rsum, 1);
    rsum += simd_shuffle_xor(rsum, 2);
    rsum += simd_shuffle_xor(rsum, 4);
    rsum += simd_shuffle_xor(rsum, 8);
    float inv = 1.0f / rsum;

    device float* Yrow = &Y[(c_row0 + r) * N + col_base];
    #pragma unroll
    for (uint t = 0; t < 16; t += 4) {
        float4 o = { vals[t]*inv, vals[t+1]*inv, vals[t+2]*inv, vals[t+3]*inv };
        *reinterpret_cast<device float4*>(Yrow + t) = o;
    }
}

matmul_sub_mul_relu.metal_source:
// matmul_sub_mul_relu: y = ReLU((x @ w - sub_val) * mul_val).
// Optimized for M=N=K=256 on M4: 8x8 simdgroup MMA tiles, BM=BN=64, BK=32,
// double-buffered float4 loads, fused (sub + mul + ReLU) epilogue.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM = 64, BN = 64, BK = 32;
constant constexpr uint SM = 16, SN = 32;
constant constexpr uint SIMDS_N = BN / SN;          // 2
constant constexpr uint MMA_M = SM / 8, MMA_N = SN / 8;  // 2, 4
constant constexpr uint LDA = BK, LDB = BN;
constant constexpr uint TILES_N = 256 / BN;          // 4

kernel void matmul_sub_mul_relu_f32(
    device const float* X       [[buffer(0)]],
    device const float* W       [[buffer(1)]],
    device       float* Y       [[buffer(2)]],
    constant     uint&  M       [[buffer(3)]],
    constant     uint&  N       [[buffer(4)]],
    constant     uint&  K       [[buffer(5)]],
    constant     float& sub_val [[buffer(6)]],
    constant     float& mul_val [[buffer(7)]],
    uint tgid_lin               [[threadgroup_position_in_grid]],
    uint sgid                   [[simdgroup_index_in_threadgroup]],
    uint lid                    [[thread_index_in_threadgroup]],
    uint lane                   [[thread_index_in_simdgroup]])
{
    const uint tx = tgid_lin % TILES_N;
    const uint ty = tgid_lin / TILES_N;

    // Double-buffered A, B; Cs aliases. 32KB tg_mem.
    constexpr uint AS_SZ = 2 * BM * LDA;   // 4096
    constexpr uint BS_SZ = 2 * BK * LDB;   // 4096
    constexpr uint SCRATCH = AS_SZ + BS_SZ; // 8192 floats = 32KB
    threadgroup float scratch[SCRATCH];
    threadgroup float (*As)[BM * LDA] = reinterpret_cast<threadgroup float(*)[BM * LDA]>(&scratch[0]);
    threadgroup float (*Bs)[BK * LDB] = reinterpret_cast<threadgroup float(*)[BK * LDB]>(&scratch[AS_SZ]);
    threadgroup float* Cs = &scratch[0];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = ty * BM;
    const uint c_col0 = tx * BN;

    const uint a_row = lid / 8;
    const uint a_c4  = lid % 8;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    // Prologue: tile 0.
    #pragma unroll
    for (uint p = 0; p < 2; ++p) {
        uint r = a_row + p * 32;
        *reinterpret_cast<threadgroup float4*>(&As[0][r * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&X[(c_row0 + r) * K + a_c4 * 4]);
    }
    #pragma unroll
    for (uint p = 0; p < 2; ++p) {
        uint r = b_row + p * 16;
        *reinterpret_cast<threadgroup float4*>(&Bs[0][r * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&W[r * N + c_col0 + b_c4 * 4]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = K / BK;   // 8
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        #pragma unroll
        for (uint p = 0; p < 2; ++p) {
            uint r = a_row + p * 32;
            *reinterpret_cast<threadgroup float4*>(&As[next][r * LDA + a_c4 * 4]) =
                *reinterpret_cast<const device float4*>(&X[(c_row0 + r) * K + k0_nxt + a_c4 * 4]);
        }
        #pragma unroll
        for (uint p = 0; p < 2; ++p) {
            uint r = b_row + p * 16;
            *reinterpret_cast<threadgroup float4*>(&Bs[next][r * LDB + b_c4 * 4]) =
                *reinterpret_cast<const device float4*>(&W[(k0_nxt + r) * N + c_col0 + b_c4 * 4]);
        }

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }
        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    // Last K-tile compute.
    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Stage C tiles in threadgroup (aliased over As/Bs).
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &Cs[(sm * SM + i * 8) * BN + (sn * SN + j * 8)],
                            BN);
    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Fused epilogue: sub, mul, ReLU; vector store.
    const uint total_f4 = BM * BN / 4;       // 1024
    #pragma unroll
    for (uint idx = lid; idx < total_f4; idx += 256) {
        uint r = (idx * 4) / BN;
        uint c = (idx * 4) % BN;
        float4 v = *reinterpret_cast<threadgroup float4*>(&Cs[r * BN + c]);
        float4 out = fmax((v - sub_val) * mul_val, float4(0.0f));
        *reinterpret_cast<device float4*>(&Y[(c_row0 + r) * N + c_col0 + c]) = out;
    }
}

matrix_add.metal_source:
// matrix_add: C = A + B. Process 2x float4 per iteration for better ILP.
#include <metal_stdlib>
using namespace metal;

kernel void matrix_add_f32(
    device const float4* A         [[buffer(0)]],
    device const float4* B         [[buffer(1)]],
    device       float4* C         [[buffer(2)]],
    constant     uint&   N         [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint grid_size = 64u * 1024u;
    const uint n4 = N >> 2;

    // Each thread processes 4 float4 stride=grid_size
    // n4=262144, grid=65536, 4 iters/thread.
    // Unroll: prefetch all 4 loads, then issue stores.
    uint i0 = tid;
    uint i1 = tid + grid_size;
    uint i2 = tid + 2u * grid_size;
    uint i3 = tid + 3u * grid_size;

    float4 a0 = A[i0];
    float4 b0 = B[i0];
    float4 a1 = A[i1];
    float4 b1 = B[i1];
    float4 a2 = A[i2];
    float4 b2 = B[i2];
    float4 a3 = A[i3];
    float4 b3 = B[i3];

    C[i0] = a0 + b0;
    C[i1] = a1 + b1;
    C[i2] = a2 + b2;
    C[i3] = a3 + b3;

    // Tail (in case n4 isn't multiple of 4*grid_size)
    for (uint i = i3 + grid_size; i < n4; i += grid_size) {
        C[i] = A[i] + B[i];
    }
}

matrix_scale.metal_source:
// matrix_scale: B = alpha * A. Float4 grid-stride, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void matrix_scale_f32(
    device const float*  A     [[buffer(0)]],
    device       float*  B     [[buffer(1)]],
    constant     uint&   N     [[buffer(2)]],
    constant     float&  alpha [[buffer(3)]],
    uint  tid                 [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&A[i * 4]));
        *(reinterpret_cast<device float4*>(&B[i * 4])) = alpha * v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        B[i] = alpha * A[i];
}

matvec.metal_source:
// matvec: y = A @ x. One threadgroup per row, float4 dot + simd reduce.
#include <metal_stdlib>
using namespace metal;

kernel void matvec_f32(
    device const float*  A  [[buffer(0)]],
    device const float*  x  [[buffer(1)]],
    device       float*  y  [[buffer(2)]],
    constant     uint&   N  [[buffer(3)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    float sum = A[row * N + t] * x[t];
    float sg_sum = simd_sum(sum);

    threadgroup float tg[32];
    const uint sg = t >> 5;
    const uint lane = t & 31;
    if (lane == 0) tg[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float v = tg[lane];
        v = simd_sum(v);
        if (lane == 0) y[row] = v;
    }
}

max_pool1d.metal_source:
// max_pool1d: NLC. y[n, l2, c] = max over window x[n, l2*s .. l2*s+k-1, c].
#include <metal_stdlib>
using namespace metal;

kernel void max_pool1d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   L       [[buffer(3)]],
    constant     uint&   C       [[buffer(4)]],
    constant     uint&   K       [[buffer(5)]],
    constant     uint&   stride  [[buffer(6)]],
    uint tid [[thread_position_in_grid]])
{
    const uint L2 = (L - K) / stride + 1;
    const uint total = N * L2 * C;
    for (uint idx = tid; idx < total; idx += 64 * 1024) {
        uint n = idx / (L2 * C); uint r = idx % (L2 * C);
        uint l2 = r / C; uint c = r % C;
        float m = -INFINITY;
        for (uint k = 0; k < K; ++k) {
            float v = x[(n * L + l2 * stride + k) * C + c];
            m = fmax(m, v);
        }
        y[(n * L2 + l2) * C + c] = m;
    }
}

max_pool2d.metal_source:
// max_pool2d: NHWC. K=2, stride=2 specialization. float4 vectorized across C.
#include <metal_stdlib>
using namespace metal;

kernel void max_pool2d_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     uint&   H       [[buffer(3)]],
    constant     uint&   W       [[buffer(4)]],
    constant     uint&   C       [[buffer(5)]],
    constant     uint&   K       [[buffer(6)]],
    constant     uint&   stride  [[buffer(7)]],
    uint tid [[thread_position_in_grid]])
{
    const uint H2 = (H - K) / stride + 1;
    const uint W2 = (W - K) / stride + 1;
    const uint C4 = C / 4;
    const uint total4 = N * H2 * W2 * C4;

    const uint sW_in4 = C4;
    const uint sH_in4 = W * C4;
    const uint sN_in4 = H * W * C4;

    device const float4* x4 = (device const float4*)x;
    device       float4* y4 = (device       float4*)y;

    for (uint idx = tid; idx < total4; idx += 64 * 1024) {
        uint q = idx;
        uint c4 = q % C4;      q /= C4;
        uint w2 = q % W2;      q /= W2;
        uint h2 = q % H2;      uint n = q / H2;

        uint base = n * sN_in4 + (h2 * stride) * sH_in4 + (w2 * stride) * sW_in4 + c4;

        float4 v00 = x4[base];
        float4 v01 = x4[base + sW_in4];
        float4 v10 = x4[base + sH_in4];
        float4 v11 = x4[base + sH_in4 + sW_in4];

        y4[idx] = fmax(fmax(v00, v01), fmax(v10, v11));
    }
}

mish.metal_source:
// mish: x * tanh(softplus(x)). Stable softplus = max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

static inline float4 softplus4(float4 v) {
    float4 ax = fabs(v);
    float4 mx = fmax(v, 0.0f);
    return mx + log(1.0f + exp(-ax));
}

kernel void mish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 sp = softplus4(v);
        *reinterpret_cast<device float4*>(&y[i * 4]) = v * tanh(sp);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        float sp = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
        y[i] = v * tanh(sp);
    }
}

mse_loss.metal_source:
// mse_loss: mean((pred - target)^2). Single-tg simdgroup reduction.
#include <metal_stdlib>
using namespace metal;

kernel void mse_loss_f32(
    device const float*  pred    [[buffer(0)]],
    device const float*  target  [[buffer(1)]],
    device       float*  out     [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    uint  tid                   [[thread_position_in_threadgroup]])
{
    const uint tg_size = 1024;
    const uint N4 = N / 4;
    device const float4* pred4 = reinterpret_cast<device const float4*>(pred);
    device const float4* targ4 = reinterpret_cast<device const float4*>(target);

    float4 acc = 0.0f;
    uint i = tid;
    for (; i + 3 * tg_size < N4; i += 4 * tg_size) {
        float4 da = pred4[i] - targ4[i];
        float4 db = pred4[i + tg_size] - targ4[i + tg_size];
        float4 dc = pred4[i + 2 * tg_size] - targ4[i + 2 * tg_size];
        float4 dd = pred4[i + 3 * tg_size] - targ4[i + 3 * tg_size];
        acc = fma(da, da, acc);
        acc = fma(db, db, acc);
        acc = fma(dc, dc, acc);
        acc = fma(dd, dd, acc);
    }
    for (; i < N4; i += tg_size) {
        float4 d = pred4[i] - targ4[i];
        acc = fma(d, d, acc);
    }
    float sum = acc.x + acc.y + acc.z + acc.w;

    float sg_sum = simd_sum(sum);

    threadgroup float tg_sum[32];
    uint sg = tid >> 5;
    uint lane = tid & 31u;
    if (lane == 0) tg_sum[sg] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float v = tg_sum[lane];
        v = simd_sum(v);
        if (lane == 0) *out = v / float(N);
    }
}

nll_loss.metal_source:
// nll_loss: per-row -sum(y_onehot * log_probs). Output (N,).
// Optimized: float4 vector loads, 256 active threads handle 4 elements each,
// single-simdgroup-per-row final reduction across 8 subgroup partials.
#include <metal_stdlib>
using namespace metal;

kernel void nll_loss_f32(
    device const float*  LP       [[buffer(0)]],
    device const float*  Yh       [[buffer(1)]],
    device       float*  out      [[buffer(2)]],
    constant     uint&   N        [[buffer(3)]],
    constant     uint&   C        [[buffer(4)]],
    uint3 tid3                   [[thread_position_in_threadgroup]],
    uint3 tgid                   [[threadgroup_position_in_grid]])
{
    const uint tid  = tid3.x;
    const uint row  = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;

    threadgroup float reduce[8];

    float partial = 0.0f;
    if (tid < 256u) {
        const uint base = row * C + (tid << 2);
        device const float4* lpp = reinterpret_cast<device const float4*>(LP + base);
        device const float4* yhp = reinterpret_cast<device const float4*>(Yh + base);
        float4 lv = *lpp;
        float4 yv = *yhp;
        float4 prod = lv * yv;
        partial = -(prod.x + prod.y + prod.z + prod.w);
    }

    float sg_sum = simd_sum(partial);
    if (tid < 256u && lane == 0u) reduce[sgid] = sg_sum;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sgid == 0u) {
        float v = (lane < 8u) ? reduce[lane] : 0.0f;
        v = simd_sum(v);
        if (lane == 0u) out[row] = v;
    }
}

outer_product.metal_source:
// outer_product: C[i][j] = x[i] * y[j]. Float4, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void outer_product_f32(
    device const float*  x       [[buffer(0)]],
    device const float*  y       [[buffer(1)]],
    device       float*  C       [[buffer(2)]],
    constant     uint&   M       [[buffer(3)]],
    constant     uint&   N       [[buffer(4)]],
    uint  tid                   [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    const uint total4 = M * n4;
    for (uint idx4 = tid; idx4 < total4; idx4 += grid_size) {
        uint i = idx4 / n4;
        uint j4 = idx4 - i * n4;
        float xi = x[i];
        float4 yv = *(reinterpret_cast<const device float4*>(&y[j4 * 4]));
        *(reinterpret_cast<device float4*>(&C[i * N + j4 * 4])) = xi * yv;
    }
}

prelu.metal_source:
// prelu: x if x>0 else alpha[c]*x. Per-channel slope.
#include <metal_stdlib>
using namespace metal;

kernel void prelu_f32(
    device const float*  x         [[buffer(0)]],
    device const float*  alpha     [[buffer(1)]],
    device       float*  y         [[buffer(2)]],
    constant     uint&   N_total   [[buffer(3)]],
    constant     uint&   C         [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N_total; i += grid_size) {
        float v = x[i];
        uint c = i % C;
        float a = alpha[c];
        y[i] = v > 0.0f ? v : a * v;
    }
}

relu.metal_source:
// relu: out = max(x, 0). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void relu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = fmax(v, 0.0f);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = fmax(x[i], 0.0f);
    }
}

residual_add.metal_source:
// residual_add: y = x + alpha * residual. Vectorized: single float4 per thread.
#include <metal_stdlib>
using namespace metal;

kernel void residual_add_f32(
    device const float*  X       [[buffer(0)]],
    device const float*  R       [[buffer(1)]],
    device       float*  Y       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    constant     uint&   grid_size [[buffer(4)]],
    constant     float&  alpha   [[buffer(5)]],
    uint tid                    [[thread_position_in_grid]])
{
    const uint n4 = N >> 2;           // 1<<18
    const float a = alpha;
    for (uint i = tid; i < n4; i += grid_size) {
        uint base = i << 2;
        float4 x = *reinterpret_cast<const device float4*>(&X[base]);
        float4 r = *reinterpret_cast<const device float4*>(&R[base]);
        *reinterpret_cast<device float4*>(&Y[base]) = x + a * r;
    }
}

rms_norm.metal_source:
// rms_norm: y = x * rsqrt(mean(x^2) + eps). Simdgroup reduction, no mean.
#include <metal_stdlib>
using namespace metal;

kernel void rms_norm_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   N       [[buffer(2)]],
    constant     float&  eps     [[buffer(3)]],
    uint3 tid                   [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * N;
    float val = x[off + t];
    float sumsq = simd_sum(val * val);

    threadgroup float tg_sum[32];
    const uint sg = t >> 5;
    if ((t & 31) == 0) tg_sum[sg] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (t < 32) {
        sumsq = tg_sum[t];
        for (uint s = 16; s > 0; s >>= 1)
            sumsq += simd_shuffle_down(sumsq, s);
    }
    if (t == 0) tg_sum[0] = sumsq;
    threadgroup_barrier(mem_flags::mem_threadgroup);

    float inv_rms = rsqrt(tg_sum[0] / float(N) + eps);
    y[off + t] = val * inv_rms;
}

rope_embedding.metal_source:
// rope_embedding: rotary position embedding. Input (S, D), D even.
#include <metal_stdlib>
using namespace metal;

kernel void rope_embedding_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   S         [[buffer(2)]],
    constant     uint&   D         [[buffer(3)]],
    constant     float&  base      [[buffer(4)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint half_d = D >> 1;
    const uint total  = S * half_d;
    if (tid >= total) return;

    const uint s = tid / half_d;
    const uint i = tid - s * half_d;

    float omega = 1.0f / pow(base, (2.0f * float(i)) / float(D));
    float ang = float(s) * omega;
    float c = precise::cos(ang);
    float sn = precise::sin(ang);

    const uint off = s * D + (i << 1);
    float2 xv = *((device const float2*)(x + off));
    float2 yv;
    yv.x = fma(xv.x, c, -xv.y * sn);
    yv.y = fma(xv.x, sn,  xv.y * c);
    *((device float2*)(y + off)) = yv;
}

rsqrt.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void rsqrt_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    for (uint i = tid; i < N; i += grid_size) {
        y[i] = rsqrt(fabs(x[i]));
    }
}

selu.metal_source:
// selu: scale * (max(x,0) + alpha * min(exp(x)-1, 0)).
#include <metal_stdlib>
using namespace metal;

constant constexpr float selu_scale = 1.05070098f;
constant constexpr float selu_alpha = 1.67326324f;

kernel void selu_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        v = selu_scale * (fmax(v, 0.0f) + selu_alpha * fmin(exp(v) - 1.0f, 0.0f));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = selu_scale * (fmax(v, 0.0f) + selu_alpha * fmin(exp(v) - 1.0f, 0.0f));
    }
}

sigmoid.metal_source:
// sigmoid: out = 1 / (1 + fast::exp(-x)). 1024 thr/tg, float4, grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void sigmoid_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        v = 1.0f / (1.0f + fast::exp(-v));
        *reinterpret_cast<device float4*>(&y[i * 4]) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = 1.0f / (1.0f + fast::exp(-v));
    }
}

softmax.metal_source:
// softmax per row: simd_max + simd_sum reductions.
#include <metal_stdlib>
using namespace metal;

kernel void softmax_f32(
    device const float*  x  [[buffer(0)]],
    device       float*  y  [[buffer(1)]],
    constant     uint&   N  [[buffer(2)]],
    uint3 tid              [[thread_position_in_threadgroup]],
    uint3 tgid             [[threadgroup_position_in_grid]])
{
    const uint t = tid.x;
    const uint row = tgid.y;
    const uint off = row * N;
    const uint sg = t >> 5;
    const uint lane = t & 31;

    threadgroup float tg_buf[32];
    threadgroup float row_max;
    threadgroup float row_sum;

    float val = x[off + t];

    float m = simd_max(val);
    if (lane == 0) tg_buf[sg] = m;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_max(v);
        if (lane == 0) row_max = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    float rmax = row_max;

    float ev = fast::exp(val - rmax);
    float s = simd_sum(ev);
    if (lane == 0) tg_buf[sg] = s;
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (sg == 0) {
        float v = tg_buf[lane];
        v = simd_sum(v);
        if (lane == 0) row_sum = v;
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    y[off + t] = ev / row_sum;
}

softplus.metal_source:
// softplus: log(1 + exp(x)). Stable form: max(x,0) + log1p(exp(-|x|)).
#include <metal_stdlib>
using namespace metal;

kernel void softplus_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        float4 ax = fabs(v);
        float4 mx = fmax(v, 0.0f);
        *reinterpret_cast<device float4*>(&y[i * 4]) = mx + log(1.0f + exp(-ax));
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = fmax(v, 0.0f) + log(1.0f + exp(-fabs(v)));
    }
}

softsign.metal_source:
// softsign: out = x / (1 + |x|). float4 grid-stride.
#include <metal_stdlib>
using namespace metal;

kernel void softsign_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        *reinterpret_cast<device float4*>(&y[i * 4]) = v / (1.0f + fabs(v));
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        y[i] = x[i] / (1.0f + fabs(x[i]));
    }
}

sqr_mm.metal_source:
// sqr_matmul: C = A @ B  (N×N f32). 64×64 tile, 256 thr, BK=16.
#include <metal_stdlib>
#include <metal_simdgroup>
#include <metal_simdgroup_matrix>
using namespace metal;

constant constexpr uint BM           = 64;
constant constexpr uint BN           = 64;
constant constexpr uint BK           = 16;
constant constexpr uint SM           = 16;
constant constexpr uint SN           = 32;
constant constexpr uint SIMDS_N      = BN / SN;
constant constexpr uint MMA_M        = SM / 8;
constant constexpr uint MMA_N        = SN / 8;
constant constexpr uint PAD          = 4;
constant constexpr uint LDA          = BK + PAD;             // 20
constant constexpr uint LDB          = BN + PAD;             // 68

kernel void sqr_matmul_f32(
    device const float* A   [[buffer(0)]],
    device const float* B   [[buffer(1)]],
    device       float* C   [[buffer(2)]],
    constant     uint&  N   [[buffer(3)]],
    uint2 tgid              [[threadgroup_position_in_grid]],
    uint  sgid              [[simdgroup_index_in_threadgroup]],
    uint  lid               [[thread_index_in_threadgroup]])
{
    threadgroup float As[2][BM * LDA];
    threadgroup float Bs[2][BK * LDB];

    const uint sm = sgid / SIMDS_N;
    const uint sn = sgid % SIMDS_N;
    const uint c_row0 = tgid.y * BM;
    const uint c_col0 = tgid.x * BN;

    const uint a_row = lid / 4;
    const uint a_c4  = lid % 4;
    const uint b_row = lid / 16;
    const uint b_c4  = lid % 16;

    simdgroup_matrix<float, 8, 8> C_acc[MMA_M][MMA_N];
    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            C_acc[i][j] = simdgroup_matrix<float, 8, 8>(0.0f);

    {
        *reinterpret_cast<threadgroup float4*>(&As[0][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * N + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[0][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[b_row * N + (c_col0 + b_c4 * 4)]);
    }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    const uint num_k_tiles = N / BK;
    uint buf = 0;

    for (uint kt = 0; kt < num_k_tiles - 1; ++kt) {
        const uint next   = 1 - buf;
        const uint k0_nxt = (kt + 1) * BK;

        *reinterpret_cast<threadgroup float4*>(&As[next][a_row * LDA + a_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&A[(c_row0 + a_row) * N + k0_nxt + a_c4 * 4]);
        *reinterpret_cast<threadgroup float4*>(&Bs[next][b_row * LDB + b_c4 * 4]) =
            *reinterpret_cast<const device float4*>(&B[(k0_nxt + b_row) * N + (c_col0 + b_c4 * 4)]);

        #pragma unroll
        for (uint kc = 0; kc < BK; kc += 8) {
            simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
            #pragma unroll
            for (uint i = 0; i < MMA_M; ++i)
                #pragma unroll
                for (uint j = 0; j < MMA_N; ++j)
                    simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
        }

        threadgroup_barrier(mem_flags::mem_threadgroup);
        buf = next;
    }

    #pragma unroll
    for (uint kc = 0; kc < BK; kc += 8) {
        simdgroup_matrix<float, 8, 8> A_blk[MMA_M], B_blk[MMA_N];
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            simdgroup_load(A_blk[i], &As[buf][(sm * SM + i * 8) * LDA + kc], LDA);
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_load(B_blk[j], &Bs[buf][kc * LDB + sn * SN + j * 8], LDB);
        #pragma unroll
        for (uint i = 0; i < MMA_M; ++i)
            #pragma unroll
            for (uint j = 0; j < MMA_N; ++j)
                simdgroup_multiply_accumulate(C_acc[i][j], A_blk[i], B_blk[j], C_acc[i][j]);
    }

    #pragma unroll
    for (uint i = 0; i < MMA_M; ++i)
        #pragma unroll
        for (uint j = 0; j < MMA_N; ++j)
            simdgroup_store(C_acc[i][j],
                            &C[(c_row0 + sm * SM + i * 8) * N + (c_col0 + sn * SN + j * 8)],
                            N);
}

swish.metal_source:
// swish: out = x * sigmoid(x) = x / (1 + exp(-x)). 1024 thr/tg, float4.
#include <metal_stdlib>
using namespace metal;

kernel void swish_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    constant     uint&   grid_size [[buffer(3)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *reinterpret_cast<const device float4*>(&x[i * 4]);
        v = v / (1.0f + fast::exp(-v));
        *reinterpret_cast<device float4*>(&y[i * 4]) = v;
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size) {
        float v = x[i];
        y[i] = v / (1.0f + fast::exp(-v));
    }
}

tanh.metal_source:
// tanh: float4 grid-stride, memory-bound.
#include <metal_stdlib>
using namespace metal;

kernel void tanh_f32(
    device const float*  x         [[buffer(0)]],
    device       float*  y         [[buffer(1)]],
    constant     uint&   N         [[buffer(2)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const uint grid_size = 64 * 1024;
    const uint n4 = N / 4;
    for (uint i = tid; i < n4; i += grid_size) {
        float4 v = *(reinterpret_cast<const device float4*>(&x[i * 4]));
        *(reinterpret_cast<device float4*>(&y[i * 4])) = tanh(v);
    }
    for (uint i = n4 * 4 + tid; i < N; i += grid_size)
        y[i] = tanh(x[i]);
}

top_k.metal_source:
// top_k: per-row top-k values, sorted descending. R=1024, C=1024, k=16.
// Strategy: single simdgroup (32 lanes) per row. Each lane owns 32 elements
// (C_PER_LANE = 1024/32). Each iteration: simd_max picks row-global max; we
// resolve ties by lane id via a tagged simd_max on (uint)(~lane). The winning
// lane invalidates its slot and rescans its 32 registers. No threadgroup
// memory, no barriers.
#include <metal_stdlib>
using namespace metal;

constant constexpr uint C_PER_LANE = 32;        // 1024 / 32
constant constexpr uint VEC_PER_LANE = 8;       // 32 / 4

kernel void top_k_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  y       [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    constant     uint&   k       [[buffer(3)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]],
    uint  simd_lane             [[thread_index_in_simdgroup]],
    uint  simd_id               [[simdgroup_index_in_threadgroup]])
{
    (void)C; (void)k; (void)simd_id;
    const uint row = tgid.y;
    const uint tid = tid3.x;
    if (tid >= 32u) return;

    device const float4* xr4 = (device const float4*)(x + row * 1024u);
    const uint base_vec = simd_lane * VEC_PER_LANE;

    float v[C_PER_LANE];
    #pragma unroll
    for (uint j = 0; j < VEC_PER_LANE; ++j) {
        float4 q = xr4[base_vec + j];
        v[j*4 + 0] = q.x;
        v[j*4 + 1] = q.y;
        v[j*4 + 2] = q.z;
        v[j*4 + 3] = q.w;
    }

    float lmax = v[0];
    uint  lidx = 0u;
    #pragma unroll
    for (uint j = 1; j < C_PER_LANE; ++j) {
        if (v[j] > lmax) { lmax = v[j]; lidx = j; }
    }

    device float* yr = y + row * 16u;

    #pragma unroll
    for (uint out_i = 0; out_i < 16u; ++out_i) {
        float gmx = simd_max(lmax);
        // Tie-break: among lanes where lmax==gmx, pick the lowest lane id.
        // Encode (lmax==gmx ? lane : 32) and take simd_min.
        uint tag = (lmax == gmx) ? simd_lane : 32u;
        uint win_lane = simd_min(tag);

        if (simd_lane == 0u) {
            yr[out_i] = gmx;
        }

        if (simd_lane == win_lane) {
            v[lidx] = -INFINITY;
            float nm = v[0];
            uint  ni = 0u;
            #pragma unroll
            for (uint j = 1; j < C_PER_LANE; ++j) {
                if (v[j] > nm) { nm = v[j]; ni = j; }
            }
            lmax = nm;
            lidx = ni;
        }
    }
}

transpose_2d.metal_source:
// transpose_2d: B = A^T. One TG per 64x64 tile, 256 threads/TG.
// Each thread handles a 4x4 sub-block: float4 load row, then float4 store col.
// SMEM padded by +1 to avoid bank conflicts on the transposed access.
#include <metal_stdlib>
using namespace metal;

#define TILE 64

[[max_total_threads_per_threadgroup(256)]]
kernel void transpose_2d_f32(
    device const float*  A       [[buffer(0)]],
    device       float*  B       [[buffer(1)]],
    constant     uint&   M       [[buffer(2)]],
    constant     uint&   N       [[buffer(3)]],
    uint  lid                   [[thread_index_in_threadgroup]],
    uint  tgid                  [[threadgroup_position_in_grid]])
{
    threadgroup float tile[TILE][TILE + 1];

    const uint num_tiles_x = N / TILE;     // col-tiles in A
    const uint tx = tgid % num_tiles_x;
    const uint ty = tgid / num_tiles_x;

    const uint lx4 = lid & 15;   // 0..15  -> col group (4 floats wide)
    const uint ly  = lid >> 4;   // 0..15  -> row group (4 rows tall)

    // Load: thread (lx4,ly) reads 4 rows x float4 from A[ty*64 + ly*4 + r, tx*64 + lx4*4]
    #pragma unroll
    for (uint r = 0; r < 4; ++r) {
        const uint a_row = ty * TILE + ly * 4 + r;
        const uint a_col = tx * TILE + lx4 * 4;
        float4 v = *reinterpret_cast<const device float4*>(A + a_row * N + a_col);
        tile[lx4 * 4 + 0][ly * 4 + r] = v.x;
        tile[lx4 * 4 + 1][ly * 4 + r] = v.y;
        tile[lx4 * 4 + 2][ly * 4 + r] = v.z;
        tile[lx4 * 4 + 3][ly * 4 + r] = v.w;
    }

    threadgroup_barrier(mem_flags::mem_threadgroup);

    // Store: B[tx*64 + ly*4 + r, ty*64 + lx4*4] = tile[ly*4 + r, lx4*4 : +4]
    #pragma unroll
    for (uint r = 0; r < 4; ++r) {
        const uint b_row = tx * TILE + ly * 4 + r;
        const uint b_col = ty * TILE + lx4 * 4;
        float4 w = *reinterpret_cast<threadgroup float4*>(&tile[ly * 4 + r][lx4 * 4]);
        *reinterpret_cast<device float4*>(B + b_row * M + b_col) = w;
    }
}

triplet_margin_loss.metal_source:
#include <metal_stdlib>
using namespace metal;

kernel void triplet_margin_loss_f32(
    device const float*  a       [[buffer(0)]],
    device const float*  p       [[buffer(1)]],
    device const float*  n       [[buffer(2)]],
    device       float*  y       [[buffer(3)]],
    constant     uint&   D       [[buffer(4)]],
    constant     float&  margin  [[buffer(5)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    const uint lane = tid & 31u;
    const uint sgid = tid >> 5;
    device const float* ar = a + row * D;
    device const float* pr = p + row * D;
    device const float* nr = n + row * D;
    threadgroup float r1[32], r2[32];

    float av = ar[tid];
    float dp = av - pr[tid];
    float dn = av - nr[tid];
    float sp = dp * dp;
    float sn = dn * dn;

    sp = simd_sum(sp);
    sn = simd_sum(sn);
    if (lane == 0) { r1[sgid] = sp; r2[sgid] = sn; }
    threadgroup_barrier(mem_flags::mem_threadgroup);
    if (tid < 32) {
        float vp = simd_sum(r1[lane]);
        float vn = simd_sum(r2[lane]);
        if (lane == 0) y[row] = fmax(sqrt(vp) - sqrt(vn) + margin, 0.0f);
    }
}

variance.metal_source:
// variance: per-row Var(x) = mean(x²) − mean(x)². One threadgroup per row.
#include <metal_stdlib>
using namespace metal;

kernel void variance_f32(
    device const float*  x       [[buffer(0)]],
    device       float*  out     [[buffer(1)]],
    constant     uint&   C       [[buffer(2)]],
    uint3 tid3                  [[thread_position_in_threadgroup]],
    uint3 tgid                  [[threadgroup_position_in_grid]])
{
    const uint tid = tid3.x;
    const uint row = tgid.y;
    device const float* row_ptr = x + row * C;
    const uint sg = tid >> 5;
    const uint lane = tid & 31;

    float v = row_ptr[tid];
    float sum   = simd_sum(v);
    float sumsq = simd_sum(v * v);

    threadgroup float tg_s[32], tg_q[32];
    if (lane == 0) { tg_s[sg] = sum; tg_q[sg] = sumsq; }
    threadgroup_barrier(mem_flags::mem_threadgroup);

    if (sg == 0) {
        float s  = tg_s[lane];
        float sq = tg_q[lane];
        s  = simd_sum(s);
        sq = simd_sum(sq);
        if (lane == 0) {
            float mean = s / float(C);
            out[row] = sq / float(C) - mean * mean;
        }
    }
}

where.metal_source:
// where: y = cond > 0.5 ? a : b.
// float4 grid-stride with 4x unroll. Batched loads (all loads before any
// store) maximize in-flight memory transactions. select() for exact
// bit-blend (rtol=atol=0).
#include <metal_stdlib>
using namespace metal;

kernel void where_f32(
    device const float*  cond      [[buffer(0)]],
    device const float*  a         [[buffer(1)]],
    device const float*  b         [[buffer(2)]],
    device       float*  y         [[buffer(3)]],
    constant     uint&   N         [[buffer(4)]],
    constant     uint&   grid_size [[buffer(5)]],
    uint  tid                     [[thread_position_in_grid]])
{
    const device float4* cond4 = reinterpret_cast<const device float4*>(cond);
    const device float4* a4    = reinterpret_cast<const device float4*>(a);
    const device float4* b4    = reinterpret_cast<const device float4*>(b);
    device       float4* y4    = reinterpret_cast<device float4*>(y);

    const uint n4 = N >> 2;
    const uint gs = grid_size;
    const uint gs2 = gs << 1;
    const uint gs3 = gs2 + gs;
    const uint gs4 = gs << 2;

    uint i = tid;
    for (; i + gs3 < n4; i += gs4) {
        uint i1 = i + gs;
        uint i2 = i + gs2;
        uint i3 = i + gs3;
        // Batch all 12 float4 loads first to overlap memory latency.
        float4 c0 = cond4[i];  float4 c1 = cond4[i1];
        float4 c2 = cond4[i2]; float4 c3 = cond4[i3];
        float4 a0 = a4[i];     float4 a1 = a4[i1];
        float4 a2 = a4[i2];    float4 a3 = a4[i3];
        float4 b0 = b4[i];     float4 b1 = b4[i1];
        float4 b2 = b4[i2];    float4 b3 = b4[i3];
        y4[i]  = select(b0, a0, c0 > 0.5f);
        y4[i1] = select(b1, a1, c1 > 0.5f);
        y4[i2] = select(b2, a2, c2 > 0.5f);
        y4[i3] = select(b3, a3, c3 > 0.5f);
    }
    for (; i < n4; i += gs) {
        float4 c = cond4[i];
        float4 av = a4[i];
        float4 bv = b4[i];
        y4[i] = select(bv, av, c > 0.5f);
    }
    for (uint k = n4 * 4u + tid; k < N; k += gs) {
        y[k] = cond[k] > 0.5f ? a[k] : b[k];
    }
}
